window.PUBLICATIONS = [{"id":"Li2026_BlackBoxTestTimeEnsemble","title":"Black-Box Test-Time Ensemble","authors":"Siyang Li et al.","year":2026,"venue":"IEEE Comput. Intell. Mag.","doi":"10.1109/MCI.2025.3624194","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":"https://github.com/sylyoung/TestEnsemble","tldr":"Tackles unsupervised combination/evaluation of privacy-preserving black-box models (accessible only via their predictions) on unlabeled downstream test data. Proposes SML-OVR, a hyperparameter-free method that uses only base classifiers' predictions on unlabeled test data to estimate each model's reliability and build a weighted ensemble favoring more accurate ones, supporting traditional classifiers and LLMs, binary/multi-class, hard/soft outputs, and offline/online settings. On 13 real-world text, image, and time-series datasets it consistently outperforms majority voting and other combination methods while being computationally efficient."},{"id":"Tu2026_BrainprintNetMultiscaleCrossBandFusionNetwork","title":"BrainprintNet: A Multiscale Cross-Band Fusion Network for EEG-Based Brainprint Recognition","authors":"Yunlu Tu et al.","year":2026,"venue":"IEEE Trans. Inf. Forensics Secur.","doi":"10.1109/TIFS.2026.3672000","topic":"Transfer Learning & Alignment","paradigm":["Biometric"],"code_url":"https://github.com/hustmx721/BrainprintNet","tldr":"Existing EEG brainprint (biometric) recognition methods are task-specific and evaluated in unrealistic conditions. Proposes BrainprintNet, a CNN integrating fine-grained filter banks, grouped multiscale temporal convolutions, and cross-band spatial fusion for EEG-based user identification. It outperforms prior architectures in the challenging simultaneous cross-session and cross-task setting across three public datasets (nine tasks), with weight visualization revealing correlations between user identity and specific frequency subbands and channels."},{"id":"Wang2026_DBConformerDualBranchConvolutionalTransformerEEG","title":"DBConformer: Dual-Branch Convolutional Transformer for EEG Decoding","authors":"Ziwei Wang et al.","year":2026,"venue":"IEEE J. Biomed. Health Informatics","doi":"10.1109/JBHI.2025.3622725","topic":"Deep Architectures","paradigm":["Seizure"],"code_url":"https://github.com/wzwvv/DBConformer","tldr":"CNN backbones for EEG decoding have short receptive fields, and most CNN-Transformer hybrids use serial designs that poorly integrate local/global features and ignore explicit channel modeling. Proposes DBConformer, a dual-branch convolutional Transformer with a temporal Conformer for long-range temporal dependencies and a spatial Conformer for inter-channel interactions, plus a lightweight channel attention module. Across four evaluation settings on motor imagery, seizure detection, and SSVEP it outperforms 13 baselines with over an eight-fold parameter reduction versus a high-capacity EEG Conformer, yielding physiologically interpretable features."},{"id":"Liu2026_EEGFoundationModelsProgressesBenchmarkingOpen","title":"EEG Foundation Models: Progresses, Benchmarking, and Open Problems","authors":"Dingkun Liu et al.","year":2026,"venue":"CoRR","doi":"10.48550/ARXIV.2601.17883","topic":"Foundation & Self-Supervised Models","paradigm":[],"code_url":"https://github.com/Dingkun0817/EEG-FM-Benchmark","tldr":"There is no fair, comprehensive comparison of EEG foundation models due to inconsistent pre-training objectives, preprocessing, and evaluation protocols. This paper reviews 50 representative models under a unified taxonomy (data standardization, architecture, self-supervised pre-training) and benchmarks 12 open-source foundation models plus competitive specialist baselines across 13 datasets and nine BCI paradigms, under leave-one-subject-out cross-subject and within-subject few-shot protocols, comparing full fine-tuning vs. linear probing. Key findings: linear probing is frequently insufficient, specialists trained from scratch remain competitive, and larger foundation models do not necessarily generalize better under current data/training regimes."},{"id":"Wu2026_FeatureWeightingImprovesPoolSequentialActive","title":"Feature Weighting Improves Pool-Based Sequential Active Learning for Regression","authors":"Dongrui Wu","year":2026,"venue":"CoRR","doi":"10.48550/ARXIV.2604.02019","topic":"Active Learning","paradigm":[],"code_url":"https://github.com/drwuHUST/FWALR","tldr":"Pool-based sequential active learning for regression (ALR) selects samples via representativeness and diversity computed from inter-sample distances, but prior methods weight all features equally, yielding inaccurate distances and suboptimal selection. This paper proposes four single-task and three multi-task feature-weighted ALR approaches that weight features by ridge-regression coefficients trained from the few already-labeled samples. Extensive experiments show this simple, easy-to-implement enhancement almost always improves five existing ALR approaches in both single- and multi-task settings, and it extends readily to stream-based ALR and classification."},{"id":"Fu2026_FSTAMNetDualAttentionNetworkMotor","title":"FSTAM-net: A dual attention network for motor imagery decoding and visualization analysis","authors":"Shuo Fu et al.","year":2026,"venue":"Biomed. Signal Process. Control.","doi":"10.1016/J.BSPC.2026.109916","topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":"https://github.com/Ericfus/FSTAM-net_code","tldr":"Addresses motor-imagery EEG decoding where existing CNN/attention models poorly capture joint spatial-frequency dependencies and lack interpretability. Proposes FSTAM-net, a two-stage dual frequency-spatial-time attention network: Stage 1 uses an interpretable wavelet kernel network plus channel attention for time-frequency and spatial features, and Stage 2 applies self-attention for global temporal dependencies. Achieves 86.07%/89.61%/80.79% accuracy on BCI Competition IV 2a/2b and Giga DB (cross-subject) while visualizing ERD/ERS patterns for interpretability."},{"id":"Jiang2026_KDFNetKnowledgeDataFusionNetworkMotor","title":"KDFNet: Knowledge-data fusion network for motor imagery based brain-computer interfaces","authors":"Xue Jiang et al.","year":2026,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2025.123001","topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":"https://github.com/jxgogo/KDFNet","tldr":"Addresses that purely data-driven deep models for motor-imagery EEG decoding ignore valuable neurophysiological prior knowledge. Proposes KDFNet, which fuses MI priors into a CNN by initializing temporal and spatial layers with band-pass and common spatial filters, embedding power-spectrum information via a log-variance activation, and initializing the output layer from a traditional classifier, then fine-tuning end-to-end. On four MI datasets it improves average accuracy by 3.07% within-subject and 2.93% cross-subject over competitive baselines."},{"id":"Liu2026_MIRepNetPipelinePreTrainedModelEEG","title":"MIRepNet: A pipeline and pre-trained model for EEG-based motor imagery classification","authors":"Dingkun Liu et al.","year":2026,"venue":"Knowl. Based Syst.","doi":"10.1016/J.KNOSYS.2026.115966","topic":"Foundation & Self-Supervised Models","paradigm":["MI"],"code_url":"https://github.com/staraink/MIRepNet","tldr":"Existing EEG foundation models merge multiple paradigms and overlook paradigm-specific neurophysiology, limiting generalization. Proposes MIRepNet, the first EEG pre-trained model tailored to the motor-imagery paradigm, combining a neurophysiologically-informed channel-template preprocessing pipeline (adaptable to arbitrary electrode layouts) with a pre-training strategy mixing self-supervised masked token reconstruction and supervised MI classification for few-shot fine-tuning (<30 trials/class). Across five public MI datasets it achieves state-of-the-art, outperforming both specialized and generalized EEG models."},{"id":"Li2026_RAICLRetrievalAugmentedContextLearningVision","title":"RAICL: Retrieval-Augmented In-Context Learning for Vision-Language-Model Based EEG Seizure Detection","authors":"Siyang Li et al.","year":2026,"venue":"CoRR","doi":"10.48550/ARXIV.2601.17844","topic":"Foundation & Self-Supervised Models","paradigm":["Seizure"],"code_url":"https://github.com/sylyoung/VLM4EEG","tldr":"Conventional EEG decoders depend on task-specific training data and specialized architectures, limiting generalizable large brain-decoding models. This paper reframes EEG decoding as a vision-language task: multivariate EEG is rendered as stacked waveform images and analyzed by off-the-shelf vision-language models (VLMs) guided by neuroscience-informed text prompts, with a Retrieval-Augmented In-Context Learning (RAICL) scheme that dynamically selects the most relevant few-shot examples to condition the VLM's autoregressive outputs. On EEG-based seizure detection, state-of-the-art VLMs under RAICL match or exceed traditional time-series approaches without any retraining or downstream architecture design."},{"id":"Yang2026_SpikingNeuralNetworkIntraCorticalBrain","title":"Spiking neural network for intra-cortical brain signal decoding","authors":"Song Yang et al.","year":2026,"venue":"Knowl. Based Syst.","doi":"10.1016/J.KNOSYS.2026.115508","topic":"Deep Architectures","paradigm":["iBCI"],"code_url":"https://github.com/SongYang008/SNN_iBCIs","tldr":"Targets intra-cortical brain-signal decoding where traditional neural-activity-vector methods are inaccurate and deep learning is computationally expensive. Proposes a multi-neuron spiking neural network (MnSNN) plus a feature-fusion approach integrating hand-crafted neural activity vector features with deep-network features. On motor-related intra-cortical recordings from two rhesus macaques, MnSNN attains higher accuracy than conventional ANNs and is tens-to-hundreds of times more compute/energy efficient, suiting low-power iBCIs."},{"id":"Li2026_StackingNetCollectiveInferenceAcrossIndependentAI","title":"StackingNet: Collective Inference Across Independent AI Foundation Models","authors":"Siyang Li et al.","year":2026,"venue":"Adv. Sci.","doi":"10.1002/advs.76488","topic":"Foundation & Self-Supervised Models","paradigm":[],"code_url":"https://github.com/sylyoung/TestEnsemble","tldr":"Independently developed black-box foundation models cannot readily share complementary strengths, and classic ensembles require training-time access. This paper proposes StackingNet, a lightweight meta-ensemble neural network that aggregates only the output predictions of diverse black-box models at inference (unifying regression and classification), improving accuracy, ranking model reliability, and identifying/pruning models that degrade performance without access to internal parameters or training data. Across language comprehension, visual attribute estimation, and academic paper rating it consistently beats individual models and classic ensembles, with gains attributed to variance reduction and consensus alignment that widen as the model pool diversifies."},{"id":"Wang2026_SyntheticDataGenerationBrainComputerInterfaces","title":"Synthetic Data Generation for Brain-Computer Interfaces: Overview, Benchmarking, and Future Directions","authors":"Ziwei Wang et al.","year":2026,"venue":"CoRR","doi":"10.48550/ARXIV.2603.12296","topic":"Privacy-Preserving BCI","paradigm":["Seizure"],"code_url":"https://github.com/wzwvv/DG4BCI","tldr":"BCI development is fundamentally constrained by limited, heterogeneous, privacy-sensitive neural recordings, motivating synthetic yet physiologically plausible brain-signal generation. This survey reviews synthetic brain-data generation for BCIs, categorizing methods into signal-transformation-based, feature-based, model-based, and translation-based generation, and benchmarks representative approaches across four paradigms (motor imagery, seizure detection, SSVEP, auditory attention detection) for downstream utility. It further consolidates evaluation principles spanning signal realism, physiological plausibility, downstream utility, and privacy, outlines future directions, and releases a benchmark codebase."},{"id":"Liu2026_TemporalOutDistributionDetectionAsynchronousMotor","title":"Temporal Out-of-Distribution Detection for Asynchronous Motor Imagery Brain-Computer Interfaces","authors":"Chenhao Liu et al.","year":2026,"venue":"CoRR","doi":"10.48550/ARXIV.2605.01014","topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":"https://github.com/Flashingcat/-Temporal-Out-of-Distribution-Detection","tldr":"Online MI-BCIs run on continuous EEG where users are mostly at rest and only intermittently perform motor imagery, yet closed-set classifiers force every window into a known class, causing erroneous control. This paper proposes a two-stage asynchronous framework: an EEGNet-based rest/task gate decides whether a sliding window enters the control decision, then in-distribution MI classification and OOD detection run only on task-state windows via TempDens, which fuses classification-output energy, deep-feature density, and temporal-consistency scores. Experiments on continuous EEG streams show improved task-state detection and OOD-MI rejection over multiple conventional OOD baselines."},{"id":"Li2026_BackpropagationFreeTestTimeAdaptationLightweight","title":"Backpropagation-Free Test-Time Adaptation for Lightweight EEG-Based Brain-Computer Interfaces","authors":"Siyang Li et al.","year":2026,"venue":"CoRR","doi":"10.48550/ARXIV.2601.07556","topic":"Privacy-Preserving BCI","paradigm":["Drowsy"],"code_url":null,"tldr":"Existing test-time adaptation (TTA) for EEG relies on backpropagation-based loss optimization, incurring compute overhead, privacy risk, and sensitivity to noisy streams. Proposes Backpropagation-Free Transformations (BFT), which applies multiple sample-wise knowledge-guided augmentations or approximate Bayesian inference to each test trial to generate multiple prediction scores, then uses a learning-to-rank module to weight and robustly aggregate them without any gradient updates. Experiments on five EEG datasets (motor-imagery classification and driver-drowsiness regression) demonstrate effectiveness, robustness, and efficiency, enabling lightweight plug-and-play BCIs on resource-constrained devices."},{"id":null,"title":"CIS Publication Spotlight [Publication Spotlight]","authors":"Yongduan Song et al.","year":2026,"venue":"IEEE Comput. Intell. Mag.","doi":"10.1109/MCI.2026.3664142","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":null,"title":"CMCRD: Cross-Modal Contrastive Representation Distillation for Emotion Recognition","authors":"Siyuan Kan et al.","year":2026,"venue":"IEEE Trans. Affect. Comput.","doi":"10.1109/TAFFC.2026.3664341","topic":"General ML & Optimization","paradigm":["Affect"],"code_url":null,"tldr":""},{"id":"An2026_FastSeizureNetAccurateEfficientKnowledgeDataFusion","title":"fastSeizureNet: Accurate and efficient knowledge-data fusion for semi-supervised seizure detection","authors":"Jiayu An et al.","year":2026,"venue":"Neural Networks","doi":"10.1016/J.NEUNET.2026.109078","topic":"Deep Architectures","paradigm":["Seizure"],"code_url":null,"tldr":"Addresses the accuracy-speed trade-off in EEG seizure detection under limited labels and severe class imbalance. Proposes fastSeizureNet, which uses lightweight neural networks to approximate expensive hand-crafted features, explores multiple knowledge-data fusion strategies to combine traditional and deep-learning strengths, and adds a balanced sampling strategy for class imbalance. Experiments on two public EEG datasets under within- and cross-patient settings with multiple backbones (EEGNet, TIE-EEGNet, CE-stSENet) verify superior accuracy and inference speed over state-of-the-art."},{"id":null,"title":"LMID: A Comprehensive Multimodal Dataset for Failure Prediction in Cloud Computing Systems","authors":"Lingfei Deng et al.","year":2026,"venue":"KDD","doi":"10.1145/3770854.3785684","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":"Jia2026_SAFESecureAccurateFederatedLearningPrivacy","title":"SAFE: Secure and Accurate Federated Learning for Privacy-Preserving Brain-Computer Interfaces","authors":"Tianwang Jia et al.","year":2026,"venue":"CoRR","doi":"10.48550/ARXIV.2601.05789","topic":"Privacy-Preserving BCI","paradigm":["P300"],"code_url":null,"tldr":"Addresses simultaneous EEG-BCI challenges of poor cross-subject generalization, adversarial vulnerability, and privacy leakage. Proposes SAFE (Secure and Accurate Federated learning), which keeps data local, uses local batch-specific normalization to mitigate cross-subject distribution shift, and improves adversarial robustness via federated adversarial training and adversarial weight perturbation in both input and parameter spaces. On five MI and ERP datasets it outperforms 14 state-of-the-art approaches in accuracy and robustness without target-subject calibration, even surpassing centralized non-private training."},{"id":"Zhang2025_LightweightSpikingNeuralNetworkEEGMotor","title":"A lightweight spiking neural network for EEG-based motor imagery classification","authors":"Herui Zhang et al.","year":2025,"venue":"Neural Networks","doi":"10.1016/J.NEUNET.2025.107741","topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":"https://github.com/Zhr1110/SnnForMI","tldr":"This paper proposes a lightweight spiking neural network (SNN) for EEG-based motor-imagery classification, built on spatial-temporal convolution, with three properties: a brain-inspired architecture, energy efficiency via sparse spike-event processing, and dataset-agnostic design. Within-subject and cross-subject experiments on three public MI datasets show it outperforms four classical CNN-based models."},{"id":"Xiang2025_AligningLogitsGenerativelyPrincipledBlackBox","title":"Aligning Logits Generatively for Principled Black-Box Knowledge Distillation in the Wild","authors":"Xiang Xiang et al.","year":2025,"venue":"IEEE Trans. Pattern Anal. Mach. Intell.","doi":"10.1109/TPAMI.2025.3602663","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":"https://github.com/HAIV-Lab/MEKD","tldr":"Black-Box Knowledge Distillation (B2KD) compresses a cloud teacher into an edge student using only the teacher's API inference outputs, protecting data privacy and model copyright, but faces limited query exchange and edge-cloud distribution disparity. This paper theoretically shifts the optimization target from logits to a 'cell boundary' and proposes Mapping-Emulation KD (MEKD) with three stages: deprivatization (a generator emulates the teacher's inverse mapping), distillation (aligning low-dimensional teacher/student logits by reducing high-dimensional image-point distances), and a forward-only graph-propagation-based test-time adaptation that corrects the student's online prediction bias. It achieves state-of-the-art across image-recognition benchmarks and various DNN teacher-student pairs, including remote-sensing recognition."},{"id":"Jia2025_MagnetoencephalographyMEGNonInvasiveChineseSpeech","title":"Magnetoencephalography (MEG) Based Non-Invasive Chinese Speech Decoding","authors":"Zhihong Jia et al.","year":2025,"venue":"Journal of Neural Engineering","doi":"10.1088/1741-2552/AE1EA2","topic":"General ML & Optimization","paradigm":["Speech"],"code_url":"https://github.com/ZhihongJia/MASD","tldr":"Non-invasive speech BCIs could help aphasia patients, but Chinese speech BCIs, especially non-invasive ones, are barely studied. The paper releases a text-magnetoencephalography (MEG) dataset for non-invasive Chinese speech BCIs and proposes MASD (Multi-modality Assisted Speech Decoding), which captures both textual and acoustic information embedded in the brain signals during speech. Experiments demonstrate the effectiveness of both the text-MEG dataset and MASD, which the authors present as the first modality-assisted decoding approach for non-invasive speech BCIs."},{"id":"Du2025_MixtureExpertsOpenSetDomainAdaptation","title":"Mixture-of-Experts for Open Set Domain Adaptation: A Dual-Space Detection Approach","authors":"Zhenbang Du et al.","year":2025,"venue":"IEEE Trans. Artif. Intell.","doi":"10.1109/TAI.2025.3560590","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":"https://github.com/ZhenbangDu/DSD","tldr":"Open set domain adaptation (OSDA) must classify known classes while rejecting unknown-class target samples, but existing methods rely on the final image-feature space, need manually tuned thresholds, and often misclassify unknowns as known. The paper proposes Dual-Space Detection (DSD) built on a Mixture-of-Experts (MoE). Because experts route known classes with characteristic patterns, unknown samples show inconsistencies between the image-feature space and the expert routing-feature space, enabling threshold-free unknown detection. A graph router further exploits spatial information among image patches. On three benchmark datasets DSD outperforms state-of-the-art OSDA methods without any manual thresholding."},{"id":"Wang2025_MVCNetMultiViewContrastiveNetworkMotor","title":"MVCNet: Multi-view contrastive network for motor imagery classification","authors":"Ziwei Wang et al.","year":2025,"venue":"Knowl. Based Syst.","doi":"10.1016/J.KNOSYS.2025.114205","topic":"Foundation & Self-Supervised Models","paradigm":["MI"],"code_url":"https://github.com/wzwvv/MVCNet","tldr":"Most motor-imagery EEG decoders use single-stream architectures that overlook the multi-view nature of EEG, limiting performance and generalization. This paper proposes MVCNet, a dual-branch network parallelizing CNN and Transformer blocks to capture local spatial-temporal features and global temporal dependencies, with a unified time/frequency/spatial augmentation pipeline and two contrastive modules (a cross-view module enforcing consistency between original and augmented views, and a cross-model module aligning the two branches) before fused, jointly optimized classification. On five public MI datasets across three scenarios it consistently outperforms nine state-of-the-art MI networks."},{"id":"Wang2025_SACMSEEGAudioContrastiveMatchingChinese","title":"SACM: SEEG-Audio Contrastive Matching for Chinese Speech Decoding","authors":"Hongbin Wang et al.","year":2025,"venue":"IEEE Transactions on Biomedical Engineering","doi":"10.1109/TBME.2026.3678858","topic":"Foundation & Self-Supervised Models","paradigm":["Speech"],"code_url":"https://github.com/WangHongbinary/SACM","tldr":"Speech disorders such as dysarthria and anarthria impair verbal communication, motivating speech-decoding BCIs as neuroprostheses, but Mandarin Chinese speech BCIs are underexplored. The paper reports an experimental protocol collecting stereo-EEG (SEEG) plus synchronized audio from eight drug-resistant epilepsy patients during a word-level reading task, and proposes SACM (SEEG-Audio Contrastive Matching), a contrastive-learning framework for speech detection and speech decoding. SACM achieves accuracies significantly above chance on both tasks, and electrode-wise analysis shows a single sensorimotor-cortex electrode can match the full array."},{"id":"Liu2025_SpatialDistillationDistributionAlignmentSDDACross","title":"Spatial Distillation based Distribution Alignment (SDDA) for Cross-Headset EEG Classification","authors":"Dingkun Liu et al.","year":2025,"venue":"IEEE Transactions on Biomedical Engineering","doi":"10.1109/TBME.2025.3631604","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":"https://github.com/Dingkun0817/SDDA","tldr":"Cross-headset EEG decoding is difficult because headsets differ in the number and locations of electrodes. SDDA (Spatial Distillation based Distribution Alignment) first uses spatial distillation so the target model can exploit the full source electrode set, then applies input-, feature-, and output-space distribution alignment to bridge the large source-target gap. The authors state this is the first use of knowledge distillation for cross-headset transfer. On six EEG datasets across two BCI paradigms it outperforms 10 classical and state-of-the-art transfer-learning algorithms in both offline unsupervised and online supervised domain adaptation."},{"id":"Wang2025_TimeFrequencyTransformEEGDataAugmentation","title":"Time-frequency transform based EEG data augmentation for brain-computer interfaces","authors":"Ziwei Wang et al.","year":2025,"venue":"Knowl. Based Syst.","doi":"10.1016/J.KNOSYS.2025.113074","topic":"Data Augmentation & Generation","paradigm":[],"code_url":"https://github.com/wzwvv/CSDA","tldr":"Existing EEG data augmentation operates in only one domain (temporal, frequency, or spatial) and generates within-subject trials, poorly capturing non-stationarity and inter-subject variability. This paper proposes two time-frequency-transform augmentations, Discrete Wavelet Transform Augmentation (DWTaug) and Hilbert-Huang Transform Augmentation (HHTaug), that decompose signals in the time-frequency domain, reassemble sub-signals across subjects, and reconstruct in the time domain, jointly addressing data scarcity, non-stationarity, and individual differences. Across 17 datasets from three BCI paradigms they outperform nine existing augmentation methods, improving about 4% over baseline on average."},{"id":"An2025_TSPTTwoStepPromptTuningClass","title":"TSPT: Two-Step Prompt Tuning for class-incremental novel class discovery","authors":"Jiayu An et al.","year":2025,"venue":"Knowl. Based Syst.","doi":"10.1016/J.KNOSYS.2025.113603","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":"https://github.com/JiayuAn0818/TSPT","tldr":"Class-incremental novel class discovery (class-iNCD) must discover unknown classes across a sequence of unlabeled tasks while avoiding catastrophic forgetting and protecting privacy (no access to old data). This paper proposes Two-Step Prompt Tuning (TSPT), a rehearsal-free, plug-and-play method. Step 1 discovers novel classes by initializing the classifier via uniform clustering and applying intra-/inter-sample consistency learning. Step 2 fuses knowledge by adapting the learned prompt as a task-specific prompt and selecting additional prompts from a prompt pool to integrate old and new class knowledge. Experiments on three image datasets (including CIFAR-100 and Tiny-ImageNet) demonstrate its effectiveness with far fewer trainable parameters."},{"id":"He2025_MultiKernelEmbeddingFusionFrameworkPhysiological","title":"A Multi-Kernel Embedding Fusion Framework for Physiological Signal Based Emotion Recognition","authors":"Xinrun He et al.","year":2025,"venue":"IEEE Trans. Affect. Comput.","doi":"10.1109/TAFFC.2025.3562905","topic":"Transfer Learning & Alignment","paradigm":["Affect"],"code_url":null,"tldr":"Physiological-signal-based emotion recognition requires effective fusion of multi-modal signals. This paper proposes a Multi-Kernel Embedding Fusion Framework (MKEFF): multi-kernel learning with kernel approximation computes per-modality multi-kernel embeddings, a proposed sparse relation learning module explores correlation and diversity across modalities, and a distribution-alignment-based fusion aligns each modality in a subspace before weighted-summation fusion. Cross-subject experiments on DEAP, DECAF, and SEED-IV show better classification accuracy and interpretability than state-of-the-art methods."},{"id":"Chen2025_AFPMAlignmentFramePatchModelingCross","title":"AFPM: Alignment-based Frame Patch Modeling for Cross-Dataset EEG Decoding","authors":"Xiaoqing Chen et al.","year":2025,"venue":"Science China Information Sciences","doi":"10.1007/S11432-025-4736-2","topic":"Transfer Learning & Alignment","paradigm":["P300"],"code_url":null,"tldr":"Cross-dataset EEG decoding is hampered by inconsistent channel layouts, non-stationary signal distributions, and limited use of neurophysiological priors. AFPM is a plug-and-play, calibration-free framework with two parts. The first, Spatial Alignment, selects task-relevant channels using brain-region priors, aligns EEG distributions across domains, and remaps channels to a unified layout. The second, Frame-Patch Encoding, models multi-dataset signals as unified spatiotemporal patches. Compared with 17 state-of-the-art methods that require dataset-specific tuning, calibration-free AFPM achieves gains up to 4.40% on motor imagery and 3.58% on ERP tasks, and is presented as the first calibration-free cross-dataset EEG decoding framework."},{"id":"Liu2025_CLEANMIScalableEfficientPipelineConstructing","title":"CLEAN-MI: A Scalable and Efficient Pipeline for Constructing High-Quality Neurodata in Motor Imagery Paradigm","authors":"Dingkun Liu et al.","year":2025,"venue":"CoRR","doi":"10.48550/ARXIV.2506.11830","topic":"Foundation & Self-Supervised Models","paradigm":["MI"],"code_url":null,"tldr":"Building large-scale, high-quality MI datasets is a prerequisite for motor-imagery foundation models, but multi-source EEG suffers from low SNR, electrode-configuration heterogeneity, and inter-subject variability. CLEAN-MI is a scalable, systematic data-construction pipeline that integrates frequency-band filtering, channel-template selection, subject screening, and marginal distribution alignment to filter out low-quality data and standardize datasets from different subjects and devices. On multiple public MI datasets it yields consistent improvements in data quality and downstream classification performance."},{"id":null,"title":"Data alignment based adversarial defense benchmark for EEG-based BCIs","authors":"Xiaoqing Chen et al.","year":2025,"venue":"Neural Networks","doi":"10.1016/J.NEUNET.2025.107516","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":""},{"id":"Chen2025_FusionGenFeatureFusionFewShotEEG","title":"FusionGen: Feature Fusion-Based Few-Shot EEG Data Generation","authors":"Yuheng Chen et al.","year":2025,"venue":"ICCVW","doi":"10.1109/ICCVW69036.2025.00042","topic":"Data Augmentation & Generation","paradigm":["SSVEP"],"code_url":null,"tldr":"EEG-based BCIs are limited by data scarcity and large inter-subject variability, which hurt decoding generalization in few-shot settings. FusionGen is an EEG data-generation framework based on disentangled representation learning and feature fusion: a feature-matching fusion module integrates features across trials and a lightweight feature-extraction/reconstruction pipeline reconstructs high-fidelity signals, ensuring both diversity and trainability under limited data. On three motor-imagery and one SSVEP public datasets it significantly outperforms existing augmentation techniques in classification accuracy."},{"id":"Liu2025_HumanRobotCollaborationConstructionRobotDesign","title":"Human-Robot collaboration in construction: Robot design, perception and Interaction, and task allocation and execution","authors":"Jiajing Liu et al.","year":2025,"venue":"Adv. Eng. Informatics","doi":"10.1016/J.AEI.2025.103109","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"This is a review of human-robot collaboration (HRC) in the construction industry, which lacks comprehensive coverage of the technology and methodology behind HRC system design and deployment. It organizes recent progress into three areas (collaborative robot design, perception and interaction, and task allocation and execution) and identifies future priorities. These include exoskeleton and rigid-flexible-soft collaborative robots for construction trades, multimodal perception and interaction methods, and digital-twin-based HRC systems."},{"id":"Li2025_MultimodalBrainComputerInterfacesAIPowered","title":"Multimodal Brain-Computer Interfaces: AI-powered Decoding Methodologies","authors":"Siyang Li et al.","year":2025,"venue":"CoRR","doi":"10.48550/ARXIV.2502.02830","topic":"Deep Architectures","paradigm":["Speech"],"code_url":null,"tldr":"This review surveys AI-powered decoding methodologies for multimodal brain-computer interfaces, dissecting the shared elements of multimodal decoding and giving a unified view of diverse approaches. It emphasizes algorithmic advances in cross-modality mapping and sequential modeling alongside classic multi-modality fusion, and comprehensively covers visual, speech, and affective decoding applications. It also discusses emerging architectures such as multimodal Transformers and challenges like brain-data heterogeneity, aiming to bridge neuroscience and AI communities."},{"id":"Wu2025_RevisitingEuclideanAlignmentTransferLearningEEG","title":"Revisiting Euclidean Alignment for Transfer Learning in EEG-Based Brain-Computer Interfaces","authors":"Dongrui Wu","year":2025,"venue":"Journal of Neural Engineering","doi":"10.1088/1741-2552/ADDD49","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":"EEG-based BCIs need time-consuming subject-specific calibration, and transfer learning is used to reduce cross-subject/session distribution discrepancies and avoid negative transfer. This paper revisits Euclidean Alignment (EA), a transfer-learning technique proposed in 2020 and validated across 13 BCI paradigms, explaining its procedure and correct usage, reviewing its applications and extensions (e.g., label alignment), and pointing out potential new research directions. It is a tutorial/review intended to guide EEG decoding researchers."},{"id":null,"title":"The 1st International Workshop on Disentangled Representation Learning for Controllable Generation (DRL4Real): Methods and Results","authors":"Qiuyu Chen et al.","year":2025,"venue":"CoRR","doi":"10.48550/ARXIV.2509.10463","topic":"Data Augmentation & Generation","paradigm":[],"code_url":null,"tldr":""},{"id":"Wu2025_VLDLPVulnerabilityDetectionRootCause","title":"VLD-LP: Vulnerability Detection and Root Cause Localization with Large Language Model and Parameter-efficient Language Model Tuning","authors":"Huanyu Wu et al.","year":2025,"venue":"SMC","doi":"10.1109/SMC58881.2025.11343151","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"Deep-learning software vulnerability detection struggles to correlate code slices with scripts (causing false positives) and to precisely localize root causes. VLD-LP preprocesses C/C++ source code, extracts graph structures, and combines them with the script into prompts, then fine-tunes an LLM via a novel Hierarchical Regulation for Parameter-Efficient Language-model Tuning (HR-PELT) that keeps shallow-layer parameters largely fixed while boosting deep-layer adaptability. A second LLM is fine-tuned for root-cause localization. On three datasets it improves detection by 4.82% average accuracy and 5.29% Macro-F1 over the state of the art, and localization by 4.80% (ACC@10%) and 3.93% (ACC@20%)."},{"id":"Chen2024_AccurateRobustPrivacyPreservingBrainComputer","title":"Accurate, Robust and Privacy-Preserving Brain-Computer Interface Decoding","authors":"Xiaoqing Chen et al.","year":2024,"venue":"Fundamental Research","doi":"10.1016/J.FMRE.2026.04.034","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":"https://github.com/xqchen914/PAT","tldr":"Real-world EEG-BCIs face three challenges simultaneously (limited accuracy, poor robustness, and privacy risk) that are rarely addressed together. Proposes Privacy-preserving Adversarial Transfer (PAT), a unified training framework combining data alignment, adversarial training, and privacy-preserving transfer, instantiable under three privacy-preserving scenarios (centralized source-free transfer, federated source-free transfer, and transfer with privacy-preserved source data) while jointly improving accuracy and robustness. On five public EEG datasets across the three scenarios, PAT outperformed over ten classic and state-of-the-art methods and exceeded leading non-private transfer methods by 9.76% in combined accuracy and robustness."},{"id":"Meng2024_AdversarialFilteringEvasionBackdoorAttacksEEG","title":"Adversarial filtering based evasion and backdoor attacks to EEG-based brain-computer interfaces","authors":"Lubin Meng et al.","year":2024,"venue":"Inf. Fusion","doi":"10.1016/J.INFFUS.2024.102316","topic":"Robustness & Security","paradigm":[],"code_url":"https://github.com/lbinmeng/adversarial_filter","tldr":"Most EEG-based BCI research targets decoding accuracy while ignoring security, yet BCI machine-learning models are vulnerable to adversarial attacks. This paper proposes easy-to-implement evasion and backdoor (poisoning) attacks based on adversarial filtering, i.e. crafting a malicious linear filter applied to EEG signals. It is the first study of adversarial filtering for EEG-based BCIs. Experiments on three datasets from different BCI paradigms demonstrated the attacks' effectiveness, raising a new BCI security concern."},{"id":"Chen2024_AlignmentAdversarialTrainingABATImprovingRobustness","title":"Alignment-Based Adversarial Training (ABAT) for Improving the Robustness and Accuracy of EEG-Based BCIs","authors":"Xiaoqing Chen et al.","year":2024,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2024.3391936","topic":"Foundation & Self-Supervised Models","paradigm":["P300"],"code_url":"https://github.com/xqchen914/ABAT","tldr":"Adversarial defenses imported from computer vision degrade EEG-BCI classification accuracy on benign samples, limiting their applicability. Proposes alignment-based adversarial training (ABAT), which performs EEG data alignment (reducing cross-domain distribution discrepancies) before adversarial training (robustifying the decision boundary), making classifiers simultaneously more accurate and more robust. Experiments on five EEG datasets from two paradigms (motor imagery and ERP), three CNNs (EEGNet, ShallowCNN, DeepCNN), and three settings (offline within-subject, online cross-session, and pre-trained classifiers) show adversarial attacks can be repurposed to jointly improve accuracy and robustness."},{"id":"Zhao2024_BaggingBoostingFineTuningEnsembleLearning","title":"Bagging and Boosting Fine-Tuning for Ensemble Learning","authors":"Changming Zhao et al.","year":2024,"venue":"IEEE Trans. Artif. Intell.","doi":"10.1109/TAI.2023.3296685","topic":"Robustness & Security","paradigm":[],"code_url":"https://github.com/zhaochangming/BBF","tldr":"Bagging and boosting are suited to base learners with large variance or large bias respectively, but not to low-variance/low-bias learners such as SVMs and regularized logistic/ridge regression. This paper proposes boosting fine-tuning (BF), which embeds boosting inside a single-hidden-layer neural network and uses Newton's method to generate a temporary training set for each boosting learner, and bagging-and-boosting fine-tuning (BBF), which trains a BF learner on each bootstrap replica of the training set. Experiments on 46 real-world datasets show BBF flexibly, robustly, and effectively fine-tunes many popular classifiers to better generalization."},{"id":"Wang2024_ChannelReflectionKnowledgeDrivenDataAugmentation","title":"Channel reflection: Knowledge-driven data augmentation for EEG-based brain-computer interfaces","authors":"Ziwei Wang et al.","year":2024,"venue":"Neural Networks","doi":"10.1016/J.NEUNET.2024.106351","topic":"Robustness & Security","paradigm":["Seizure"],"code_url":"https://github.com/sylyoung/DeepTransferEEG","tldr":"EEG-based BCIs usually need subject-specific calibration data, which is often too scarce for purely data-driven decoders. This paper proposes channel reflection (CR), a parameter-free data-augmentation method that uses prior knowledge of the left-right symmetry of scalp EEG channel layouts to swap/reflect channels across hemispheres, tailored to different BCI paradigms. Experiments on eight public datasets spanning motor imagery, SSVEP, P300, and seizure classification with several decoders show CR is effective, robust (consistently beating existing augmentations), and complementary to other augmentation methods."},{"id":"Wang2024_CrossSpeciesCrossModalityEpilepticSeizure","title":"Cross-Species and Cross-Modality Epileptic Seizure Detection via Multi-Space Alignment","authors":"Z. Wang et al.","year":2024,"venue":"National Science Review","doi":"10.1093/NSR/NWAF086","topic":"Transfer Learning & Alignment","paradigm":["Seizure"],"code_url":"https://github.com/wzwvv/CST","tldr":"Epileptic seizure detection is hindered by scarce labeled data and by heterogeneity across species and recording modalities. Proposes a multi-space alignment framework (ResizeNet plus Multi-Space Alignment) that uses domain adaptation and knowledge distillation to align cross-species (human/canine) and cross-modality (scalp/intracranial) EEG, enabling knowledge transfer beyond within-species/within-modality models. On multiple surface and intracranial EEG datasets of humans and canines it achieved over 90% AUC for cross-species and cross-modality seizure detection with extremely limited target labels, reportedly the first demonstration that integrating heterogeneous species/modality data improves EEG seizure detection."},{"id":"Xu2024_CrossTaskInconsistencyActiveLearningCTIAL","title":"Cross-Task Inconsistency Based Active Learning (CTIAL) for Emotion Recognition","authors":"Yifan Xu et al.","year":2024,"venue":"IEEE Trans. Affect. Comput.","doi":"10.1109/TAFFC.2024.3366767","topic":"Active Learning","paradigm":["Affect"],"code_url":"https://github.com/LaviexXu/CTIAL-Cross-Task-Inconsistency-Based-Active-Learning-for-Emotion-Recognition","tldr":"Training accurate emotion-recognition models needs costly labels, since each affective sample usually requires multiple evaluators. This paper proposes cross-task inconsistency based active learning (CTIAL), which uses affective norms as prior knowledge to bridge the label spaces of categorical emotion classification and dimensional emotion estimation, then selects the unlabeled samples whose predictions are most inconsistent across the two tasks for labeling in the target task. Experiments on within-corpus and cross-corpus transfers show cross-task inconsistency is a valuable active-learning metric. It is the first work to exploit prior knowledge and data from a different task to aid active learning for a new task."},{"id":"Jiang2024_CSPNetCommonSpatialPatternEmpowered","title":"CSP-Net: Common spatial pattern empowered neural networks for EEG-based motor imagery classification","authors":"Xue Jiang et al.","year":2024,"venue":"Knowl. Based Syst.","doi":"10.1016/J.KNOSYS.2024.112668","topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":"https://github.com/jxgogo/CSP-Net","tldr":"EEG motor-imagery (MI) classification benefits from both knowledge-driven common spatial pattern (CSP) filters and data-driven CNNs, but they are typically used separately. This paper proposes two CSP-empowered networks. CSP-Net-1 inserts a CSP layer before a CNN to improve input discriminability, and CSP-Net-2 replaces a CNN convolutional layer with a CSP layer. The CSP layers are initialized from CSP filters designed on training data and can be kept fixed or fine-tuned by gradient descent. On four public MI datasets, both CSP-Nets consistently improved over their CNN backbones in within- and cross-subject settings, especially with very few training samples."},{"id":"Jiang2024_DeepSourceSemiSupervisedTransferLearning","title":"Deep Source Semi-Supervised Transfer Learning (DS3TL) for Cross-Subject EEG Classification","authors":"Xue Jiang et al.","year":2024,"venue":"IEEE Trans. Biomed. Eng.","doi":"10.1109/TBME.2023.3333327","topic":"Foundation & Self-Supervised Models","paradigm":[],"code_url":"https://github.com/jxgogo/DS3TL","tldr":"EEG-based BCIs typically require many labeled trials, which are costly and user-unfriendly to collect. This paper proposes deep source semi-supervised transfer learning (DS3TL) for the setting where the source subject has a few labeled plus many unlabeled trials and all target-subject trials are unlabeled. It combines a hybrid SSL module (pseudo-labeling + consistency regularization), a weakly-supervised contrastive module using true and pseudo labels, and an uncertainty-reduction domain adaptation module. On three EEG datasets it outperformed a supervised baseline trained with many more labels and several state-of-the-art SSL methods. It is the first BCI approach to exploit unlabeled source data for more accurate target-classifier training."},{"id":"Fu2024_EffectiveEfficientIntracorticalBrainSignalDecoding","title":"Effective and Efficient Intracortical Brain Signal Decoding with Spiking Neural Networks","authors":"Haotian Fu et al.","year":2024,"venue":"Neurocomputing","doi":"10.1016/J.NEUCOM.2026.134374","topic":"Data Augmentation & Generation","paradigm":["iBCI"],"code_url":"https://github.com/1439278026/LSS-CA-SNN","tldr":"Invasive BCIs need both high decoding accuracy and low energy consumption. Proposes LSS-CA-SNN, a spiking neural network combining local synaptic stabilization (LSS, which optimizes neuronal membrane-potential dynamics to boost accuracy) and channel-wise attention (CA, which refines neuronal activation to reduce energy), plus SpikeDrop, a spiking-data augmentation that randomly masks spikes to expand training data. On invasive spiking datasets recorded from two rhesus macaques, LSS-CA-SNN surpassed state-of-the-art ANNs with 0.80-3.87% accuracy gains and 14.78-43.86x energy savings, and SpikeDrop is described as the first augmentation tailored to spiking data."},{"id":"Jia2024_FederatedMotorImageryClassificationPrivacyPreserving","title":"Federated Motor Imagery Classification for Privacy-Preserving Brain-Computer Interfaces","authors":"Tianwang Jia et al.","year":2024,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2024.3457504","topic":"Privacy-Preserving BCI","paradigm":["MI"],"code_url":"https://github.com/TianwangJia/FedBS","tldr":"Training an accurate EEG-BCI classifier needs data from many users, but their privacy must be protected, and federated learning (FL) is a promising solution. Proposes FedBS (Federated classification with local Batch-specific batch normalization and Sharpness-aware minimization): local batch-specific batch normalization keeps each client's BN statistics private while mitigating feature shift across clients, and the sharpness-aware minimization optimizer in local training drives client models toward flatter minima for better generalization. On three public MI datasets with three deep models, FedBS outperformed six state-of-the-art FL approaches and even surpassed (non-private) centralized training."},{"id":"Chen2024_FrontEndReplicationDynamicWindowFRDW","title":"Front-end Replication Dynamic Window (FRDW) for Online Motor Imagery Classification","authors":"Xinru Chen et al.","year":2024,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2023.3321640","topic":"Data Augmentation & Generation","paradigm":["MI"],"code_url":"https://github.com/XinRu2001/FRDW","tldr":"Online MI classification must be both accurate and fast despite varying trial lengths, a speed-accuracy trade-off, and large individual differences. Proposes front-end replication dynamic window (FRDW): a dynamic window classifies test trials shorter than the training length for faster decisions, front-end replication fills a short test trial to the training length for higher accuracy, and Euclidean alignment is integrated to handle cross-subject individual differences. On three public MI datasets with three classifiers and three data-augmentation methods, FRDW significantly increased the information transfer rate, and it helped win national champion of the 2022 China BCI Competition."},{"id":"Peng2024_KnowledgeDataFusionSourceFreeSemi","title":"Knowledge-Data Fusion Based Source-Free Semi-Supervised Domain Adaptation for Seizure Subtype Classification","authors":"Ruimin Peng et al.","year":2024,"venue":"SMC","doi":"10.1109/SMC54092.2024.10831339","topic":"Foundation & Self-Supervised Models","paradigm":["Seizure"],"code_url":"https://github.com/rmpeng/MutualSHOT","tldr":"Addresses source-free semi-supervised domain adaptation (SF-SSDA) for privacy-preserving EEG-based seizure subtype classification, tackling how to fuse raw EEG data with expert knowledge in classifier design and how to align source/target distributions without access to source data. Proposes KDF-MutualSHOT: source pre-training (KDF) uses Jensen-Shannon divergence for mutual learning between a knowledge-driven Soft Decision Tree over expert features and a data-driven Vision Transformer over raw EEG, and target adaptation uses MutualSHOT, an SF-SSDA algorithm with a consistency-based pseudo-label selection strategy. On the public TUSZ and CHSZ datasets it outperformed other supervised and source-free domain adaptation approaches in cross-subject seizure subtype classification."},{"id":"Wu2024_MotorImageryClassificationAsynchronousEEGBrain","title":"Motor Imagery Classification for Asynchronous EEG-Based Brain-Computer Interfaces","authors":"Huanyu Wu et al.","year":2024,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2024.3356916","topic":"Foundation & Self-Supervised Models","paradigm":["MI"],"code_url":"https://github.com/why135724/SWPC","tldr":"Asynchronous MI-based BCIs must decode without explicit triggers, first separating resting-state from MI and then classifying the MI task. Proposes sliding window prescreening and classification (SWPC): a prescreening EEGNet module screens MI trials out of the resting-state, then a classification EEGNet module classifies them, with both modules trained by supervised learning followed by self-supervised learning to refine the feature extractors. Within- and cross-subject experiments on four MI datasets show SWPC always achieved the highest average accuracy, beating the best state-of-the-art baseline on each dataset by about 2%."},{"id":"Peng2024_MultiBranchMutualDistillationTransformerEEG","title":"Multi-Branch Mutual-Distillation Transformer for EEG-Based Seizure Subtype Classification","authors":"Ruimin Peng et al.","year":2024,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2024.3365713","topic":"Transfer Learning & Alignment","paradigm":["Seizure"],"code_url":"https://github.com/rmpeng/EBE-Transformer","tldr":"Cross-subject EEG-based seizure subtype classification is clinically important, but deep models usually need large labeled datasets that are scarce in practice. Proposes the Multi-Branch Mutual-Distillation (MBMD) Transformer, which replaces the even-numbered encoder blocks of a vanilla Vision Transformer with designed multi-branch encoder blocks and applies a mutual-distillation strategy to transfer knowledge between the raw EEG and its wavelets of different frequency bands, enabling effective training from small labeled data. On two public EEG datasets it outperformed several traditional machine learning and state-of-the-art deep-learning approaches, and the authors state it is the first work on knowledge distillation for EEG-based seizure subtype classification."},{"id":"Meng2024_ProtectingMultipleTypesPrivacySimultaneouslyEEG","title":"Protecting Multiple Types of Privacy Simultaneously in EEG-Based Brain-Computer Interfaces","authors":"Lubin Meng et al.","year":2024,"venue":"SMC","doi":"10.1109/SMC54092.2024.10832088","topic":"Privacy-Preserving BCI","paradigm":["Biometric"],"code_url":"https://github.com/lbinmeng/Multi-privacy-protection","tldr":"EEG signals inherently carry rich personal information beyond the intended BCI task. This paper demonstrates that multiple private attributes (user identity, gender, and BCI-experience) can be easily inferred from EEG, then designs perturbations that convert raw EEG into privacy-protected EEG concealing these attributes while preserving primary BCI task performance. Experiments show the protected data sharply reduce identity/gender/experience classification accuracy while barely affecting the main BCI task accuracy."},{"id":"Deng2024_SemisupervisedTransferBoostingSSTrBoosting","title":"Semisupervised Transfer Boosting (SS-TrBoosting)","authors":"Lingfei Deng et al.","year":2024,"venue":"IEEE Trans. Artif. Intell.","doi":"10.1109/TAI.2024.3350543","topic":"Data Augmentation & Generation","paradigm":[],"code_url":"https://github.com/Fly-Deng/SS-TrBoosting","tldr":"Semi-supervised domain adaptation (SSDA) struggles to find a feature space where source and target share the same conditional distribution, and there is no flexible strategy to extend unsupervised domain adaptation (UDA) methods to SSDA. This paper proposes semi-supervised transfer boosting (SS-TrBoosting). Starting from a well-trained UDA/SSDA model as the initial learner, it generates additional base learners by boosting (half via supervised domain adaptation and half via semi-supervised learning) and ensembles them, plus a source-data generation approach that extends it to source-free SSDA (SS-SFDA). Extensive experiments on three real-world datasets show it improves many existing UDA, SSDA, and SFDA methods."},{"id":"Li2024_TTIMETestTimeInformationMaximization","title":"T-TIME: Test-Time Information Maximization Ensemble for Plug-and-Play BCIs","authors":"Siyang Li et al.","year":2024,"venue":"IEEE Trans. Biomed. Eng.","doi":"10.1109/TBME.2023.3303289","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":"https://github.com/sylyoung/DeepTransferEEG","tldr":"Existing transfer learning for EEG BCIs mostly assumes an offline setting with access to all unlabeled target trials, whereas real online use needs immediate classification of streaming trials. This paper proposes Test-Time Information Maximization Ensemble (T-TIME). It initializes multiple classifiers from Euclidean-aligned source data, predicts each incoming unlabeled trial by ensembling, then updates each classifier online via conditional entropy minimization and adaptive marginal-distribution regularization. On three public motor-imagery datasets T-TIME outperformed about 20 classical and state-of-the-art TL approaches. It is the first test-time adaptation for calibration-free, plug-and-play EEG BCIs."},{"id":"Chen2024_UserWisePerturbationsUserIdentityProtection","title":"User-wise Perturbations for User Identity Protection in EEG-Based BCIs","authors":"Xiaoqing Chen et al.","year":2024,"venue":"Journal of Neural Engineering","doi":"10.1088/1741-2552/AD88A5","topic":"Privacy-Preserving BCI","paradigm":["Biometric"],"code_url":"https://github.com/xqchen914/Unlearnable-examples-for-EEG","tldr":"Beyond task information, EEG contains private user-identity information that should be protectable. This work shows for the first time that adding user-wise perturbations can make identity information in EEG unlearnable while preserving BCI task information. Proposes four types of user-wise privacy-preserving perturbations (random noise, synthetic noise, error-minimization noise, and error-maximization noise) added to EEG training data so a user-identification model cannot learn identity, unlike a prior sample/user-wise method that also required perturbing test data. Experiments on six EEG datasets with three neural-network classifiers and various traditional models demonstrate robustness and practicability."},{"id":"Jiang2024_CSPRetrainingFrameworkMotorImageryBrain","title":"A CSP-based retraining framework for motor imagery based brain-computer interfaces","authors":"Xue Jiang et al.","year":2024,"venue":"Sci. China Inf. Sci.","doi":"10.1007/S11432-024-4081-X","topic":"Robustness & Security","paradigm":["Speech"],"code_url":null,"tldr":"For motor-imagery EEG, traditional CSP-based pipelines are robust with small data but suboptimal, while deep networks need much more labeled data to avoid overfitting. This Science China Information Sciences letter proposes a CSP-based retraining framework that instantiates a neural network with the same forward computation and initial parameters as the traditional CSP model, then further optimizes it on labeled data via gradient descent. On four MI datasets, retraining improves the traditional model's accuracy and outperforms several popular deep networks, particularly when labeled training data are very scarce."},{"id":"Chen2024_DistributedNashEquilibriumSeekingGamesNonlinear","title":"Distributed Nash Equilibrium Seeking for Games with Nonlinear Players via Fuzzy Adaptive Control","authors":"Ying Chen et al.","year":2024,"venue":"FUZZ","doi":"10.1109/FUZZ-IEEE60900.2024.10611868","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"This paper addresses distributed Nash equilibrium (NE) seeking in noncooperative games where players have unknown high-order nonlinear dynamics. It employs a fuzzy observer to estimate the unknown nonlinearities and unmeasurable states, then develops an observer-based distributed NE-seeking algorithm via fuzzy adaptive backstepping, guaranteeing players' actions converge to a neighborhood of the NE with all closed-loop signals bounded. A numerical example demonstrates the algorithm's effectiveness."},{"id":null,"title":"Future-generation attack and defense in neural networks","authors":"Yang Li et al.","year":2024,"venue":"Future Gener. Comput. Syst.","doi":"10.1016/J.FUTURE.2023.10.017","topic":"Robustness & Security","paradigm":[],"code_url":null,"tldr":""},{"id":"Wang2024_GatedParametricNeuronSpikeAudioRecognition","title":"Gated parametric neuron for spike-based audio recognition","authors":"Haoran Wang et al.","year":2024,"venue":"Neurocomputing","doi":"10.1016/J.NEUCOM.2024.128477","topic":"Deep Architectures","paradigm":[],"code_url":null,"tldr":"Spiking neural networks (SNNs) built on the standard leaky integrate-and-fire (LIF) neuron suffer from vanishing gradients under backpropagation and rely on manually fixed, homogeneous neuronal parameters, unlike real neurons. This paper proposes the gated parametric neuron (GPN), which uses a gating mechanism to improve gradient flow and automatically learn spatio-temporal heterogeneous neuronal parameters, and embeds it in a hybrid RNN-SNN architecture (the same gate also removes initial-parameter selection). On two spike-based audio datasets, the GPN network outperformed several state-of-the-art SNNs while mitigating vanishing gradients and capturing long-term dependencies."},{"id":"Zheng2024_SemiSupervisedDomainAdaptationEegSleep","title":"Semi-Supervised Domain Adaptation for Eeg-Based Sleep Stage Classification","authors":"Shitao Zheng et al.","year":2024,"venue":"ICASSP","doi":"10.1109/ICASSP48485.2024.10448352","topic":"Transfer Learning & Alignment","paradigm":["Sleep"],"code_url":null,"tldr":"Deep-learning EEG sleep-stage classification is hindered by cross-subject domain shift and insufficient labeled patient data. This paper proposes a Transformer-based semi-supervised domain adaptation (SSDA) approach that uses two class tokens to separately extract source- and target-domain knowledge, combined with a training-test strategy using adaptive entropy-weighted ensembling, attention-based adaptation, and consistency regularization to improve target-domain performance. Experiments on two public datasets demonstrated its effectiveness."},{"id":"Xiong2024_StochasticGradientDescentRandomLabelNoises","title":"Stochastic gradient descent with random label noises: doubly stochastic models and inference stabilizer","authors":"Haoyi Xiong et al.","year":2024,"venue":"Mach. Learn. Sci. Technol.","doi":"10.1088/2632-2153/AD13BA","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":null,"tldr":"This work studies the implicit-regularization effect of unbiased random label noise in stochastic gradient descent (SGD), rather than its effect on accuracy. It models SGD dynamics on a quadratic loss as a stochastic differential equation with two diffusion terms, forming a doubly stochastic model. One term comes from mini-batch sampling of loss gradients and a second from mini-batch sampling of the label noise acting as an implicit regularizer. Without assuming an Ornstein-Uhlenbeck process, it proves that this regularizer favors convergence points that stabilize model outputs against parameter perturbations (inference stability). Two sets of experiments validate the analysis and the resulting inference stabilizer."},{"id":null,"title":"Time-Aware Attention-Based Transformer (TAAT) for Cloud Computing System Failure Prediction","authors":"Lingfei Deng et al.","year":2024,"venue":"KDD","doi":"10.1145/3637528.3671547","topic":"Deep Architectures","paradigm":[],"code_url":null,"tldr":""},{"id":null,"title":"TMMM: Transformer in Multimodal Sentiment Analysis under Missing Modalities","authors":"Huanyu Wu et al.","year":2024,"venue":"IJCNN","doi":"10.1109/IJCNN60899.2024.10651217","topic":"Deep Architectures","paradigm":[],"code_url":null,"tldr":""},{"id":"Zhang2020_OvercomingNegativeTransferSurvey","title":"A Survey on Negative Transfer","authors":"Wen Zhang et al.","year":2023,"venue":"IEEE CAA J. Autom. Sinica","doi":"10.1109/JAS.2022.106004","topic":"Transfer Learning & Alignment","paradigm":["Affect"],"code_url":"https://github.com/chamwen/NT-Benchmark","tldr":"Provides a systematic survey of negative transfer (NT), i.e., when using source-domain data/knowledge undesirably reduces target-domain learning performance, which had lacked a unified treatment. It formalizes the definition and contributing factors of NT and reviews about fifty representative mitigation approaches organized into four categories: secure/safe transfer, domain similarity estimation, distant transfer, and NT mitigation, and further discusses NT in related fields (multi-task learning, lifelong learning, adversarial attacks). The published version adds a benchmark comparing over 20 NT-detection methods on synthetic and real object- and emotion-recognition datasets."},{"id":"Jiang2023_ActivePoisoningEfficientBackdoorAttacksTransfer","title":"Active poisoning: efficient backdoor attacks on transfer learning-based brain-computer interfaces","authors":"Xue Jiang et al.","year":2023,"venue":"Sci. China Inf. Sci.","doi":"10.1007/S11432-022-3548-2","topic":"Robustness & Security","paradigm":[],"code_url":"https://github.com/jxgogo/Active_Poisoning","tldr":"Transfer learning reduces EEG-BCI calibration effort but opens a backdoor-attack vector, by poisoning source-domain data with a trigger so the transferred model misclassifies triggered test samples into an attacker-specified class while behaving normally on benign samples. Proposes several active poisoning (AP) strategies (maximum diversity sampling, representativeness-and-diversity sampling, minimum uncertainty sampling, minimum model change sampling, and combinations) to select the source samples most beneficial to poison, improving attack success rate and stealthiness. Experiments on four EEG datasets and three CNN models show TL-based BCIs are vulnerable even under fine-tuning and data augmentation. It is described as the first study of backdoor attacks on TL models in EEG-based BCIs."},{"id":"Meng2023_AdversarialRobustnessBenchmarkEEGBrainComputer","title":"Adversarial robustness benchmark for EEG-based brain-computer interfaces","authors":"Lubin Meng et al.","year":2023,"venue":"Future Gener. Comput. Syst.","doi":"10.1016/J.FUTURE.2023.01.028","topic":"Robustness & Security","paradigm":[],"code_url":"https://github.com/lbinmeng/bci_adv_defense","tldr":"Addresses the security of EEG-based brain-computer interfaces (BCIs), which are known to be vulnerable to adversarial examples but for which no prior study had examined adversarial defenses. The paper benchmarks nine classical and state-of-the-art adversarial defense approaches across three convolutional neural networks and two EEG datasets under multiple attack scenarios, establishing the first comprehensive adversarial-defense benchmark for EEG-based BCIs. From the evaluation it draws key observations to guide future defense research and raise attention to BCI adversarial security."},{"id":"Cui2023_LayerNormalizationTSKFuzzySystemOptimization","title":"Layer Normalization for TSK Fuzzy System Optimization in Regression Problems","authors":"Yuqi Cui et al.","year":2023,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2022.3185464","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/YuqiCui/HTSK-LN","tldr":"Addresses the sensitivity of mini-batch gradient descent (MBGD)-trained Takagi-Sugeno-Kang (TSK) fuzzy systems to optimizer choice, which the authors attribute to a gradient-vanishing problem on rule consequent parameters caused by the small magnitude of normalized rule firing levels (worse when the rulebase is large). It proposes applying first layer normalization (LN) to amplify the small firing levels and then a ReLU to discard rules far from the current sample, yielding HTSK-LN and HTSK-LN-ReLU built on the prior high-dimensional TSK (HTSK) model. On twelve regression datasets of varied size and dimensionality, the methods significantly improve generalization regardless of training-set size, dimensionality, optimizer, and rulebase size."},{"id":"Peng2023_WAVELET2VECFilterBankMaskedAutoencoderEEG","title":"WAVELET2VEC: A Filter Bank Masked Autoencoder for EEG-Based Seizure Subtype Classification","authors":"Ruimin Peng et al.","year":2023,"venue":"ICASSP","doi":"10.1109/ICASSP49357.2023.10097183","topic":"Foundation & Self-Supervised Models","paradigm":["Seizure"],"code_url":"https://github.com/rmpeng/Wavelet2Vec","tldr":"Targets EEG-based seizure subtype classification, which is limited by CNN/RNN difficulty in learning long-term dependencies and by scarce labeled subtype data. Proposes a Transformer-based self-supervised model in which filter-bank analysis turns a Vision Transformer into a Wavelet Transformer (WaT) encoder producing multi-grained EEG feature representations, pre-trained as a masked autoencoder on unlabeled EEG. On two public datasets, Wavelet2Vec outperforms several supervised and self-supervised baselines in cross-subject seizure subtype classification."},{"id":null,"title":"23rd IEEE/ACIS International Conference on Computer and Information Science, ICIS 2023, Wuxi, China, June 23-25, 2023","authors":"Yuan Liu et al.","year":2023,"venue":"ICIS","doi":"10.1109/ICIS57766.2023","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":"Wu2023_AccurateSecurePrivacyPreservingBrainComputer","title":"Accurate, Secure and Privacy-Preserving Brain-Computer Interfaces: Keynote Address","authors":"Dongrui Wu","year":2023,"venue":"ICIS","doi":"10.1109/ICIS57766.2023.10210238","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":null,"tldr":"A one-page keynote-address abstract (ICIS 2023) by Dongrui Wu outlining a research vision for brain-computer interfaces that are simultaneously accurate, secure, and privacy-preserving. It summarizes transfer-learning approaches to expedite or eliminate BCI calibration, and discusses adversarial attacks and privacy-protection approaches for BCIs. It is a talk summary with author biography rather than a technical methods paper, containing no experiments."},{"id":null,"title":"Affective Brain-Computer Interfaces (aBCIs): A Tutorial","authors":"Dongrui Wu et al.","year":2023,"venue":"Proc. IEEE","doi":"10.1109/JPROC.2023.3277471","topic":"General ML & Optimization","paradigm":["Affect"],"code_url":null,"tldr":""},{"id":null,"title":"BoostTree and BoostForest for Ensemble Learning","authors":"Changming Zhao et al.","year":2023,"venue":"IEEE Trans. Pattern Anal. Mach. Intell.","doi":"10.1109/TPAMI.2022.3227370","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":"Xu2023_CrossModalDiversityActiveLearningMulti","title":"Cross-Modal Diversity-Based Active Learning for Multi-Modal Emotion Estimation","authors":"Yifan Xu et al.","year":2023,"venue":"IJCNN","doi":"10.1109/IJCNN54540.2023.10191581","topic":"Active Learning","paradigm":["Affect"],"code_url":null,"tldr":"Addresses the high cost of labeling emotion data, where each sample typically needs multiple annotators, in a previously unexplored multi-modal unsupervised active-learning-for-regression setting. It proposes a cross-modal diversity measure that captures the correlation between different modalities and integrates it with representativeness to select samples for unsupervised active learning. Experiments on the RECOLA and IEMOCAP datasets demonstrate improved multi-modal emotion estimation over baselines."},{"id":"Sun2023_DARCHighDimensionalDiffusingAnomalyDetection","title":"DARC: High-dimensional Diffusing Anomaly Detection and Root Cause Location in Cloud Computing Systems","authors":"Wanning Sun et al.","year":2023,"venue":"IEEE Big Data","doi":"10.1109/BIGDATA59044.2023.10386246","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"Addresses early detection and root-cause location of diffusing anomalies in large, dynamic cloud computing systems, where the high-dimensional attribute space makes locating causes an NP-hard combinatorial search. Proposes DARC, which uses two-stage percentile analysis plus Mann-Kendall trend-score thresholding to detect rare anomalies, then a bottom-up search strategy with three computational-complexity-reduction techniques to efficiently locate root causes. Extensive experiments show accurate and efficient root-cause location, and DARC has been deployed in the daily practice of Alibaba Cloud."},{"id":"Dong2023_DeformableObjectManipulationHumanDemonstrationEnhanced","title":"Deformable Object Manipulation Using Human Demonstration Enhanced Deep Deterministic Policy Gradient","authors":"Zihao Dong et al.","year":2023,"venue":"MHS","doi":"10.1109/MHS59931.2023.10510085","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses reinforcement-learning-based deformable-object manipulation, which needs large amounts of data/time and makes inefficient use of human demonstrations (HD) because a poorly trained critic underuses them early in training. The proposed HDE-DDPG decouples the action into grasp and place primitives with conditional policy training, uses a high-dimensional Takagi-Sugeno-Kang (HTSK) fuzzy classifier for grasp-point selection feeding the actor, and pretrains the critic to assign higher scores to HD actions so behavior cloning is exploited more frequently and appropriately. Ablation experiments show significantly faster training and superior, more consistent performance."},{"id":null,"title":"Lightweight Source-Free Transfer for Privacy-Preserving Motor Imagery Classification","authors":"Wen Zhang et al.","year":2023,"venue":"IEEE Trans. Cogn. Dev. Syst.","doi":"10.1109/TCDS.2022.3193731","topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":null,"tldr":"Offline unsupervised cross-subject motor-imagery transfer that protects source-subject privacy. It generates source models locally and encapsulates them as APIs, builds a virtual intermediate domain to transfer knowledge to the target, then performs feature adaptation. Source-free and lightweight (few parameters, no access to source data or massive source models). On four MI datasets it outperformed 13 approaches, including transfer methods that use the source samples or model parameters directly.\n"},{"id":"Zhang2023_MultiModalityFusionAmpInductiveKnowledge","title":"Multi-Modality Fusion & Inductive Knowledge Transfer Underlying Non-Sparse Multi-Kernel Learning and Distribution Adaption","authors":"Yuanpeng Zhang et al.","year":2023,"venue":"IEEE ACM Trans. Comput. Biol. Bioinform.","doi":"10.1109/TCBB.2022.3142748","topic":"Transfer Learning & Alignment","paradigm":["Seizure"],"code_url":null,"tldr":"Tackles multi-modal biomedical data analysis under two obstacles: multiple modalities/feature spaces and insufficient labeled samples. Proposes a feature-level fusion model that extends kernel ridge regression to a non-sparse (lp-norm constrained) multi-kernel version to exploit complementary cross-modal patterns, combined with marginal probability distribution adaptation (transfer learning) to mitigate scarce labels. On 12 multi-modality and transfer scenarios constructed from the University of Bonn epilepsy EEG data, the model outperforms baselines on most scenarios."},{"id":"Xia2023_PrivacyPreservingBrainComputerInterfacesSystematic","title":"Privacy-Preserving Brain-Computer Interfaces: A Systematic Review","authors":"Kun Xia et al.","year":2023,"venue":"IEEE Trans. Comput. Soc. Syst.","doi":"10.1109/TCSS.2022.3184818","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":null,"tldr":"A systematic review of privacy-preserving brain-computer interfaces, motivated by the observation that most BCI research targets accuracy and reliability while data and model transmission among collaborating organizations (hospitals, universities, companies) poses serious privacy threats, and no contemporary comprehensive review existed. It describes potential privacy threats and protection strategies (e.g., cryptography, data perturbation, source-free transfer learning, and federated learning) in BCIs, and points out several challenges and future research directions for developing privacy-preserving BCIs."},{"id":null,"title":"Program Chair Message","authors":"Dongrui Wu et al.","year":2023,"venue":"ICIS","doi":"10.1109/ICIS57766.2023.10210253","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":"An2023_SemiSupervisedGeneralizedSourceFreeDomain","title":"Semi-Supervised Generalized Source-Free Domain Adaptation (SSG-SFDA)","authors":"Jiayu An et al.","year":2023,"venue":"IJCNN","doi":"10.1109/IJCNN54540.2023.10191761","topic":"Foundation & Self-Supervised Models","paradigm":[],"code_url":null,"tldr":"Addresses domain-incremental learning in a source-free, semi-supervised setting where only a pre-trained source model, a few labeled target samples, and many unlabeled target samples are available, and the model must perform well on all domains while protecting source-data privacy and avoiding catastrophic forgetting. The proposed SSG-SFDA trains a per-domain conditional variational autoencoder (CVAE) to model feature distributions plus a domain discriminator (using CVAE-generated virtual shallow features) for domain-ID-agnostic inference, uses soft domain attention to reduce forgetting, and applies MixMatch to better exploit the few labels. Experiments on three datasets demonstrate its effectiveness."},{"id":null,"title":"Type-1 and Interval Type-2 Fuzzy Systems [AI- eXplained]","authors":"Dongrui Wu et al.","year":2023,"venue":"IEEE Comput. Intell. Mag.","doi":"10.1109/MCI.2022.3223496","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":""},{"id":"Gong2023_ZeroSumGameSecureTrackingControl","title":"Zero-Sum Game Based Secure Tracking Control of UAV Against FDI Attacks Using Fixed-Time Convergent Reinforcement Learning","authors":"Zhenyu Gong et al.","year":2023,"venue":"CDC","doi":"10.1109/CDC49753.2023.10384146","topic":"Robustness & Security","paradigm":[],"code_url":null,"tldr":"Addresses secure trajectory-tracking control of a UAV whose actuators may be subject to false-data-injection (FDI) attacks that push it off its reference path. It formulates the problem as a zero-sum differential game between a secure controller (minimizing a common performance function) and an attacker (maximizing it), whose optimal controller requires solving the associated Hamilton-Jacobi-Isaacs (HJI) equation, and develops a critic-only online reinforcement-learning algorithm with a proven fixed-time convergence guarantee. A simulation example demonstrates the effectiveness of the proposed fixed-time convergent RL secure controller."},{"id":"Li2022_FacialAffectAnalysisLearningSyntheticData","title":"Facial Affect Analysis: Learning from Synthetic Data & Multi-Task Learning Challenges","authors":"Siyang Li et al.","year":2022,"venue":"CoRR","doi":"10.48550/ARXIV.2207.09748","topic":"Data Augmentation & Generation","paradigm":["Affect"],"code_url":"https://github.com/sylyoung/ABAW4-HUST-ANT","tldr":"Presents the HUST-ANT team's solutions to the two tracks of the 4th Affective Behavior Analysis in-the-Wild (ABAW) competition. For the Multi-Task-Learning (MTL) challenge it adopts SMM-EmotionNet with an improved ensemble strategy over feature vectors. For the Learning-from-Synthetic-Data (LSD) challenge it introduces methods addressing single labels, imbalanced distributions, fine-tuning limitations, and model-architecture choice. On the competition's official validation sets, both proposed approaches outperform the baselines by a large margin."},{"id":"Xia2022_PrivacyPreservingDomainAdaptationMotorImagery","title":"Privacy-Preserving Domain Adaptation for Motor Imagery-Based Brain-Computer Interfaces","authors":"Kun Xia et al.","year":2022,"venue":"IEEE Trans. Biomed. Eng.","doi":"10.1109/TBME.2022.3168570","topic":"Privacy-Preserving BCI","paradigm":["MI"],"code_url":"https://github.com/xkazm/ASFA","tldr":"Tackles the tension between cross-subject domain adaptation and user privacy in motor-imagery (MI) EEG BCIs, since sharing raw EEG leaks sensitive health/mental information. Proposes augmentation-based source-free adaptation (ASFA): source-model training with a novel MI-EEG data augmentation to boost cross-subject generalization, and target-model training that jointly performs uncertainty reduction and consistency regularization while accessing only source-model parameters (extended to a stricter setting where even parameters are inaccessible). On four MI datasets ASFA outperforms 15 classical and state-of-the-art methods, and is presented as the first completely source-free domain adaptation for EEG-based BCIs."},{"id":"Cui2022_PyTSKPythonToolboxTSKFuzzySystems","title":"PyTSK: A Python Toolbox for TSK Fuzzy Systems","authors":"Yuqi Cui et al.","year":2022,"venue":"CoRR","doi":"10.48550/ARXIV.2206.03310","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/YuqiCui/pytsk","tldr":"Presents PyTSK, a Python toolbox for developing Takagi-Sugeno-Kang (TSK) fuzzy systems, built on scikit-learn and PyTorch. It lets users optimize TSK systems via fuzzy clustering (with separable, tunable antecedent/consequent modules exposed through scikit-learn APIs such as GridSearchCV) or via mini-batch gradient descent (MBGD), implementing several state-of-the-art MBGD algorithms that improve generalization for big-data applications, and is easily extended for custom fuzzy structures, more sophisticated training algorithms, and combinations of TSK systems with neural networks."},{"id":"Bian2022_SSVEPBrainComputerInterfacesVulnerableSquare","title":"SSVEP-based brain-computer interfaces are vulnerable to square wave attacks","authors":"Rui Bian et al.","year":2022,"venue":"Sci. China Inf. Sci.","doi":"10.1007/S11432-022-3440-5","topic":"Privacy-Preserving BCI","paradigm":["SSVEP"],"code_url":"https://github.com/BianRuiBR/SquareWaveAttack","tldr":"Addresses the security of steady-state visual evoked potential (SSVEP)-based BCIs, noting that existing EEG adversarial attacks are hard to implement in real-world systems. Exploiting SSVEP's dependence on frequency information, it proposes using easily generated square-wave signals as adversarial perturbations. Adding such a perturbation can push EEG trials into any attacker-specified target class against canonical-correlation-analysis (CCA)-based SSVEP classifiers. Experiments on two SSVEP datasets demonstrate the attack's efficiency and robustness against two CCA-based classifiers, exposing a practical security flaw."},{"id":"Xie2022_AdaptiveImageSteganographyFuzzyEnhancementGrey","title":"Adaptive Image Steganography Using Fuzzy Enhancement and Grey Wolf Optimizer","authors":"Jialiang Xie et al.","year":2022,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2022.3164791","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Proposes an adaptive image steganography scheme that embeds into edge and complex-texture regions following three design rules. Edges (both weak and strong) are detected by an improved fuzzy enhancement function optimized with the grey wolf optimizer (complexity-first rule). Complex-texture regions are selected by minimizing the average classification error rate. The embedding cost function is designed with two average filters and a KerBohme filter (spreading rule). Finally, secret data is embedded via syndrome-trellis codes. It outperforms seven classical adaptive steganography algorithms on two steganalytic feature sets, with the largest gains at high payloads."},{"id":"Chen2022_AdversarialArtifactDetectionEEGBrainComputer","title":"Adversarial Artifact Detection in EEG-Based Brain-Computer Interfaces","authors":"Xiaoqing Chen et al.","year":2022,"venue":"Journal of Neural Engineering","doi":"10.1088/1741-2552/AD8964","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":null,"tldr":"Studies the security of EEG-based BCIs, which are vulnerable to adversarial attacks where small input perturbations cause misclassification, making detection of adversarial examples important for understanding and defense. Presents the first exploration of adversarial-example detection in EEG-based BCIs, evaluating multiple detection approaches on two EEG datasets with three convolutional neural networks. Results show both white-box and black-box attacks can be detected, with white-box attacks being easier to detect."},{"id":"Wu2022_AffectEstimation3DSpaceMultiTask","title":"Affect Estimation in 3D Space Using Multi-Task Active Learning for Regression","authors":"Dongrui Wu et al.","year":2022,"venue":"IEEE Trans. Affect. Comput.","doi":"10.1109/TAFFC.2019.2916040","topic":"Active Learning","paradigm":["Affect"],"code_url":null,"tldr":"Addresses the costly labeling of affective-computing data, where multiple assessors must rate each sample along three dimensions (valence, arousal, dominance). Proposes two multi-task active-learning-for-regression approaches that select the most beneficial samples to label by considering all three affect primitives simultaneously via greedy sampling in the combined feature/label space. On the VAM corpus, the optimal sample-selection strategies yield better 3D affect-estimation performance than random selection and several traditional single-task active-learning approaches, reducing the number of labeling queries needed."},{"id":"Tang2022_IntervalType2FuzzyEdgeDetection","title":"An interval type-2 fuzzy edge detection and matrix coding approach for color image adaptive steganography","authors":"Lili Tang et al.","year":2022,"venue":"Multim. Tools Appl.","doi":"10.1007/S11042-022-13127-0","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Proposes an adaptive color-image steganography method that jointly considers human-eye sensitivity to edges and the RGB color components. It detects edge/non-edge points via interval type-2 fuzzy similarity after noise estimation and filtering, uses a genetic algorithm to optimize per-channel embedding bits by message capacity, applies a chaotic method and random-sequence scrambling for security, and embeds via three matrix-coding schemes (LSB, Hamming code, XOR coding) of differing efficiency. Experiments show it hides large payloads with high stego-image quality and outperforms several state-of-the-art methods on payload, MSE, PSNR, and SSIM, with robustness confirmed by RS steganalysis and pixel-difference-histogram analysis."},{"id":"Liu2022_ExploringCommonPrincipalSubspaceDeepFeatures","title":"Exploring the common principal subspace of deep features in neural networks","authors":"Haoran Liu et al.","year":2022,"venue":"Mach. Learn.","doi":"10.1007/S10994-021-06076-6","topic":"Foundation & Self-Supervised Models","paradigm":[],"code_url":null,"tldr":"Investigates whether different deep neural networks learn similar feature spaces, an interpretability question. Finds that DNNs trained on the same dataset share a common principal subspace in latent space regardless of architecture (CNN/MLP/autoencoder) or supervision (supervised/unsupervised/self-supervised), and introduces a P-vector metric to represent this subspace and measure the angle between subspaces of different networks. Experiments on MNIST, CIFAR-10, and CIFAR-100 show near-zero angles (cosine near 1.0) between any two trained DNNs, that the angle shrinks from 70-80 degrees toward small values over training, and that the P-vector-to-data-subspace angle correlates with generalization."},{"id":null,"title":"Facial Expression Recognition In-the-Wild with Deep Pre-trained Models","authors":"Siyang Li et al.","year":2022,"venue":"ECCV Workshops","doi":"10.1007/978-3-031-25075-0_14","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":"Xie2022_GrayWolfOptimizationSelfOrganizingFuzzy","title":"Gray wolf optimization-based self-organizing fuzzy multi-objective evolution algorithm","authors":"Jialiang Xie et al.","year":2022,"venue":"Soft Comput.","doi":"10.1007/S00500-022-07492-Z","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Targets improving the convergence and diversity of multi-objective evolutionary algorithms (MOEAs), especially on problems with complex Pareto-front/Pareto-set shapes. Proposes a gray-wolf-optimization-based self-organizing fuzzy MOEA that uses gray wolf optimization to initialize the self-organizing map (SOM) network weights, builds individual neighborhoods via the SOM to preserve population structure in Pareto space, and generates offspring with a fuzzy differential-evolution operator (a fuzzy inference system dynamically tunes the DE weighting) refined by polynomial mutation. On 15 benchmark problems (GLT1-6 and WFG1-9) it attains the best result on 18 metric values, surpassing several state-of-the-art MOEAs in convergence and diversity."},{"id":"Xu2022_InconsistencyMultiTaskCooperativeLearningEmotion","title":"Inconsistency-Based Multi-Task Cooperative Learning for Emotion Recognition","authors":"Yifan Xu et al.","year":2022,"venue":"IEEE Trans. Affect. Comput.","doi":"10.1109/TAFFC.2022.3197414","topic":"Active Learning","paradigm":["Affect"],"code_url":null,"tldr":"Aims to reduce the costly multi-annotator labeling in multi-task emotion recognition. Introduces an inconsistency measure quantifying the difference between labels predicted from the feature space and the label distribution of the labeled set, then uses it as a sample-informativeness indicator in an inconsistency-based multi-task cooperative learning framework that unifies multi-task active learning with self-training semi-supervised learning. Experiments on two scenarios (multi-dimensional emotion estimation, and simultaneous emotion classification and estimation) show it outperforms several single-task and multi-task active-learning approaches."},{"id":"Chen2022_IntervalType2FuzzyDisturbanceObserver","title":"Interval Type-2 Fuzzy Disturbance Observer-Based T-S Fuzzy Control for a Pneumatic Flexible Joint","authors":"Cheng Chen et al.","year":2022,"venue":"IEEE Trans. Ind. Electron.","doi":"10.1109/TIE.2021.3090708","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses trajectory-tracking control of a flexible joint actuated by a pneumatic artificial muscle plus torsion spring under external disturbances. Proposes an interval type-2 fuzzy disturbance observer (IT2FDO) that injects IT2 fuzzy sets into a fuzzy disturbance observer to improve approximation, with a novel adaptive law updating all observer parameters (control representative values, center and width vectors), combined with Takagi-Sugeno fuzzy model-based control and guaranteed observer and closed-loop stability. Simulations verify the IT2FDO's effectiveness and real-world experiments demonstrate the control strategy's robustness to external disturbance."},{"id":"Mo2022_IntervalType2FuzzyHierarchicalAdaptive","title":"Interval Type-2 Fuzzy Hierarchical Adaptive Cruise Following-Control for Intelligent Vehicles","authors":"Hong Mo et al.","year":2022,"venue":"IEEE CAA J. Autom. Sinica","doi":"10.1109/JAS.2022.105806","topic":"Fuzzy Systems & Computing-with-Words","paradigm":["Drowsy"],"code_url":null,"tldr":"Addresses adaptive cruise following-control (ACFC) for intelligent vehicles, aiming to mimic human driving habits while accurately tracking the desired acceleration under nonlinear dynamics. Proposes a hierarchical control strategy synthesizing an improved variable time headway model (accounting for lead-car acceleration), an interval type-2 fuzzy logic controller (IT2 FLC) for the upper structure, and a feedforward-plus-fuzzy-PI-feedback (F+FPIF) controller with an inverse longitudinal dynamics model for the lower structure. Simulations across different scenarios show the IT2 FLC upper controller and F+FPIF lower controller outperform PID, LQR, subsection function control, type-1 fuzzy control, and fuzzy-PI baselines in tracking accuracy."},{"id":null,"title":"Meta-Learning for Fast and Privacy-Preserving Source Knowledge Transfer of EEG-Based BCIs","authors":"Siyang Li et al.","year":2022,"venue":"IEEE Comput. Intell. Mag.","doi":"10.1109/MCI.2022.3199622","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":""},{"id":null,"title":"Multi-Source Decentralized Transfer for Privacy-Preserving BCIs","authors":"Wen Zhang et al.","year":2022,"venue":"IEEE Trans. Neural Syst. Rehabil. Eng.","doi":"10.1109/TNSRE.2022.3207494","topic":"Privacy-Preserving BCI","paradigm":["MI","Affect"],"code_url":null,"tldr":"Decentralized privacy-preserving transfer: several source subjects whose data and computations stay local, exposing only their pre-trained models' parameters (gray-box) or predictions (black-box). Proposes offline unsupervised multi-source decentralized transfer (MSDT), which builds one pre-trained model per source subject and transfers to a new subject without accessing any source data. On motor-imagery and affective BCI datasets MSDT improved classification while, unlike the compared approaches, preserving privacy.\n"},{"id":"Xie2022_NetworkIntrusionDetectionDynamicIntuitionisticFuzzy","title":"Network Intrusion Detection Based on Dynamic Intuitionistic Fuzzy Sets","authors":"Jialiang Xie et al.","year":2022,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2021.3117441","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses the uncertainty inherent in network intrusion detection. Proposes a detection algorithm based on dynamic intuitionistic fuzzy sets (IFSs): it preprocesses data and selects features via a chi-square test, constructs dynamic intuitionistic fuzzy patterns from the feature-selected data using time-series processing, and builds a classifier with a newly proposed distance measure for dynamic IFSs. On the KDD 99, NSL-KDD, and large high-dimensional UNSW-NB15 datasets it outperforms state-of-the-art algorithms, with especially significant gains on the large dataset."},{"id":"Fang2022_PhysiologicalComputingOccupationalHealthSafetyConstruction","title":"Physiological computing for occupational health and safety in construction: Review, challenges and implications for future research","authors":"Weili Fang et al.","year":2022,"venue":"Adv. Eng. Informatics","doi":"10.1016/J.AEI.2022.101729","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"A narrative systematic review of physiological computing (AI/machine-learning analysis of physiological signals, including brain-computer interfaces) for occupational health and safety (OHS) in construction. It finds that such systems need to be more accurate, more portable and easier to use, more generalizable across work tasks, and more accepted by users, and recommends future work on high-quality databases, machine-learning-based feature engineering, and context-aware intervention strategies. As a review, it presents no method implementation."},{"id":"Wu2020_TransferLearningEEGBrainComputerInterfaces","title":"Transfer Learning for EEG-Based Brain-Computer Interfaces: A Review of Progress Made Since 2016","authors":"Dongrui Wu et al.","year":2022,"venue":"IEEE Trans. Cogn. Dev. Syst.","doi":"10.1109/TCDS.2020.3007453","topic":"Transfer Learning & Alignment","paradigm":["SSVEP"],"code_url":null,"tldr":"EEG-based BCIs are hampered by noise/artifacts and between- and within-subject non-stationarity, so a per-subject calibration session is usually required, which is time-consuming and user-unfriendly. Transfer learning (TL) can reduce this burden. This paper reviews journal publications on TL in EEG-based BCIs since 2016 across six paradigms/applications (motor imagery, event-related potentials, SSVEP, affective BCIs, regression, and adversarial attacks), grouping approaches into cross-subject/session, cross-device, and cross-task settings. It summarizes the state of the art per paradigm and draws observations and future research directions."},{"id":null,"title":"Transfer learning for motor imagery based brain-computer interfaces: A tutorial","authors":"Dongrui Wu et al.","year":2022,"venue":"Neural Networks","doi":"10.1016/J.NEUNET.2022.06.008","topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":null,"tldr":""},{"id":"Cui2021_CurseDimensionalityTSKFuzzyNeuralNetworks","title":"Curse of Dimensionality for TSK Fuzzy Neural Networks: Explanation and Solutions","authors":"Yuqi Cui et al.","year":2021,"venue":"IJCNN","doi":"10.1109/IJCNN52387.2021.9534265","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/YuqiCui/pytsk","tldr":"TSK fuzzy systems with Gaussian membership functions perform poorly on high-dimensional data. By reformulating defuzzification as an equivalent softmax function, the paper shows this failure stems from softmax saturation, whereby each sample fires only a few rules, antecedent gradients blow up, and the loss landscape becomes rugged. It proposes two saturation-avoiding defuzzification operations, LogTSK and the newly introduced HTSK (which ties the membership-function scaling to the input dimensionality), and validates across datasets of varying dimensionality that they restore stable training without hand-tuning the Gaussian spread for each dimensionality."},{"id":"Shi2021_FCMRDpATSKFuzzyRegressionModel","title":"FCM-RDpA: TSK fuzzy regression model construction using fuzzy C-means clustering, regularization, Droprule, and Powerball Adabelief","authors":"Zhenhua Shi et al.","year":2021,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2021.05.084","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/ZhenhuaShi/FCM-RDpA","tldr":"Addresses optimization of Takagi-Sugeno-Kang (TSK) fuzzy systems for regression, improving the prior MBGD-RDA algorithm. FCM-RDpA replaces grid-partition rule initialization with fuzzy c-means clustering and swaps the AdaBound optimizer for Powerball AdaBelief (combining the Powerball gradient and AdaBelief) to expedite and stabilize training. A variant FCM-RDpAx additionally augments features in both rule antecedents and consequents. Across 22 regression datasets it outperforms MBGD-RDA, with the largest gains at higher feature dimensionality."},{"id":"Zhang2021_OptimizationVarianceExploringGeneralizationPropertiesDNNs","title":"Optimization Variance: Exploring Generalization Properties of DNNs","authors":"Xiao Zhang et al.","year":2021,"venue":"CoRR","doi":null,"topic":"General ML & Optimization","paradigm":[],"code_url":"https://github.com/ZhangXiao96/OptimizationVariance","tldr":"DNNs exhibit epoch-wise double descent, where test error can rise and then fall again as training epochs increase, which complicates early stopping. Extending bias-variance decomposition of the zero-one loss to the epoch-wise setting, the paper finds that the variance alone (without the bias) varies consistently with test error, and proposes a new metric, optimization variance (OV), that measures the diversity of model updates produced by stochastic gradients of different mini-batches drawn in the same iteration. OV is computed from the training set only yet correlates well with the unknown test error, enabling early stopping without any validation set."},{"id":"Liu2021_PoolUnsupervisedActiveLearningRegressionIterative","title":"Pool-based unsupervised active learning for regression using iterative representativeness-diversity maximization (iRDM)","authors":"Ziang Liu et al.","year":2021,"venue":"Pattern Recognit. Lett.","doi":"10.1016/J.PATREC.2020.11.019","topic":"Active Learning","paradigm":[],"code_url":"https://github.com/drwuHUST/iRDM","tldr":"Studies completely unsupervised pool-based active learning for regression (ALR), where samples must be chosen for labeling without any label information or existing model. The proposed iterative representativeness-diversity maximization (iRDM) alternately optimizes the representativeness and the diversity of the selected sample set, and applies to both linear and kernel regression. Experiments on 60 datasets show it outperforms other unsupervised ALR methods and even beats supervised ALR when the labeling budget is small."},{"id":"Yan2021_UnsupervisedLearningFrameworkInterestPointDetection","title":"Unsupervised learning framework for interest point detection and description via properties optimization","authors":"Pei Yan et al.","year":2021,"venue":"Pattern Recognit.","doi":"10.1016/J.PATCOG.2020.107808","topic":"Deep Architectures","paradigm":[],"code_url":"https://github.com/elvintanhust/POP-Interest-Point","tldr":"Proposes Properties Optimization Point (POP), an unsupervised framework for interest-point detection and description that formulates the interest-point set as a latent variable and gives probabilistic objectives for four classical properties (sparsity, repeatability, invariability, discriminability) plus a new 'informativeness' property capturing local information complexity. An efficient approximate Expectation-Maximization algorithm optimizes the resulting non-differentiable objective, and POP is instantiated with fully convolutional networks. It outperforms state-of-the-art methods on several planar and non-planar image-matching benchmarks."},{"id":"Chen2021_ComprehensiveStudyEfficiencyTypeReductionAlgorithms","title":"A Comprehensive Study of the Efficiency of Type-Reduction Algorithms","authors":"Chao Chen et al.","year":2021,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2020.2981002","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Provides a comprehensive efficiency study of type-reduction algorithms for interval type-2 fuzzy systems, motivated by conflicting efficiency claims that depend heavily on implementation platform and language. It proposes two new type-reduction algorithms and, for the first time, compares existing and new approaches on both algorithmic complexity (big-O) and measured runtime across a variety of programming languages, giving recommendations for the preferred algorithm in different platform and application scenarios."},{"id":"Lin2021_DrivingPerformanceForecastingSystemBrainDynamic","title":"A Driving Performance Forecasting System Based on Brain Dynamic State Analysis Using 4-D Convolutional Neural Networks","authors":"Chin-Teng Lin et al.","year":2021,"venue":"IEEE Trans. Cybern.","doi":"10.1109/TCYB.2020.3010805","topic":"Deep Architectures","paradigm":["Drowsy"],"code_url":null,"tldr":"Aims to forecast drivers' cognitive/fatigue state from EEG during a VR lane-keeping task with 37 subjects. A 4-D convolutional neural network jointly encodes frequency, temporal, and 2-D spatial (electrode-location) information of the EEG, outperforming 2-D CNN, 3-D CNN and shallow networks (e.g., 3.82% RMSE and 11.98% correlation-coefficient improvement over 3-D CNN). The learned model highlights significant theta and alpha activations in frontal and posterior cingulate cortices across distinct fatigue levels."},{"id":"Jiang2021_NovelNegativeTransferResistantFuzzyClustering","title":"A Novel Negative-Transfer-Resistant Fuzzy Clustering Model With a Shared Cross-Domain Transfer Latent Space and its Application to Brain CT Image Segmentation","authors":"Yizhang Jiang et al.","year":2021,"venue":"IEEE ACM Trans. Comput. Biol. Bioinform.","doi":"10.1109/TCBB.2019.2963873","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses clustering-based medical image (brain CT) segmentation when labeled target data is scarce and transfer learning risks negative transfer. The proposed NTR-FC-SCT integrates a negative-transfer-resistant mechanism (weighting the transferred knowledge) and maximum mean discrepancy (MMD) into fuzzy c-means clustering built on a shared cross-domain transfer latent space. It outperforms several traditional non-transfer and related transfer clustering algorithms on brain CT segmentation."},{"id":"Wu2021_AdversarialAttacksDefensesPhysiologicalComputingSystematic","title":"Adversarial Attacks and Defenses in Physiological Computing: A Systematic Review","authors":"Dongrui Wu et al.","year":2021,"venue":"National Science Open","doi":"10.1360/NSO/20220023","topic":"Robustness & Security","paradigm":["Affect"],"code_url":null,"tldr":"A systematic review of adversarial attacks and defenses in physiological computing, a field spanning brain-computer interfaces, affective computing, adaptive automation, health informatics, and physiological-signal biometrics. It surveys the main application areas, categorizes the types of adversarial attacks and how they apply to physiological signals, and reviews corresponding defense strategies, arguing the vulnerability of these safety-critical systems has been under-studied. The contribution is the first comprehensive review consolidating this literature to motivate security/defense research in the field."},{"id":"Jiang2021_AgFlowFastModelSelectionPenalizedPCA","title":"AgFlow: fast model selection of penalized PCA via implicit regularization effects of gradient flow","authors":"Haiyan Jiang et al.","year":2021,"venue":"Mach. Learn.","doi":"10.1007/S10994-021-06025-3","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"Tackles the expensive model selection of l2-penalized PCA, which normally requires repeated matrix inversions along a Ridge solution path in the high-dimension-low-sample-size setting. The proposed AgFlow (approximated gradient flow) exploits the implicit regularization effect of (stochastic) gradient flow to recover the complete solution path of l2-penalized PCA across varying regularization strengths at much lower computational complexity. On real-world datasets it outperforms Oja's algorithm, power iteration, VR-PCA and vanilla Ridge estimators in computation cost."},{"id":"Tang2021_AdaptiveFuzzyInferenceApproachColorImage","title":"An adaptive fuzzy inference approach for color image steganography","authors":"Lili Tang et al.","year":2021,"venue":"Soft Comput.","doi":"10.1007/S00500-021-05825-Y","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Presents an adaptive fuzzy inference approach for color-image steganography that accounts for image-complexity factors: pixel similarity, pixel brightness, and color sensitivity. A fuzzy inference system classifies cover-image features to decide the embedding payload per sub-region, then least-significant-bit substitution hides data adaptively according to human-eye sensitivity to the R/G/B components, while a chaotic map plus random-sequence scrambling secures the message. It reports better MSE, PSNR, SSIM and payload than state-of-the-art methods, with robustness verified via RS steganalysis and pixel-difference-histogram analysis."},{"id":"Yang2021_DBANAdversarialNetworkMultiScaleFeatures","title":"DBAN: Adversarial Network With Multi-Scale Features for Cardiac MRI Segmentation","authors":"Xinyu Yang et al.","year":2021,"venue":"IEEE J. Biomed. Health Informatics","doi":"10.1109/JBHI.2020.3028463","topic":"Robustness & Security","paradigm":[],"code_url":null,"tldr":"Proposes DBAN (dilated block adversarial network) for automatic left-ventricle, right-ventricle and myocardium segmentation in short-axis cardiac MRI. A segmentor built from dilated blocks (DB) captures and aggregates multi-scale features to produce segmentation probability maps, while an adversarial discriminator distinguishes predictions from ground truth at the pixel level and its confidence maps guide the segmentor to refine outputs. DBAN attains state-of-the-art performance on the ACDC dataset, with derived cardiac-function indices close to those of clinical experts."},{"id":null,"title":"EEG-Based Brain-Computer Interfaces (BCIs): A Survey of Recent Studies on Signal Sensing Technologies and Computational Intelligence Approaches and Their Applications","authors":"Xiaotong Gu et al.","year":2021,"venue":"IEEE ACM Trans. Comput. Biol. Bioinform.","doi":"10.1109/TCBB.2021.3052811","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":"Jiang2021_EEGDriverDrowsinessEstimationOnlineMulti","title":"EEG-Based Driver Drowsiness Estimation Using an Online Multi-View and Transfer TSK Fuzzy System","authors":"Yizhang Jiang et al.","year":2021,"venue":"IEEE Trans. Intell. Transp. Syst.","doi":"10.1109/TITS.2020.2973673","topic":"Transfer Learning & Alignment","paradigm":["Drowsy"],"code_url":null,"tldr":"Targets EEG-based driver drowsiness estimation for a new subject with few calibration samples, noting that existing transfer-learning models are typically offline, single-view, and non-transparent. Using a first-order TSK fuzzy system as the base regressor, the method injects multi-view feature representations into a transfer-learning framework and enforces consistency across views, yielding an online multi-view and transfer TSK fuzzy system. On a driving dataset it achieves lower drowsiness-estimation error and higher interpretability than benchmark models while meeting online (streaming) requirements."},{"id":"Ming2021_EEGDrowsinessEstimationDrivingSafetyDeep","title":"EEG-Based Drowsiness Estimation for Driving Safety Using Deep Q-Learning","authors":"Yurui Ming et al.","year":2021,"venue":"IEEE Trans. Emerg. Top. Comput. Intell.","doi":"10.1109/TETCI.2020.2997031","topic":"Data Augmentation & Generation","paradigm":["Drowsy"],"code_url":null,"tldr":"Frames EEG-based driver drowsiness estimation as a reinforcement-learning problem, analyzing an EEG dataset from a simulated endurance driving test. The authors adapt driving-test terminology to a Q-learning formulation and tailor a deep Q-network (DQN) to the characteristics of EEG data so that its generated actions indirectly estimate drowsiness. Presented as the first use of deep reinforcement learning for this BCI scenario, it outperforms a supervised-learning counterpart while tracking mind-state variations."},{"id":"Quan2021_ManifoldDiscriminativeTransferLearningUnsupervisedDomain","title":"Manifold Discriminative Transfer Learning for Unsupervised Domain Adaptation","authors":"Xueliang Quan et al.","year":2021,"venue":"ICONIP","doi":"10.1007/978-3-030-92270-2_28","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":"Proposes Manifold Discriminative Transfer Learning (MDTL) for traditional (non-deep) unsupervised domain adaptation. It first reconstructs source and target data via manifold subspace learning to reduce domain shift, then jointly performs structural risk minimization, discriminative class-level alignment (minimizing intra-class and maximizing inter-class distribution discrepancy), and manifold regularization to preserve data geometry. MDTL admits a closed-form, low-cost solution and outperforms several state-of-the-art traditional domain-adaptation methods."},{"id":"Jiang2021_MultiTaskActiveLearningSimultaneousEmotion","title":"Multi-Task Active Learning for Simultaneous Emotion Classification and Regression","authors":"Xue Jiang et al.","year":2021,"venue":"SMC","doi":"10.1109/SMC52423.2021.9659052","topic":"Active Learning","paradigm":["Affect"],"code_url":null,"tldr":"Training emotion classification (categorical) and emotion regression (continuous valence/arousal/dominance) models both require many costly multi-assessor labels. The paper proposes a multi-task active learning (MTAL) framework that queries the most informative samples so that a classification model and multiple regression models can be trained simultaneously from the same labeled set, and is flexible enough to wrap any existing single-task active-learning criterion. On the IEMOCAP corpus, MTAL outperformed random selection and several state-of-the-art single-task active learning methods, yielding better classification and regression models at the same labeling budget."},{"id":null,"title":"Personalized Human Activity Recognition Based on Integrated Wearable Sensor and Transfer Learning","authors":"Zhongzheng Fu et al.","year":2021,"venue":"Sensors","doi":"10.3390/S21030885","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":""},{"id":"Zhang2021_RethinkConnectionsAmongGeneralizationMemorizationSpectral","title":"Rethink the Connections among Generalization, Memorization, and the Spectral Bias of DNNs","authors":"Xiao Zhang et al.","year":2021,"venue":"IJCAI","doi":"10.24963/IJCAI.2021/467","topic":"Deep Architectures","paradigm":[],"code_url":null,"tldr":"Re-examines the relationship among generalization, memorization, and the spectral bias of deep neural networks, challenging the assumed monotonicity of the learning bias (that DNNs learn simple low-to-high-frequency patterns). Under a deep double-descent setup, the authors show the high-frequency components of DNNs actually diminish in the late training stage, coinciding with the second descent of test error, while random-label examples are still being memorized. They further show the DNN frequency spectrum, computed from the training set alone, can indicate the onset of the second descent of test error."},{"id":"Zhang2019_TransferabilityVersusDiscriminabilityJointProbabilityDistribution","title":"Discriminative Joint Probability Maximum Mean Discrepancy (DJP-MMD) for Domain Adaptation","authors":"Wen Zhang et al.","year":2020,"venue":"IJCNN","doi":"10.1109/IJCNN48605.2020.9207365","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":"https://github.com/chamwen/JPDA","tldr":"Existing domain-adaptation methods rely on a joint MMD (weighted sum of marginal and conditional distribution discrepancies) that only maximizes transferability and ignores class discriminability. The paper proposes discriminative joint probability MMD (DJP-MMD) to replace the joint MMD. It measures the joint probability distribution discrepancy directly, giving a simpler and more accurate theoretical basis while simultaneously increasing cross-domain transferability and between-class discriminability, and embeds it in a joint probability domain adaptation (JPDA) framework. On six image-classification datasets DJP-MMD outperforms traditional MMD-based domain adaptation."},{"id":"Wu2020_MultitaskingGeneticAlgorithmMTGAFuzzySystem","title":"Multitasking Genetic Algorithm (MTGA) for Fuzzy System Optimization","authors":"Dongrui Wu et al.","year":2020,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2020.2968863","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/drwuHUST/MTGA","tldr":"This paper proposes the multitasking genetic algorithm (MTGA), an evolutionary multitasking / multifactorial optimization method that solves multiple distinct optimization tasks simultaneously by estimating and exploiting the bias between tasks. Across nine benchmarks and against eight state-of-the-art single-task and multitask baselines, MTGA achieved the best average performance while incurring lower computational cost than six of them. It further introduces an MTGA-based simultaneous optimization strategy for fuzzy system design, jointly optimizing a type-1 and an interval type-2 fuzzy logic controller for coupled-tank water-level control."},{"id":"Cui2020_OptimizeTSKFuzzySystemsClassificationProblems","title":"Optimize TSK Fuzzy Systems for Classification Problems: Minibatch Gradient Descent With Uniform Regularization and Batch Normalization","authors":"Yuqi Cui et al.","year":2020,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2020.2967282","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/YuqiCui/TSK_BN_UR","tldr":"TSK fuzzy classifiers are flexible and interpretable but hard to optimize on large and/or high-dimensional datasets. The paper proposes an MBGD-based training algorithm (TSK-MBGD-UR-BN) integrating two novel techniques: uniform regularization (UR), which forces the rules to contribute similarly on average to improve generalization, and batch normalization (BN) adapted to the rule-consequent computation to speed convergence and improve generalization. On 12 UCI datasets of varying size and dimensionality, UR and BN each help individually and combine for further gains, enabling training of TSK classifiers even on big, high-dimensional data."},{"id":"Wu2020_OptimizeTSKFuzzySystemsRegressionProblems","title":"Optimize TSK Fuzzy Systems for Regression Problems: Minibatch Gradient Descent With Regularization, DropRule, and AdaBound (MBGD-RDA)","authors":"Dongrui Wu et al.","year":2020,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2019.2958559","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/drwuHUST/MBGD_RDA","tldr":"TSK fuzzy systems lacked an efficient, effective training algorithm that ensures good generalization and scales to big data. The paper extends three neural-network optimization techniques (mini-batch gradient descent, regularization, and AdaBound) to TSK fuzzy systems and adds three fuzzy-specific techniques (DropRule, DropMF, DropMembership). The combined MBGD-RDA algorithm achieves fast convergence and superior test generalization, and works on datasets of any size, being especially useful for big data where no efficient trainers previously existed."},{"id":"Wu2020_PatchLearning","title":"Patch Learning","authors":"Dongrui Wu et al.","year":2020,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2019.2930022","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/drwuHUST/Patch-Learning","tldr":"The paper introduces patch learning (PL), a new strategy for improving an under-performing machine learning model. PL (i) trains an initial global model on all data, (ii) identifies the input-space patches contributing most to the learning error and trains a dedicated local patch model for each, and (iii) retrains the global model on data falling outside all patches. At inference, the corresponding patch model is used if the input lies in a patch, otherwise the global model. Demonstrated with fuzzy systems on five regression tasks (1-D/2-D/3-D curve fitting, nonlinear system identification, chaotic time-series prediction), PL improved accuracy and, per the authors, opens a new line of research."},{"id":"Cui2020_SupervisedEnhancedSoftSubspaceClusteringSESSC","title":"Supervised Enhanced Soft Subspace Clustering (SESSC) for TSK Fuzzy Classifiers","authors":"Yuqi Cui et al.","year":2020,"venue":"CoRR","doi":null,"topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/YuqiCui/SESSC","tldr":"Fuzzy c-means-style clustering used to initialize TSK fuzzy-classifier antecedents is typically unsupervised, discarding valuable label information. The paper proposes supervised enhanced soft subspace clustering (SESSC), which jointly optimizes within-cluster compactness, between-cluster separation, and label information, and can serve as a standalone classifier or initialize a TSK fuzzy classifier. On nine UCI datasets, SESSC-based initialization outperforms other clustering approaches, especially when the number of rules is small."},{"id":"Zhang2020_TinyNoiseCanMakeEEGBrain","title":"Tiny Noise Can Make an EEG-Based Brain-Computer Interface Speller Output Anything","authors":"Xiao Zhang et al.","year":2020,"venue":"CoRR","doi":null,"topic":"Privacy-Preserving BCI","paradigm":["SSVEP"],"code_url":"https://github.com/ZhangXiao96/Speller-Attacks","tldr":"Prior EEG-based BCI speller research focused on speed and reliability while largely ignoring security. This paper shows for the first time that P300 and SSVEP BCI spellers are highly vulnerable to adversarial perturbations - tiny, essentially imperceptible noise added to the EEG that can mislead the speller into outputting whatever the attacker wants. It demonstrates severe vulnerability whose consequences range from user frustration to clinical misdiagnosis, urging attention to BCI speller security."},{"id":"Wu2020_TransferLearningBrainComputerInterfacesComplete","title":"Transfer Learning for Brain-Computer Interfaces: A Complete Pipeline","authors":"Dongrui Wu et al.","year":2020,"venue":"CoRR","doi":null,"topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":"https://github.com/drwuHUST/TLBCI","tldr":"Prior transfer learning for motor-imagery (MI) BCIs addressed only one or two blocks of the decoding pipeline. This paper argues TL should be applied to all three components (spatial filtering, feature engineering, and classification) of MI-based BCIs, and adds a data-alignment component (Euclidean alignment) before spatial filtering to make cross-subject data more consistent and thus facilitate downstream TL. Offline calibration experiments on two MI datasets confirm that integrating data alignment with sophisticated TL significantly improves classification and greatly reduces calibration effort."},{"id":"He2018_TransferLearningBrainComputerInterfacesEuclidean","title":"Transfer Learning for Brain-Computer Interfaces: A Euclidean Space Data Alignment Approach","authors":"He He et al.","year":2020,"venue":"IEEE Trans. Biomed. Eng.","doi":"10.1109/TBME.2019.2913914","topic":"Transfer Learning & Alignment","paradigm":["P300"],"code_url":"https://github.com/hehe03/EA","tldr":"Addresses the individual-differences problem in EEG-based BCIs, where a new subject normally needs subject-specific calibration data. The paper proposes Euclidean Alignment (EA), an unsupervised, low-cost preprocessing step that aligns each subject's EEG trials directly in Euclidean space (whitening trials by the subject's mean covariance matrix) so different subjects' distributions become more similar, after which any standard feature extraction and classifier can be applied. On motor imagery and ERP classification, in both offline and simulated-online settings, EA outperforms a state-of-the-art Riemannian alignment method and no-alignment baselines."},{"id":"Wu2020_ActiveStackingHeartRateEstimation","title":"Active Stacking for Heart Rate Estimation","authors":"Dongrui Wu et al.","year":2020,"venue":"IJCNN","doi":"10.1109/IJCNN48605.2020.9207599","topic":"Active Learning","paradigm":[],"code_url":null,"tldr":"No single algorithm estimates heart rate well from ECG across all subjects because of large individual differences and varying signal quality, and any algorithm can break down on some subjects. The paper uses stacking ensemble regression to aggregate multiple base estimators and applies active learning to optimally select a few trials from each new subject to label, proposing four active-stacking approaches. They significantly outperform three unsupervised ensemble approaches and random-selection supervised stacking, needing only three or four labeled trials per subject to reach RMSE below 3 beats/min. It is presented as the first work on active stacking."},{"id":"Kebria2020_AdaptiveType2FuzzyNeuralNetwork","title":"Adaptive Type-2 Fuzzy Neural-Network Control for Teleoperation Systems With Delay and Uncertainties","authors":"Parham Mohsenzadeh Kebria et al.","year":2020,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2019.2941173","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Teleoperation systems suffer from time-varying communication delays and uncertainties in operator, robot, and remote-environment dynamics. The paper proposes an adaptive interval type-2 fuzzy neural-network control scheme in which the type-2 fuzzy models are built from experimental data on a local network and closed-loop stability is proven via a Lyapunov-Krasovskii analysis. Evaluated on a real intercontinental teleoperation link (Australia-Scotland) with a different, unforeseen slave robot, the proposed controller outperformed traditional techniques."},{"id":"Huang2020_AutomaticAnalogInstrumentReadingSystemComputer","title":"An Automatic Analog Instrument Reading System Using Computer Vision and Inspection Robot","authors":"Jian Huang et al.","year":2020,"venue":"IEEE Trans. Instrum. Meas.","doi":"10.1109/TIM.2020.2967956","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":"Manual inspection of analog pointer instruments is inefficient, while existing computer-vision reading systems rely on many costly fixed cameras or incur high computational cost aligning pan-tilt-zoom (PTZ) cameras, and are usually instrument-type-dependent. The paper builds an inspection-robot system with a PTZ camera, a fast visual-servo camera-alignment algorithm using an improved YOLOv3 to locate the instrument and iteratively align the camera, and a monocular-vision pointer-reconstruction algorithm to read the value. Experiments show the system is fast and reliable in alignment and effective at reading multiple types of round analog instruments during robot-based inspection."},{"id":"Ming2020_EEGDataAnalysisStackedDifferentiableNeural","title":"EEG data analysis with stacked differentiable neural computers","authors":"Yurui Ming et al.","year":2020,"venue":"Neural Comput. Appl.","doi":"10.1007/S00521-018-3879-1","topic":"Data Augmentation & Generation","paradigm":[],"code_url":null,"tldr":"This paper extends the differentiable neural computer (DNC), a memory-augmented network, to EEG data analysis by stacking enhanced DNC modules to increase representational and learning capacity. It replaces the DNC's LSTM controller with a recurrent convolutional controller and modifies the memory-access structures to handle EEG topographic (spatial) data. On an open-source EEG dataset the stacked DNC achieved the highest average accuracy reported by the authors, and further reduced mean error on a proprietary EEG dataset after fine-tuning."},{"id":"Meng2020_EEGBrainComputerInterfacesVulnerableBackdoor","title":"EEG-Based Brain-Computer Interfaces Are Vulnerable to Backdoor Attacks","authors":"Lubin Meng et al.","year":2020,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2023.3273214","topic":"Robustness & Security","paradigm":[],"code_url":null,"tldr":"Exposes a security vulnerability of EEG-based BCIs to backdoor (poisoning) attacks. It proposes using a narrow period pulse (NPP) as the backdoor key injected into a small number of training samples. Crucially, unlike prior EEG attacks, the key does not need to be synchronized with the EEG trials, making the attack very easy to implement in practice. Experiments demonstrate that any test trial carrying the backdoor key is reliably classified into the attacker-specified target class, showing the attack is effective and robust and raising a critical security concern for EEG-based BCIs."},{"id":"Zhang2020_EmpiricalStudiesPropertiesLinearRegionsDeep","title":"Empirical Studies on the Properties of Linear Regions in Deep Neural Networks","authors":"Xiao Zhang et al.","year":2020,"venue":"ICLR","doi":null,"topic":"Deep Architectures","paradigm":[],"code_url":null,"tldr":"Expressivity of piecewise-linear DNNs is usually characterized only by counting linear regions, ignoring their finer local structure. This paper empirically studies local properties of the linear regions - their inspheres, the orientations of the bounding hyperplanes, the decision boundaries, and the relevance of surrounding regions. It observes that different optimization techniques yield completely different linear regions even at similar classification accuracy, offering a more meticulous lens on DNN behavior to inspire new optimization designs (ICLR 2020)."},{"id":"Wang2020_HandGestureRecognitionMultiClassificationAdaptive","title":"Hand Gesture Recognition Based on Multi-Classification Adaptive Neuro-Fuzzy Inference System and pMMG","authors":"Lei Wang et al.","year":2020,"venue":"ICARM","doi":"10.1109/ICARM49381.2020.9195286","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The paper targets hand-gesture recognition from pneumatic muscle-pressure (pMMG) signals, avoiding drawbacks of surface EMG. It proposes a multi-classification adaptive neuro-fuzzy inference system that combines a neural network with a TSK fuzzy system, trained with mini-batch gradient descent, L2 regularization, DropRule, and AdaBound, to recognize six common gestures. The multiple-classifier system reaches 95.12% average accuracy, exceeding CNN, LDA, and other multiple-classifier systems using MMG inputs."},{"id":"Liu2020_IntegratingInformativenessRepresentativenessDiversityPoolSequential","title":"Integrating Informativeness, Representativeness and Diversity in Pool-Based Sequential Active Learning for Regression","authors":"Ziang Liu et al.","year":2020,"venue":"IJCNN","doi":"10.1109/IJCNN48605.2020.9206845","topic":"Active Learning","paradigm":[],"code_url":null,"tldr":"Pool-based sequential active learning for regression (ALR) rarely integrates all three essential sample-selection criteria - informativeness, representativeness, and diversity - simultaneously. The paper proposes three new ALR approaches with different strategies for combining these criteria (built on greedy sampling for ridge regression). Extensive experiments on 12 datasets across various domains demonstrate their effectiveness over approaches that consider fewer criteria."},{"id":"Wu2020_MBGDRDATrainingRulePruningConcise","title":"MBGD-RDA Training and Rule Pruning for Concise TSK Fuzzy Regression Models","authors":"Dongrui Wu","year":2020,"venue":"CoRR","doi":null,"topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The original MBGD-RDA trainer for TSK fuzzy regression has limitations: it cannot let the user directly specify the number of rules and supports only Gaussian membership functions. This paper proposes two MBGD-RDA variants that remove these limitations (user-specified rule count and non-Gaussian, e.g., trapezoidal, MFs) plus a similarity-based rule-pruning algorithm that reduces the rule count with little performance loss. The variants outperform the original MBGD-RDA and classical ANFIS at the same number of rules, and pruned rules are generally better than training that many rules from scratch, especially with Gaussian MFs."},{"id":"Song2020_MDixonSyntheticCTGenerationTransferPatch","title":"mDixon-based synthetic CT generation via transfer and patch learning","authors":"Xin Song et al.","year":2020,"venue":"Pattern Recognit. Lett.","doi":"10.1016/J.PATREC.2020.06.017","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Generating synthetic CT from MR for PET attenuation correction is difficult in the abdomen/pelvis because MR cannot easily distinguish bone from air, and prior methods rely on specialized long-acquisition MR sequences. The paper proposes SCG-TPL, a voxel-oriented synthetic-CT method from ordinary mDixon MR that (i) extracts seven-dimensional texture features via weighted convolutional sums, (ii) uses knowledge-leveraged transfer fuzzy c-means (KL-TFCM) as a global model to cluster tissues and identify patches, and (iii) trains local semi-supervised LapSVM patch models to refine tissue classification. This transfer-plus-patch-learning scheme yields accurate abdominal synthetic CT using only easily acquired mDixon MR."},{"id":null,"title":"On the Functional Equivalence of TSK Fuzzy Systems to Neural Networks, Mixture of Experts, CART, and Stacking Ensemble Regression","authors":"Dongrui Wu et al.","year":2020,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2019.2941697","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":""},{"id":"Yue2020_ProbabilisticLinguisticMultiCriteriaDecisionMaking","title":"Probabilistic linguistic multi-criteria decision-making based on double information under imperfect conditions","authors":"Na Yue et al.","year":2020,"venue":"Fuzzy Optim. Decis. Mak.","doi":"10.1007/S10700-020-09325-W","topic":"General ML & Optimization","paradigm":["Affect"],"code_url":null,"tldr":"This paper addresses probabilistic linguistic multi-criteria decision-making (MCDM) under imperfect conditions, where alternative assessments are incomplete and criteria weights are known only within ranges. It introduces equivalent vector expressions and transformation functions for probabilistic linguistic term sets, builds four projection-based normalization models for different types of uncertain problems, and proposes a new deviation-degree formula together with a probabilistic-linguistic two-step method to determine criteria weights and rank alternatives. The models and method are illustrated on a case study assessing data-hiding techniques."},{"id":"Wang2020_SetMembershipFilteringIncompleteObservations","title":"Set-Membership filtering with incomplete observations","authors":"Yuan Wang et al.","year":2020,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2019.12.087","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"This paper studies set-membership estimation for discrete time-varying systems with incomplete observations (e.g., random measurement dropouts), a setting where conventional set-membership filters cannot guarantee stability. It develops a recursive set-membership filter that computes a state-estimate ellipsoid guaranteed to contain the true state, and derives, via interval analysis under bounded-noise assumptions, a tight bound on the estimation error linked to the data-dropout rate. It proves the filter is asymptotically stable when the dropout rate stays below a derived maximum, and demonstrates the theory on a two-state example."},{"id":"Shi2020_SupervisedDiscriminativeSparsePCAAdaptiveNeighbors","title":"Supervised Discriminative Sparse PCA with Adaptive Neighbors for Dimensionality Reduction","authors":"Zhenhua Shi et al.","year":2020,"venue":"IJCNN","doi":"10.1109/IJCNN48605.2020.9206927","topic":"Robustness & Security","paradigm":[],"code_url":null,"tldr":"Most linear dimensionality-reduction methods preserve either global structure (e.g., PCA, but outlier-sensitive) or local structure (e.g., locality preserving projections, but unsupervised with a fixed graph), not both. The paper proposes SDSPCAAN, which integrates neighborhood-free supervised discriminative sparse PCA with projected clustering with adaptive neighbors, thereby exploiting global and local data structure together with label information. Classification experiments on nine high-dimensional datasets validate its effectiveness and robustness."},{"id":"Cheng2020_WassersteinDistanceDeepAdversarialTransferLearning","title":"Wasserstein distance based deep adversarial transfer learning for intelligent fault diagnosis with unlabeled or insufficient labeled data","authors":"Cheng Cheng et al.","year":2020,"venue":"Neurocomputing","doi":"10.1016/J.NEUCOM.2020.05.040","topic":"Robustness & Security","paradigm":[],"code_url":null,"tldr":"CNN-based intelligent fault diagnosis degrades when source and target machines run under different operating conditions (distribution shift) and target labels are scarce or unavailable. The paper proposes WD-DTL (Wasserstein Distance-based Deep Transfer Learning), in which a CNN feature extractor is trained adversarially to minimize the Wasserstein distance between source and target feature distributions, supporting both supervised and unsupervised domain adaptation. Across 16 transfer tasks WD-DTL achieved the highest diagnostic accuracy compared with Maximum Mean Discrepancy and plain-CNN baselines."},{"id":"Wu2019_ActiveLearningRegressionGreedySampling","title":"Active learning for regression using greedy sampling","authors":"Dongrui Wu et al.","year":2019,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2018.09.060","topic":"Robustness & Security","paradigm":["Drowsy"],"code_url":"https://github.com/drwuHUST/iGS","tldr":"Addresses active learning for regression (ALR), which reduces labeling cost by selecting the most beneficial unlabeled samples to label instead of random selection. Proposes two greedy-sampling approaches: GSy, which selects samples to increase diversity in the output space, and iGS, which selects samples to increase diversity in both the input and output spaces. Extensive experiments on 10+ UCI/CMU StatLib datasets and on 15 subjects for EEG-based driver drowsiness estimation verify their effectiveness and robustness over random sampling and prior ALR methods."},{"id":"He2019_DifferentSetDomainAdaptationBrainComputer","title":"Different Set Domain Adaptation for Brain-Computer Interfaces: A Label Alignment Approach","authors":"He He et al.","year":2019,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2020.2980299","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":"https://github.com/hehe91/LA","tldr":"Most domain adaptation for BCIs requires the source and target domains to share the same label space, so auxiliary data with a different set of classes cannot be used. This paper addresses different-set domain adaptation and proposes a label alignment (LA) approach, using Riemannian-geometry alignment to map the source label space onto the target label space. LA needs as few as one labeled target sample per class, acts as a preprocessing step before arbitrary feature extractors/classifiers, and can be combined with other domain-adaptation methods. Experiments on two motor-imagery datasets demonstrate its effectiveness."},{"id":"Zhang2019_ManifoldEmbeddedKnowledgeTransferBrainComputer","title":"Manifold Embedded Knowledge Transfer for Brain-Computer Interfaces","authors":"Wen Zhang et al.","year":2019,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2020.2985996","topic":"Transfer Learning & Alignment","paradigm":["P300"],"code_url":"https://github.com/chamwen/MEKT","tldr":"Addresses offline unsupervised cross-subject EEG classification, where labeled trials exist for source subjects but only unlabeled trials for the target. Proposes Manifold Embedded Knowledge Transfer (MEKT), which aligns the EEG trial covariance matrices on the Riemannian manifold, extracts features in the tangent space, then performs domain adaptation by minimizing the joint (marginal and conditional) distribution shift between source and target while preserving their geometric structures. A domain transferability estimation (DTE) selects the most beneficial source subjects. On four EEG datasets across two paradigms (MI and ERP), MEKT outperformed several state-of-the-art transfer-learning methods, and DTE cut more than half the computational cost with little accuracy loss."},{"id":"Cui2019_OptimizeTSKFuzzySystemsBigData","title":"Optimize TSK Fuzzy Systems for Big Data Classification Problems: Bag of Tricks","authors":"Yuqi Cui et al.","year":2019,"venue":"CoRR","doi":null,"topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/YuqiCui/TSK_BN_UR","tldr":"Improves training of TSK fuzzy classifiers on large and/or high-dimensional data, where evolutionary/GD/ANFIS approaches struggle. Proposes a mini-batch gradient descent training algorithm integrating two techniques: uniform regularization (UR), which forces the rules to have similar average contributions to the output to improve generalization, and batch normalization (BN) extended from deep neural networks to TSK classifiers to expedite convergence. Experiments on 12 UCI datasets show UR and BN are each effective and their integration further improves classification performance."},{"id":"Agarwal2019_ProtectingPrivacyUsersBrainComputerInterface","title":"Protecting Privacy of Users in Brain-Computer Interface Applications","authors":"Anisha Agarwal et al.","year":2019,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2019.2926965","topic":"Privacy-Preserving BCI","paradigm":["Drowsy"],"code_url":"https://bitbucket.org/uwtppml","tldr":"Enables machine learning over EEG data from many users while cryptographically protecting each individual's raw signals, motivated by how much sensitive information (PINs, passwords, etc.) leaks from unprotected EEG. Proposes commodity-based Secure Multiparty Computation (SMC) protocols using additive secret sharing to perform privacy-preserving linear regression over multi-user EEG, implemented in the authors' Lynx SMC library. Reported as the first application of commodity-based SMC to EEG and the largest documented secret-sharing SMC experiment (15 players), demonstrated on driver-drowsiness estimation at reasonable computational cost."},{"id":"Liu2019_UniversalAdversarialPerturbationsCNNClassifiersEEG","title":"Universal Adversarial Perturbations for CNN Classifiers in EEG-Based BCIs","authors":"Zihan Liu et al.","year":2019,"venue":"Journal of Neural Engineering","doi":"10.1088/1741-2552/AC0F4C","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":"https://github.com/ZihanLiu95/UAP_EEG","tldr":"CNN classifiers for EEG-based BCIs are shown to be vulnerable to universal adversarial perturbations (UAPs) - small, example-independent perturbations that degrade performance when added to any input. The paper proposes a total loss minimization (TLM) approach to craft such UAPs for EEG trials, supporting both target and non-target attacks. TLM effectively fools three popular CNN classifiers, the UAPs transfer across models, and this is the first study of UAPs in EEG-based BCIs, exposing a real-time security threat."},{"id":"Wu2019_ConstrainedRepresentationTheoremWellShapedInterval","title":"A Constrained Representation Theorem for Well-Shaped Interval Type-2 Fuzzy Sets, and the Corresponding Constrained Uncertainty Measures","authors":"Dongrui Wu et al.","year":2019,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2018.2874018","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses a mismatch in interval type-2 (IT2) fuzzy set theory: the Mendel-John representation theorem uses possibly nonconvex/subnormal embedded type-1 (T1) FSs, whereas most applications (computing with words) use only convex, normal T1 FSs. It proposes a constrained representation theorem (CRT) for well-shaped IT2 FSs built only from convex and normal embedded T1 FSs, shows that IT2 FSs produced by three word-encoding approaches and four computing-with-words engines (LWAs, OLWAs, LWPMs, perceptual reasoning) are all well-shaped, and derives five constrained uncertainty measures (centroid, cardinality, fuzziness, variance, skewness). These results are useful for computing with words, IT2 FLS design, and similarity computation."},{"id":"Jiang2019_ActiveLearningBlackBoxAdversarialAttacks","title":"Active Learning for Black-Box Adversarial Attacks in EEG-Based Brain-Computer Interfaces","authors":"Xue Jiang et al.","year":2019,"venue":"SSCI","doi":"10.1109/SSCI44817.2019.9002719","topic":"Robustness & Security","paradigm":[],"code_url":null,"tldr":"Improves the query efficiency of transferability-based black-box adversarial attacks on EEG CNN classifiers, where an attacker trains a substitute model from limited queries to the target. Introduces a query-synthesis active-learning strategy that uses binary search over opposite-class instance pairs to synthesize informative queries near the target's decision boundary in the input space, rather than stepping along gradients. Experiments on three CNNs (EEGNet, DeepCNN, ShallowCNN) and three EEG datasets show higher attack success rate for the same query budget. It is claimed as the first work integrating active learning with adversarial attacks for EEG BCIs."},{"id":"Wang2019_AlzheimerAposSDiseaseBrainNetwork","title":"Alzheimer's Disease Brain Network Classification Using Improved Transfer Feature Learning with Joint Distribution Adaptation","authors":"Binglin Wang et al.","year":2019,"venue":"EMBC","doi":"10.1109/EMBC.2019.8856726","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":"Targets Alzheimer's disease classification from functional-MRI brain networks, which is hard because case collection is difficult and fMRI may come from different populations/machines, yielding small heterogeneous datasets. Proposes an improved transfer-feature-learning approach: joint distribution adaptation (JDA) projects source and target samples into a shared feature space, and a classifier is then trained by minimizing a weighted loss over both domains that assigns larger weights to target-domain samples. With the help of the auxiliary dataset, target-dataset classification accuracy is greatly improved."},{"id":"Guo2019_CanonicalCorrelationAnalysisCCAMultiView","title":"Canonical Correlation Analysis (CCA) Based Multi-View Learning: An Overview","authors":"Chenfeng Guo et al.","year":2019,"venue":"CoRR","doi":null,"topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":"A survey/overview of Canonical Correlation Analysis (CCA) based multi-view learning, filling the gap that no such overview existed. It reviews representative extensions that overcome traditional CCA's three limitations (only two views, linear-only correlation, and unsupervised label-wasting), covering nonlinear (kernel and deep CCA), supervised, and generalized/multi-view variants, and organizes them within the co-training / multi-kernel / subspace-learning taxonomy of multi-view learning. Describes typical applications in pattern recognition, multi-modal retrieval and classification, and multi-view embedding."},{"id":"He2019_ChannelTrialsSelectionReducingCovariateShift","title":"Channel and Trials Selection for Reducing Covariate Shift in EEG-based Brain-Computer Interfaces","authors":"He He et al.","year":2019,"venue":"SMC","doi":"10.1109/SMC.2019.8914414","topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":null,"tldr":"Addresses calibration-free cross-subject EEG motor-imagery classification by reducing covariate shift for a state-of-the-art Riemannian Alignment (RA) transfer-learning baseline. Proposes two enhancements: Trials Selection (TS), which resamples the auxiliary subjects' trials to be more consistent with the target subject's, and Channel Selection (CS), which uses CSP to reduce channel count so the Riemannian-space covariance computations become more accurate and efficient. On two MI datasets, both TS and CS improved RA's accuracy without any labeled trials from the new subject."},{"id":"Cui2019_EEGDriverDrowsinessEstimationFeatureWeighted","title":"EEG-Based Driver Drowsiness Estimation Using Feature Weighted Episodic Training","authors":"Yuqi Cui et al.","year":2019,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2019.2945794","topic":"Transfer Learning & Alignment","paradigm":["Drowsy"],"code_url":null,"tldr":"Aims to completely eliminate subject calibration for EEG-based driver-drowsiness estimation despite strong individual differences. Proposes Feature Weighted Episodic Training (FWET), integrating feature weighting to learn the importance of different features with episodic training for domain generalization, requiring no labeled or unlabeled calibration data from the new subject. Experiments show both feature weighting and episodic training are effective and their integration further improves cross-subject generalization, making it suitable for plug-and-play BCIs."},{"id":"Xu2019_EEGDriverDrowsinessEstimationSelfPaced","title":"EEG-Based Driver Drowsiness Estimation Using Self-Paced Learning with Label Diversity","authors":"Yifan Xu et al.","year":2019,"venue":"SSCI","doi":"10.1109/SSCI44817.2019.9002753","topic":"Transfer Learning & Alignment","paradigm":["Drowsy"],"code_url":null,"tldr":"Targets calibration-free (plug-and-play) subject-independent EEG driver-drowsiness estimation, framed as a regression problem hurt by individual differences. Proposes self-paced learning with label diversity (SPLLD): the model trains on the easiest samples first and gradually adds harder ones, while a label-diversity term ensures samples are drawn from different label clusters at each pace to improve generalization. On a 15-subject simulated-driving dataset, SPLLD achieved lower estimation error than several baseline approaches without any calibration data from the new subject."},{"id":null,"title":"Guest Editorial: Special Issue on New Advances in Deep-Transfer Learning","authors":"Zhaohong Deng et al.","year":2019,"venue":"IEEE Trans. Emerg. Top. Comput. Intell.","doi":"10.1109/TETCI.2019.2936641","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":""},{"id":"Zhang2019_VitroFertilizationIVFCumulativePregnancyRate","title":"In Vitro Fertilization (IVF) Cumulative Pregnancy Rate Prediction From Basic Patient Characteristics","authors":"Bo Zhang et al.","year":2019,"venue":"IEEE Access","doi":"10.1109/ACCESS.2019.2940588","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"Tackles pre-treatment prediction of IVF cumulative pregnancy rate (after multiple oocyte pickup cycles) from basic patient characteristics, the first question patients typically ask. Proposes three approaches, the best of which first clusters patients into groups and then trains a separate support vector machine model for each cluster. On 11,190 patients the cluster-then-SVM approach achieved the best overall performance, providing a quick and economical estimate to help patients decide on own vs donor oocyte, number of cycles, and embryo freezing."},{"id":"Cao2019_IntegrationNonlinearDisturbanceObserverWithinProxy","title":"Integration of Nonlinear Disturbance Observer within Proxy-based Sliding Mode Control for Pneumatic Muscle Actuators","authors":"Yu Cao et al.","year":2019,"venue":"CoRR","doi":null,"topic":"Robustness & Security","paradigm":[],"code_url":null,"tldr":"Addresses robust tracking control of Pneumatic Muscle Actuators (PMAs), whose nonlinearity, hysteresis, and time-varying dynamics produce unmeasurable uncertainties and disturbances that defeat accurate model-based control. Proposes IDO-PSMC, integrating a nonlinear disturbance observer into proxy-based sliding mode control to jointly reduce the 'chattering' phenomenon and improve robustness, with a constrained Firefly Algorithm optimizing the control parameters and a Lyapunov proof that the PMA states are globally uniformly ultimately bounded. Extensive experiments across multiple tracking scenarios verified superior performance."},{"id":"Liu2019_MultiTaskDeepLearningDynamicProgramming","title":"Multi-Task Deep Learning With Dynamic Programming for Embryo Early Development Stage Classification From Time-Lapse Videos","authors":"Zihan Liu et al.","year":2019,"venue":"IEEE Access","doi":"10.1109/ACCESS.2019.2937765","topic":"Deep Architectures","paradigm":[],"code_url":null,"tldr":"Addresses classification of embryo early development stages from IVF time-lapse videos, which informs embryo-quality assessment. Proposes MTDL-DP, where multi-task deep learning (CNN) first pre-classifies each video frame into a development stage, then dynamic programming optimizes the whole stage sequence under the practical constraint that the stage number is monotonically non-decreasing. One-to-many, many-to-one, and many-to-many MTDL frameworks are compared. The one-to-many MTDL framework gives the best accuracy/computation trade-off, and this is reported as the first application of MTDL to embryo stage classification."},{"id":"Shi2019_MultiViewBroadLearningSystemPrimate","title":"Multi-View Broad Learning System for Primate Oculomotor Decision Decoding","authors":"Zhenhua Shi et al.","year":2019,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2020.3003342","topic":"Deep Architectures","paradigm":["iBCI"],"code_url":null,"tldr":"Decodes non-human-primate oculomotor decisions from invasive cortical signals, exploiting that simultaneously recorded local field potentials (LFPs) and action potentials (spikes) carry complementary information and can be treated as two views. Extends the Broad Learning System (a wide, incrementally-grown neural network) from single-view to multi-view learning (multi-view BLS) and applies it to monkey medial-frontal recordings. Shows LFPs and spikes indeed contain complementary decision information and that multi-view BLS decodes the oculomotor decision more effectively than classical and state-of-the-art single-view and multi-view methods."},{"id":"Zhang2019_MultiviewFuzzyLogicSystemCooperationBetween","title":"Multiview Fuzzy Logic System With the Cooperation Between Visible and Hidden Views","authors":"Te Zhang et al.","year":2019,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2018.2871005","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses multi-view learning, where traditional methods decompose a multi-view dataset into single views and ignore the hidden information behind the visible views. It proposes a multi-view Takagi-Sugeno-Kang fuzzy logic system that cooperatively exploits both the hidden information shared across the multiple visible views and the information of each individual visible view. Extensive experiments validate its effectiveness for classification."},{"id":"Chen2019_NonlinearDisturbanceObserverTSFuzzy","title":"Nonlinear Disturbance Observer Based T-S Fuzzy Logic Control of Pneumatic Artificial Muscles","authors":"Cheng Chen et al.","year":2019,"venue":"ICARM","doi":"10.1109/ICARM.2019.8834335","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses high-precision trajectory-tracking control of pneumatic artificial muscles (PAM), which is difficult due to time-varying parameters, hysteresis, and external disturbances. Proposes a nonlinear disturbance observer based T-S fuzzy logic controller (NDOTS): starting from the three-element PAM model, T-S fuzzy modeling decomposes the nonlinear dynamics into a set of linear models so linear control theory applies, feedback gains are obtained via the MATLAB LMI toolbox, a nonlinear disturbance observer compensates disturbances, and a Lyapunov function establishes stability. Experiments with loads attached to the PAM validate the tracking accuracy and robustness of the controller."},{"id":"Zhang2019_VulnerabilityCNNClassifiersEEGBCIs","title":"On the Vulnerability of CNN Classifiers in EEG-Based BCIs","authors":"Xiao Zhang et al.","year":2019,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2019.2908955","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":null,"tldr":"First study of the security/adversarial vulnerability of CNN classifiers in EEG-based BCIs. Proposes an unsupervised fast gradient sign method (UFGSM) to craft adversarial perturbations attacking three popular CNNs (EEGNet, DeepCNN, ShallowCNN), and verifies the transferability of adversarial examples across models, so attacks succeed without knowing the target's architecture, parameters, or training data. Demonstrates effective white-box and black-box (transfer) attacks, raising attention to BCI security."},{"id":null,"title":"Pool-Based Sequential Active Learning for Regression","authors":"Dongrui Wu","year":2019,"venue":"IEEE Trans. Neural Networks Learn. Syst.","doi":"10.1109/TNNLS.2018.2868649","topic":"Active Learning","paradigm":[],"code_url":null,"tldr":""},{"id":"Wu2019_RecommendationsDesigningPracticalIntervalType2","title":"Recommendations on designing practical interval type-2 fuzzy systems","authors":"Dongrui Wu et al.","year":2019,"venue":"Eng. Appl. Artif. Intell.","doi":"10.1016/J.ENGAPPAI.2019.06.012","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"A tutorial/recommendation paper addressing the many confusing design choices that face beginners building an interval type-2 (IT2) fuzzy system, whose operation is more complex than its type-1 counterpart. It walks through the key questions (singleton vs non-singleton fuzzifier, number and shape of membership functions, Gaussian vs piecewise-linear MFs, Mamdani vs TSK inference, minimum vs product t-norm, whether to use type-reduction, and how to optimize) and recommends representative default starting choices for each. The goal is to make IT2 fuzzy systems more accessible to practitioners."},{"id":"Wu2019_SimilarityMeasuresClosedGeneralType2","title":"Similarity Measures for Closed General Type-2 Fuzzy Sets: Overview, Comparisons, and a Geometric Approach","authors":"Dongrui Wu et al.","year":2019,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2018.2862869","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Studies similarity measures for general type-2 (GT2) fuzzy sets, whose membership grades are themselves fuzzy. It gives a comprehensive overview of existing GT2 similarity measures and points out that they all depend on a specific representation (vertical-slice or alpha-plane), then proposes a Jaccard similarity measure for GT2 FSs via an intuitive geometric approach that considers the overall geometries of the two sets and is representation-independent. The proposed measure is proved to satisfy four properties of a similarity measure and its reasonableness is demonstrated on two examples."},{"id":"Ming2019_SubjectAdaptationNetworkEEGDataAnalysis","title":"Subject adaptation network for EEG data analysis","authors":"Yurui Ming et al.","year":2019,"venue":"Appl. Soft Comput.","doi":"10.1016/J.ASOC.2019.105689","topic":"Robustness & Security","paradigm":["SSVEP"],"code_url":null,"tldr":"Addresses the strong intra- and cross-subject variance in EEG that makes a trained model generalize poorly to new test subjects. Proposes the Subject Adaptation Network (SAN), a generative-adversarial-network-inspired domain-adaptation architecture (combined with clustering-based sample selection) that mitigates the distribution discrepancy between subjects' EEG. On an EEG dataset from a VEP oddball task, SAN yields improved classification performance over conventional approaches."},{"id":"Meng2019_WhiteBoxTargetAttackEEGBCI","title":"White-Box Target Attack for EEG-Based BCI Regression Problems","authors":"Lubin Meng et al.","year":2019,"venue":"ICONIP","doi":"10.1007/978-3-030-36708-4_39","topic":"Privacy-Preserving BCI","paradigm":[],"code_url":null,"tldr":"Studies adversarial target attacks for regression problems, which had been largely unexplored compared with classification attacks, in the context of EEG-based BCIs. It proposes two white-box target attack approaches that, assuming full knowledge of the regression model, craft small input perturbations to shift the regression output by a pre-determined amount. Experiments on two BCI regression problems show both approaches are effective, and the crafted adversarial examples transfer across models (enabling black-box attacks). This is presented as the first study of adversarial attacks on EEG-based BCI regression."},{"id":"Chen2018_CommentQuotDirectApproachDeterminingSwitch","title":"A Comment on \"A Direct Approach for Determining the Switch Points in the Karnik-Mendel Algorithm\"","authors":"Chao Chen et al.","year":2018,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2018.2865134","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://gitlab.com/chao.chen/DA_Letter_2017","tldr":"A prior paper reported the EIASC type-reduction algorithm as the most inefficient in R, contradicting an earlier study that found EIASC most efficient in MATLAB. This letter investigates the inconsistency by re-implementing and optimizing the three algorithms (DA/DA*, EKM, EIASC) across five languages - MATLAB, R, Python, C, and Java. It concludes both results are valid: the discrepancy arises from differing loop-operation efficiency across languages, so algorithm-efficiency conclusions in one language cannot be generalized to others."},{"id":"Wu2018_MultiTaskingEvolutionaryAlgorithmMTEASingle","title":"Multi-Tasking Evolutionary Algorithm (MTEA) for Single-Objective Continuous Optimization","authors":"Dongrui Wu et al.","year":2018,"venue":"CoRR","doi":null,"topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"https://github.com/drwuHUST/MTGA","tldr":"Tackles evolutionary multi-tasking (multi-factorial optimization), i.e., solving several optimization tasks simultaneously by sharing knowledge, which degrades when the tasks differ significantly. The paper proposes the Multi-Tasking Genetic Algorithm (MTGA), which explicitly estimates and uses the bias between tasks so that significantly different tasks can still help each other. On nine benchmarks MTGA beat eight state-of-the-art single- and multi-task methods on average with lower cost than six of them, and it enabled a new strategy for simultaneously optimizing type-1 and interval type-2 fuzzy logic controllers for coupled-tank water-level control."},{"id":"Agarwal2018_PrivacyPreservingLinearRegressionBrainComputer","title":"Privacy-Preserving Linear Regression for Brain-Computer Interface Applications","authors":"Anisha Agarwal et al.","year":2018,"venue":"IEEE BigData","doi":"10.1109/BIGDATA.2018.8621861","topic":"Privacy-Preserving BCI","paradigm":["Drowsy"],"code_url":"https://bitbucket.org/uwtppml/lynx","tldr":"EEG/BCI data is highly sensitive, and application developers can extract private information (e.g., PINs) from unprotected signals, so the challenge is doing meaningful machine learning on EEG while preserving user privacy. The paper uses secure multiparty computation (SMC) to train a linear-regression model over EEG data from many users in a fully privacy-preserving way, without any party disclosing its data, evaluated on driver-drowsiness estimation. Many-party SMC training scales reasonably (about 48.5 s to 350 s for 2 to 14 parties) versus sub-second in the clear, demonstrating feasibility of privacy-preserving regression for BCI."},{"id":"Huang2018_SwitchModeFireflyAlgorithmGlobalOptimization","title":"A Switch-Mode Firefly Algorithm for Global Optimization","authors":"Jian Huang et al.","year":2018,"venue":"IEEE Access","doi":"10.1109/ACCESS.2018.2870531","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"The standard firefly algorithm uses a fixed randomization parameter that over-emphasizes exploration relative to exploitation, slowing convergence. This paper proposes a switch-mode firefly algorithm that first explores with a fixed randomization parameter and then automatically switches to exploitation with a gradually decreasing parameter, with the switch point identified automatically. Extensive experiments on benchmark functions show improved convergence and optimization performance over the standard firefly algorithm."},{"id":"Guo2018_FeatureDimensionalityReductionVideoAffectClassification","title":"Feature Dimensionality Reduction for Video Affect Classification: A Comparative Study","authors":"Chenfeng Guo et al.","year":2018,"venue":"2018 First Asian Conference on Affective Computing and Intelligent Interaction (ACII Asia)","doi":"10.1109/ACIIASIA.2018.8470329","topic":"General ML & Optimization","paradigm":["Affect"],"code_url":null,"tldr":"In affective computing, labeled samples are scarce while the number of extractable features is large, making dimensionality reduction critical for affect classification. This paper is a preliminary comparative study that introduces and compares five popular dimensionality-reduction (feature extraction and selection) approaches for video affect classification. On the DEAP dataset, no single approach universally outperforms the others, and classifying with the raw features directly is not necessarily a bad choice."},{"id":"Huang2018_IntervalType2FuzzyControlPneumatic","title":"Interval Type-2 Fuzzy Control of Pneumatic Muscle Actuator","authors":"Xiang Huang et al.","year":2018,"venue":"ICIRA","doi":"10.1007/978-3-319-97586-3_38","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The pneumatic muscle actuator (PMA) is a highly nonlinear system that is challenging to control. The paper proposes an interval type-2 fuzzy controller for the PMA, whose interval type-2 fuzzy sets provide better handling of uncertainty than a type-1 fuzzy controller. Both simulation and physical experiments confirm the proposed interval type-2 fuzzy controller achieves better tracking performance than a type-1 fuzzy controller."},{"id":"Huang2018_IntervalType2FuzzyLogicModeling","title":"Interval Type-2 Fuzzy Logic Modeling and Control of a Mobile Two-Wheeled Inverted Pendulum","authors":"Jian Huang et al.","year":2018,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2017.2760283","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Controlling an underactuated mobile two-wheeled inverted pendulum (MTWIP) is difficult under modeling uncertainties and external disturbances. The paper presents an integrated interval type-2 fuzzy logic approach that both models and controls the MTWIP: four IT2 fuzzy logic systems (Takagi-Sugeno models for the dynamics and for balance, Mamdani models for position and direction), with a linear-matrix-inequality design guaranteeing stability of the balance controller. Real-world experiments show the IT2 fuzzy system outperforms a type-1 fuzzy system, especially under uncertainties and disturbances."},{"id":"Cui2018_OMGEmotionChallengeSolution","title":"OMG - Emotion Challenge Solution","authors":"Yuqi Cui et al.","year":2018,"venue":"CoRR","doi":null,"topic":"General ML & Optimization","paradigm":["Affect"],"code_url":null,"tldr":"This short paper describes the authors' solution to the 2018 IEEE WCCI OMG One-Minute Gradual-Emotion challenge, which required estimating continuous arousal and valence from short videos. They build four base regression models from visual features (InceptionV3 features fed to an LSTM plus MLP) and audio features, then fuse them with a spectral (spectral meta-learner style) approach. The spectral fusion yields improved performance over the individual base models."},{"id":"He2018_SpatialFilteringBrainComputerInterfacesComparison","title":"Spatial Filtering for Brain Computer Interfaces: A Comparison between the Common Spatial Pattern and Its Variant","authors":"He He et al.","year":2018,"venue":"ICSPCC","doi":"10.1109/ICSPCC.2018.8567789","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":"EEG for BCIs is easily contaminated by artifacts and noise, so spatial filtering such as the common spatial pattern (CSP) is used to raise signal-to-noise ratio before classification. This paper compares the traditional CSP solution against a variant derived from a slightly different (Stiefel-manifold) objective function on motor-imagery data, and studies the effect of regularizing the covariance matrices. The traditional CSP solution generally gives better classification, and adding covariance regularization improves performance under either objective function."},{"id":null,"title":"Spatial Filtering for EEG-Based Regression Problems in Brain-Computer Interface (BCI)","authors":"Dongrui Wu et al.","year":2018,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2017.2688423","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":"Ming2018_SustainedAttentionDrivingTaskAnalysisRecurrent","title":"Sustained Attention Driving Task Analysis based on Recurrent Residual Neural Network using EEG Data","authors":"Yurui Ming et al.","year":2018,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2018.8491646","topic":"Deep Architectures","paradigm":["Drowsy"],"code_url":null,"tldr":"The paper applies deep learning to EEG recorded during a simulated sustained-attention driving task. It tailors a recurrent residual network (RRN) - combining residual connections with a recurrent structure - for EEG signal processing, applies it to a sustained-attention driving dataset, and analyzes the learned filters from an EEG frequency-band perspective. The RRN achieves competitive results and the learned filters admit meaningful frequency-band interpretations."},{"id":"Wu2017_ActiveSemiSupervisedTransferLearningASTL","title":"Active semi-supervised transfer learning (ASTL) for offline BCI calibration","authors":"Dongrui Wu","year":2017,"venue":"SMC","doi":"10.1109/SMC.2017.8122610","topic":"Active Learning","paradigm":["P300"],"code_url":null,"tldr":"Reduces the labeled subject-specific calibration data needed for single-trial ERP classification in BCIs, considering a more general setting than prior transfer-learning work in which part of the auxiliary (other-subject) data is unlabeled. The paper proposes Active Semi-supervised Transfer Learning (ASTL) for offline calibration, integrating regularization, active learning, transfer learning, and semi-supervised learning. On a visual-evoked-potential oddball task across three different EEG headsets, ASTL achieves consistently good cross-subject/cross-headset performance and outperforms several state-of-the-art approaches."},{"id":"Mendel2017_CritiqueQuotNewLookType2","title":"Critique of \"A New Look at Type-2 Fuzzy Sets and Type-2 Fuzzy Logic Systems\"","authors":"Jerry M. Mendel et al.","year":2017,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2017.2648882","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"A critique letter (Mendel and Wu) that provides a critical review of the paper 'A New Look at Type-2 Fuzzy Sets and Type-2 Fuzzy Logic Systems' and argues against its four main claims (e.g., that conditional fuzzy sets are a clearer framework than type-2 fuzzy sets, and the reduction of type-2 to type-1 fuzzy logic systems). It is a theoretical commentary rather than a method paper, contributing counterarguments and clarifications on type-2 fuzzy set representation."},{"id":"Wu2017_DriverDrowsinessEstimationEEGSignalsOnline","title":"Driver Drowsiness Estimation From EEG Signals Using Online Weighted Adaptation Regularization for Regression (OwARR)","authors":"Dongrui Wu et al.","year":2017,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2016.2633379","topic":"Robustness & Security","paradigm":["Drowsy"],"code_url":null,"tldr":"Targets an EEG-based BCI regression problem, online driver drowsiness estimation, where individual differences demand subject-specific calibration data. The paper integrates fuzzy sets with domain adaptation to propose Online Weighted Adaptation Regularization for Regression (OwARR) to cut the required subject-specific calibration data, plus a Source Domain Selection (SDS) scheme that removes about half the computational cost. On a 15-subject simulated-driving dataset, OwARR and OwARR-SDS achieve significantly smaller estimation errors than several baselines, with comprehensive robustness analyses."},{"id":"Cui2017_EEGDriverDrowsinessEstimationConvolutionalNeural","title":"EEG-Based Driver Drowsiness Estimation Using Convolutional Neural Networks","authors":"Yuqi Cui et al.","year":2017,"venue":"ICONIP","doi":"10.1007/978-3-319-70096-0_84","topic":"Deep Architectures","paradigm":["Drowsy"],"code_url":null,"tldr":"Extends deep learning in BCIs from classification to regression for EEG-based driver drowsiness estimation. The paper adapts EEGNet (a 3-layer CNN) to regression, uses the power spectral density (PSD) of EEG as input instead of raw signals, and aggregates multiple EEGNets with a spectral meta-learner for regression (SMLR). PSD inputs substantially reduce computational cost while improving regression accuracy over raw-EEG inputs, giving strong performance on driver drowsiness estimation."},{"id":"Wu2017_EEGUserReactionTimeEstimationRiemannian","title":"EEG-Based User Reaction Time Estimation Using Riemannian Geometry Features","authors":"Dongrui Wu et al.","year":2017,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2017.2699784","topic":"Transfer Learning & Alignment","paradigm":["Drowsy"],"code_url":null,"tldr":"Applies Riemannian geometry to EEG-based BCI regression for the first time, targeting user reaction-time estimation (Riemannian methods had previously been used only for BCI classification). The method first applies a spatial filter to raise EEG signal quality and reduce covariance-matrix dimensionality, then extracts Riemannian tangent-space features from the covariance matrices for regression. On a large-scale sustained-attention psychomotor vigilance task, the tangent-space features reduced RMSE by 4.30-8.30% and increased the estimation correlation coefficient by 6.59-11.13% over traditional powerband features."},{"id":"Chang2017_GeneratingFuzzyRuleBrainStateDrift","title":"Generating a fuzzy rule-based brain-state-drift detector by riemann-metric-based clustering","authors":"Yu-Cheng Chang et al.","year":2017,"venue":"SMC","doi":"10.1109/SMC.2017.8122779","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses how brain-state drifts (changing attentional/cognitive states) degrade machine-learning performance in BCIs and how to detect and represent them. The method applies Riemann-metric-based clustering to categorize and visualize EEG data distributions, then builds a fuzzy rule-based brain-state-drift detector to cope with the subjective uncertainty of EEG signals. Tested on data from multiple subjects in simulated and real-world human-system interaction, the detector achieves acceptable detection performance."},{"id":null,"title":"Guest Editorial for the Special Section on Brain Computer Interface (BCI)","authors":"Dongrui Wu et al.","year":2017,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2017.2652799","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":"Wu2017_OnlineOfflineDomainAdaptationReducingBCI","title":"Online and Offline Domain Adaptation for Reducing BCI Calibration Effort","authors":"Dongrui Wu","year":2017,"venue":"IEEE Trans. Hum. Mach. Syst.","doi":"10.1109/THMS.2016.2608931","topic":"Transfer Learning & Alignment","paradigm":["P300"],"code_url":null,"tldr":"Reduces the labeled subject-specific EEG data needed to calibrate single-trial ERP classifiers, since neural responses differ across subjects. The paper proposes both online and offline weighted adaptation regularization (wAR) domain-adaptation algorithms, together with source domain selection to cut computational cost by about 50%. On a visually-evoked-potential oddball task across three different EEG headsets, both online and offline wAR significantly outperform several other algorithms."},{"id":"Wang2017_RealTimeFMRIBrainComputerInterface","title":"Real-Time fMRI-Based Brain Computer Interface: A Review","authors":"Yang Wang et al.","year":2017,"venue":"ICONIP","doi":"10.1007/978-3-319-70096-0_85","topic":"Deep Architectures","paradigm":[],"code_url":null,"tldr":"A review of real-time fMRI-based BCIs (rtfMRI-BCI). It surveys the closed-loop system architecture (image acquisition, preprocessing, analysis, and feedback), the emerging machine-learning-based data-analysis approach known as multi-voxel pattern analysis (MVPA), and applications plus recent advances. It highlights that, unlike EEG, rtfMRI-BCI offers whole-brain decoding with high spatial resolution and lets subjects voluntarily self-regulate specific brain regions."},{"id":"Wu2017_SwitchingEEGHeadsetsMadeEasyReducing","title":"Switching EEG Headsets Made Easy: Reducing Offline Calibration Effort Using Active Weighted Adaptation Regularization","authors":"Dongrui Wu et al.","year":2017,"venue":"IEEE Transactions on Neural Systems and Rehabilitation Engineering","doi":"10.1109/TNSRE.2016.2544108","topic":"Active Learning","paradigm":["P300"],"code_url":null,"tldr":"Addresses the need to recalibrate BCI classifiers when switching between EEG headsets from different hardware systems, aiming to reduce offline calibration effort for the new headset. The paper proposes Active Weighted Adaptation Regularization (AwAR), combining weighted adaptation regularization (wAR, which reuses labeled data from the previous headset and handles class imbalance) with active learning (which selects the most informative new-headset samples to label). On single-trial ERP classification, AwAR significantly raises accuracy for a given number of labeled new-headset samples, thereby reducing the labeling effort required."},{"id":"Xu2017_TalentPlanningModelEmpiricalResearchKey","title":"The talent planning model and empirical research to the key disciplines in science and technology","authors":"Hao Xu et al.","year":2017,"venue":"Clust. Comput.","doi":"10.1007/S10586-017-1060-8","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"A management/scientometrics paper (not a BCI or machine-learning study, though Dongrui Wu is a co-author) on talent planning for key science-and-technology disciplines. It proposes a three-level tree-structured talent planning model with 2 level-I, 8 level-II, and 23 level-III indices, and uses the Analytic Hierarchy Process (AHP) to determine the index weights. The empirical result is a systematic, strategic framework intended to make talent planning for key disciplines more scientific."},{"id":"He2017_TransferLearningEnhancedCommonSpatialPattern","title":"Transfer Learning Enhanced Common Spatial Pattern Filtering for Brain Computer Interfaces (BCIs): Overview and a New Approach","authors":"He He et al.","year":2017,"venue":"ICONIP","doi":"10.1007/978-3-319-70096-0_83","topic":"Transfer Learning & Alignment","paradigm":["MI"],"code_url":null,"tldr":"Addresses that Common Spatial Pattern (CSP), the standard supervised spatial filter for EEG, needs subject-specific calibration data, which is time-consuming. The paper reviews three existing ways to incorporate transfer learning into CSP and proposes a new transfer-learning-enhanced CSP approach that uses data from other subjects. On motor imagery classification the proposed method performs best, especially when the number of target-subject calibration samples is small."},{"id":"Wu2016_AgreementRateInitializedMaximumLikelihoodEstimator","title":"Agreement rate initialized maximum likelihood estimator for ensemble classifier aggregation and its application in brain-computer interface","authors":"Dongrui Wu et al.","year":2016,"venue":"SMC","doi":"10.1109/SMC.2016.7844327","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":"Addresses optimal weighted aggregation of an ensemble of classifiers without labeled data, going beyond simple majority voting. Proposes the Agreement Rate Initialized Maximum Likelihood Estimator (ARIMLE): a simplified agreement-rate method estimates each base classifier's accuracy from unlabeled samples, these accuracies initialize a maximum likelihood estimator, and an expectation-maximization algorithm refines it. On visually evoked potential classification in a BCI application, ARIMLE outperforms majority voting and matches or beats several state-of-the-art classifier-combination methods."},{"id":"Wu2016_OfflineEEGDriverDrowsinessEstimationEnhanced","title":"Offline EEG-based driver drowsiness estimation using enhanced batch-mode active learning (EBMAL) for regression","authors":"Dongrui Wu et al.","year":2016,"venue":"SMC","doi":"10.1109/SMC.2016.7844328","topic":"Active Learning","paradigm":["Drowsy"],"code_url":null,"tldr":"Studies offline pool-based active learning for regression in BCI, i.e., selecting a small subset of unlabeled EEG epochs to label so an accurate regressor can be trained to label the rest, a setting the authors state had not been used for BCI regression before. Proposes Enhanced Batch-Mode Active Learning (EBMAL), which improves a baseline active-learning algorithm by increasing the reliability, representativeness, and diversity of the selected samples. Validated on EEG-based driver drowsiness estimation, though EBMAL is presented as a general approach for other offline regression problems."},{"id":null,"title":"Spectral meta-learner for regression (SMLR) model aggregation: Towards calibrationless brain-computer interface (BCI)","authors":"Dongrui Wu et al.","year":2016,"venue":"SMC","doi":"10.1109/SMC.2016.7844330","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":"Salaken2015_ApproximationCentroidEndPointsSwitchPoints","title":"Approximation of centroid end-points and switch points for replacing type reduction algorithms","authors":"Syed Moshfeq Salaken et al.","year":2015,"venue":"Int. J. Approx. Reason.","doi":"10.1016/J.IJAR.2015.07.010","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Targets the high computational cost of type reduction (TR) in interval type-2 fuzzy logic systems, where the Karnik-Mendel (KM) algorithm is far slower than a type-1 defuzzifier. Proposes a data-driven framework that trains simple regression models (on data generated by an exhaustive defuzzification method) to directly estimate the KM algorithm's centroid end-points and switch points. Simulations report centroid end-points approximated with mean absolute percentage error as low as 0.4% and switch-point prediction accuracy up to 100%, giving fast TR while keeping the uncertainty information intact."},{"id":"Salaken2015_EffectDifferentInitializationsEKMAlgorithm","title":"Effect of different initializations on EKM algorithm","authors":"Syed Moshfeq Salaken et al.","year":2015,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2015.7337810","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Focuses on speeding up type reduction in interval type-2 fuzzy logic systems through better initialization of the Enhanced Karnik-Mendel (EKM) algorithm, the most commonly used TR method. Proposes three new initialization schemes for EKM and shows that one of them significantly outperforms the others. Comprehensive simulations report performance gains up to 40%, justified by reduced computational time and fewer iterations for switch-point search."},{"id":"Lawhern2015_EfficientLabelingEEGSignalArtifactsActive","title":"Efficient Labeling of EEG Signal Artifacts Using Active Learning","authors":"Vernon Lawhern et al.","year":2015,"venue":"SMC","doi":"10.1109/SMC.2015.558","topic":"Active Learning","paradigm":[],"code_url":null,"tldr":"Addresses the time-consuming manual annotation of artifacts required before downstream processing of large EEG collections. Uses active learning to improve the reliability of existing EEG artifact classifiers (SVM with autoregressive-model features) with minimal user interaction. Results show that classification accuracy equivalent to classifiers trained on full data annotation can be obtained while labeling less than 25% of the data."},{"id":"Salaken2015_LinearApproximationKarnikMendelTypeReduction","title":"Linear approximation of Karnik-Mendel type reduction algorithm","authors":"Syed Moshfeq Salaken et al.","year":2015,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2015.7337811","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses the absence of a closed-form replacement for the iterative, computationally expensive Karnik-Mendel (KM) type-reduction algorithm in interval type-2 fuzzy logic systems. Demonstrates that the KM output can be approximated with simple linear regression models trained offline, exploiting the fact that most applications have a fixed input range with only small-scale variations. Simulations show approximation error below 2% while keeping the uncertainty bounds intact, yielding low run-time computational burden."},{"id":"Wu2015_OnlineDriverAposSDrowsinessEstimation","title":"Online driver's drowsiness estimation using domain adaptation with model fusion","authors":"Dongrui Wu et al.","year":2015,"venue":"ACII","doi":"10.1109/ACII.2015.7344682","topic":"Transfer Learning & Alignment","paradigm":["Drowsy"],"code_url":null,"tldr":"Tackles online EEG-based driver drowsiness estimation, where large individual differences make a single subject-independent model infeasible and per-subject calibration data are costly. Proposes Domain Adaptation with Model Fusion (DAMF), which uses EEG data from other subjects in a transfer-learning framework so that very little subject-specific calibration data is needed. In a simulated-driving experiment with 15 subjects, DAMF achieved better performance than several other approaches."},{"id":"Wu2015_ReducingBCICalibrationEffortRSVPTasks","title":"Reducing BCI calibration effort in RSVP tasks using online weighted adaptation regularization with source domain selection","authors":"Dongrui Wu et al.","year":2015,"venue":"ACII","doi":"10.1109/ACII.2015.7344626","topic":"Transfer Learning & Alignment","paradigm":["P300"],"code_url":null,"tldr":"Reduces online BCI calibration effort for single-trial event-related potential classification in rapid serial visual presentation (RSVP) tasks. Proposes Online Weighted Adaptation Regularization (OwAR), a domain-adaptation/transfer-learning method that exploits other subjects' data so fewer labeled subject-specific samples are needed for a given accuracy, together with a source-domain-selection step. Source domain selection reduced OwAR's computational cost by more than 50% without a statistically significant loss of classification accuracy."},{"id":"Wu2015_ReducingOfflineBCICalibrationEffortWeighted","title":"Reducing Offline BCI Calibration Effort Using Weighted Adaptation Regularization with Source Domain Selection","authors":"Dongrui Wu et al.","year":2015,"venue":"SMC","doi":"10.1109/SMC.2015.557","topic":"General ML & Optimization","paradigm":["P300"],"code_url":null,"tldr":"Reduces offline BCI calibration effort for single-trial ERP classification by borrowing data from other subjects. Proposes Weighted Adaptation Regularization (wAR), which explicitly handles the class-imbalance common in real BCI applications, together with a Source Domain Selection (SDS) step to cut computational cost. Experiments show wARSDS achieves comparable performance to wAR while being much less computationally intensive, lowering the number of labeled subject-specific samples needed for a target accuracy."},{"id":"Salaken2015_SwitchPointFindingPolynomialRegressionFuzzy","title":"Switch point finding using polynomial regression for fuzzy type reduction algorithms","authors":"Syed Moshfeq Salaken et al.","year":2015,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2015.7337812","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Aims to remove the iterative left/right switch-point search that is the computational bottleneck of the Karnik-Mendel (KM) type-reduction algorithm while retaining its uncertainty measures. Proposes a polynomial-regression approximator that predicts the switch points from firing intervals, rule centroids, and FLS structural features, after which the defuzzified output is obtained via basic vector multiplications. Comprehensive simulations across a variety of fuzzy logic systems report 100% switch-point approximation accuracy."},{"id":"Wu2014_ReconstructionDecoderComputingWords","title":"A reconstruction decoder for computing with words","authors":"Dongrui Wu","year":2014,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2013.08.050","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"In the Perceptual Computer for computing with words (CWW), the standard Word decoder maps the CWW engine's fuzzy-set output to a single codebook word, causing significant information loss especially when the codebook is small. Proposes a Reconstruction decoder that represents the CWW output as a combination of two successive codebook words with minimum information loss by solving a constrained optimization problem, preserving the output's shape information. It generalizes the Word decoder, is implicitly a Rank decoder, and equals the 2-tuple representation under certain conditions. Its effectiveness is verified in three experiments."},{"id":"Wu2014_DesigningPracticalIntervalType2Fuzzy","title":"Designing practical interval type-2 fuzzy logic systems made simple","authors":"Dongrui Wu et al.","year":2014,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2014.6891534","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Designing an interval type-2 fuzzy logic system (IT2 FLS) requires many choices (membership-function shape/number, singleton vs non-singleton fuzzifier, Mamdani vs TSK rules, minimum vs product t-norm, whether to type-reduce, and gradient- vs evolutionary-based one-/two-step tuning) that can overwhelm beginners and deter wider adoption. This tutorial/guidance paper recommends a set of representative, practical default choices to steer IT2 beginners through these design decisions and clarifies two common myths about IT2 FLSs, aiming to make IT2 FLSs more accessible. It is design guidance rather than a new algorithm."},{"id":"Mendel2014_DeterminingIntervalType2FuzzySet","title":"Determining interval type-2 fuzzy set models for words using data collected from one subject: Person FOUs","authors":"Jerry M. Mendel et al.","year":2014,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2014.6891618","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"For computing-with-words products used by a single person (e.g., a Personal Advisor), a word's fuzzy-set model only needs to capture that user's own (intra-) uncertainty, yet prior interval type-2 fuzzy set (IT2 FS) construction methods require data collected from a group of subjects. This paper proposes a methodology to build a word's 'Person FOU' (footprint of uncertainty) from a single subject by collecting interval end-point uncertainty intervals instead of only end-point intervals, which are easier to gather and avoid injecting methodological uncertainty during data collection. The method is applied to ten probability words to obtain Person FOUs, and its robustness to the choice of probability distribution assigned to the end-point uncertainty intervals is examined and demonstrated."},{"id":"Wu2014_TransferLearningActiveTransferLearningReducing","title":"Transfer learning and active transfer learning for reducing calibration data in single-trial classification of visually-evoked potentials","authors":"Dongrui Wu et al.","year":2014,"venue":"SMC","doi":"10.1109/SMC.2014.6974353","topic":"Active Learning","paradigm":["SSVEP"],"code_url":null,"tldr":"Single-trial ERP/VEP classification for BCIs normally needs a subject-specific calibration session because of strong individual differences, which reduces system usability. The paper proposes a Transfer Learning approach to cut the amount of subject-specific data needed for online single-trial ERP classifier calibration, plus an Active Transfer Learning approach for offline calibration that selectively labels the most informative samples. On a visually-evoked-potential EEG dataset, both approaches achieve higher accuracy for a given number of labeled subject-specific samples (equivalently, reach a target accuracy with less labeling effort) than random sample selection."},{"id":"Wu2013_ApproachesReducingComputationalCostIntervalType","title":"Approaches for Reducing the Computational Cost of Interval Type-2 Fuzzy Logic Systems: Overview and Comparisons","authors":"Dongrui Wu","year":2013,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2012.2201728","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The high computational cost of the iterative Karnik-Mendel (KM) type-reduction algorithms makes IT2 fuzzy logic systems expensive to deploy in cost-sensitive real-time applications. This survey gives a comprehensive overview and experimental comparison of three categories of cost-reduction methods: five enhancements to the KM algorithms, eleven alternative closed-form type-reducers, and a simplified IT2 FLS structure that can be combined with either category for further savings. Experiments show almost all of these methods are faster than the KM algorithms, and the paper concludes with a concrete recommendation to help practitioners choose a structure and type-reduction algorithm."},{"id":null,"title":"Special Issue on Computational Intelligence and Affective Computing [Guest Editorial]","authors":"Dongrui Wu et al.","year":2013,"venue":"IEEE Comput. Intell. Mag.","doi":"10.1109/MCI.2013.2247822","topic":"General ML & Optimization","paradigm":["Affect"],"code_url":null,"tldr":""},{"id":"Wu2013_TwoDifferencesBetweenIntervalType2","title":"Two Differences Between Interval Type-2 and Type-1 Fuzzy Logic Controllers: Adaptiveness and Novelty","authors":"Dongrui Wu","year":2013,"venue":"Advances in Type-2 Fuzzy Sets and Systems","doi":"10.1007/978-1-4614-6666-6_3","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"This Springer book chapter addresses why interval type-2 (IT2) fuzzy logic controllers handle uncertainty better than their type-1 (T1) counterparts by identifying two fundamental differences. Adaptiveness means the embedded T1 fuzzy sets used to compute the bounds of the type-reduced interval change as the input changes. Novelty means the upper and lower membership functions of the same IT2 fuzzy set can be used simultaneously in computing each bound. Because T1 FLCs have neither property, a T1 FLC cannot reproduce the more complex control surface of an IT2 FLC given the same rule base."},{"id":"Wu2012_EnhancedIntervalApproachEncodingWordsInto","title":"Enhanced Interval Approach for Encoding Words Into Interval Type-2 Fuzzy Sets and Its Convergence Analysis","authors":"Dongrui Wu et al.","year":2012,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2011.2177272","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"http://www-scf.usc.edu/~dongruiw/files/EIA.zip","tldr":"Constructing interval type-2 (IT2) fuzzy set models of words from survey data intervals is the first step of the Perceptual Computer, and the Interval Approach (IA) had been the only systematic method to do so. This paper proposes an Enhanced Interval Approach (EIA) that adds stricter, more reasonable tests in the data part and an improved procedure for computing the lower membership function, and provides a convergence analysis proving the resulting IT2 FS converges in the mean-square sense as more data intervals are collected, with about 30 intervals being a good cost/accuracy compromise. It is demonstrated on data collected from a web survey."},{"id":"Wu2012_ReconstructionDecoderPerceptualComputer","title":"A reconstruction decoder for the perceptual computer","authors":"Dongrui Wu","year":2012,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2012.6250766","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"In the Perceptual Computer, the Word decoder maps the CWW-engine output (a fuzzy set) to the closest word in a codebook, but it incurs significant information loss, especially when the codebook is small. This paper proposes a Reconstruction decoder that represents the CWW-engine output as a combination of two successive codebook words with minimum information loss by solving a constrained optimization problem. It generalizes the Word decoder, is implicitly also a Rank decoder, and compactly preserves the shape information of the engine output. Experiments verify its effectiveness, and a full MATLAB implementation is provided in the paper's Appendix."},{"id":"Wu2012_OverviewAlternativeTypeReductionApproachesReducing","title":"An overview of alternative type-reduction approaches for reducing the computational cost of interval type-2 fuzzy logic controllers","authors":"Dongrui Wu","year":2012,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2012.6251242","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Targets the high computational cost of the iterative Karnik-Mendel (KM) type-reduction algorithms, which can prevent interval type-2 fuzzy logic controllers from being used in real-time applications. The paper provides an overview and experimental comparison of 11 alternative closed-form type-reducers that are more convenient for analysis. It finds that 10 of them are faster than the KM algorithms, with the Wu-Tan and Nie-Tan methods being the fastest, only about 1.2-1.7 times slower than a type-1 fuzzy logic controller."},{"id":"Liu2012_AnalyticalSolutionMethodsFuzzyWeightedAverage","title":"Analytical solution methods for the fuzzy weighted average","authors":"Xinwang Liu et al.","year":2012,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2011.10.006","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The fuzzy weighted average (FWA) is widely used but is normally computed with discrete alpha-cut algorithms (either mathematical-programming/linear-programming transformations or direct iterative computation), with analytical solutions being very rare. Building on results from the Karnik-Mendel (KM) algorithm, this paper derives an analytical solution method for the FWA and proposes two algorithms to compute it, giving a precise, concisely structured, and computationally efficient solution with sound theoretical proofs. Two numerical examples illustrate the approach."},{"id":"Mendel2012_ChallengesPerceptualComputerApplicationsHowThey","title":"Challenges for Perceptual Computer Applications and How They Were Overcome","authors":"Jerry M. Mendel et al.","year":2012,"venue":"IEEE Comput. Intell. Mag.","doi":"10.1109/MCI.2012.2200627","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"This IEEE Computational Intelligence Magazine overview article presents Perceptual Computing, a Computing-with-Words (CWW) methodology to assist humans in making subjective judgments, and its instantiation, the Perceptual Computer (Per-C). The Per-C comprises an encoder (words to interval type-2 fuzzy sets forming a codebook), a CWW engine, and a decoder (fuzzy set back to a word/rank/class). The paper reviews the main challenges faced in building real Per-C applications and explains how each was overcome, positioning Per-C as an implementation of 'basic' CWW."},{"id":"Wu2012_FuzzySetsSystemsBuildingClosedLoop","title":"Fuzzy sets and systems in building closed-loop affective computing systems for human-computer interaction: Advances and new research directions","authors":"Dongrui Wu","year":2012,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2012.6250779","topic":"General ML & Optimization","paradigm":["Speech"],"code_url":null,"tldr":"A review/position paper arguing that fuzzy sets and systems, particularly type-2 fuzzy sets, are well suited to model the intra-personal uncertainty (a person's own uncertainty about an emotion) and inter-personal uncertainty (differing perceptions/expressions across people) inherent in affective computing for human-computer interaction. It frames affective computing as a closed-loop system of affect recognition, affect modeling, and affect control, introduces four application areas, and surveys recent applications of fuzzy logic to each of the three stages. The main contribution is synthesizing advances at the intersection of fuzzy logic and affective computing and pointing out new research directions for both communities."},{"id":"Wu2012_GeneticAlgorithmFeatureSelectionSpeakerTrait","title":"Genetic Algorithm Based Feature Selection for Speaker Trait Classification","authors":"Dongrui Wu","year":2012,"venue":"INTERSPEECH","doi":"10.21437/INTERSPEECH.2012-96","topic":"Robustness & Security","paradigm":["Speech"],"code_url":null,"tldr":"Tackles speaker-trait classification (personality, likability, pathology) from a large acoustic feature set (6125 features) in the INTERSPEECH 2012 Speaker Trait Challenge. The proposed method combines Fisher Information Metric feature filtering with genetic-algorithm-based feature selection, and fuses several linear SVMs (implemented with libSVM) trained on different feature subsets for robustness. On the challenge dataset the approach outperforms both provided baselines."},{"id":"Lam2012_IEEECISSocialMediaHaveYou","title":"IEEE CIS Social Media: Have You Joined Our Online Community? [Society Briefs]","authors":"Albert Y. S. Lam et al.","year":2012,"venue":"IEEE Comput. Intell. Mag.","doi":"10.1109/MCI.2011.2177020","topic":"Transfer Learning & Alignment","paradigm":[],"code_url":null,"tldr":"This is a non-technical IEEE Computational Intelligence Society (CIS) 'Society Briefs' announcement, co-authored by Dongrui Wu as vice-chair of the CIS Social Media Subcommittee, rather than a research paper. It introduces the Society's newly established social-media presence (Facebook, Twitter, LinkedIn, Second Life, and country/language-specific platforms), briefly describes each channel, and invites members to join and engage with the online community."},{"id":"Wu2012_FundamentalDifferencesBetweenIntervalType2","title":"On the Fundamental Differences Between Interval Type-2 and Type-1 Fuzzy Logic Controllers","authors":"Dongrui Wu","year":2012,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2012.2186818","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"This IEEE Transactions on Fuzzy Systems paper (the journal version of the analysis in index 194) explains two fundamental differences between interval type-2 (IT2) and type-1 (T1) fuzzy logic controllers: adaptiveness (the embedded T1 fuzzy sets computing the type-reduced interval bounds change with the input) and novelty (the upper and lower membership functions of the same IT2 set may be used simultaneously in computing each bound), which together let an IT2 FLC realize a more complex control surface than any T1 FLC with the same rule base. It introduces several tools to visualize and analyze these effects (the control surface, the P-map, equivalent generalized T1 fuzzy sets, and equivalent PI gains). It further examines five alternative type-reducers and explains why they fail to capture these IT2 fundamentals."},{"id":"Liu2012_StudyEnhancedKarnikMendelAlgorithmsInitialization","title":"Study on enhanced Karnik-Mendel algorithms: Initialization explanations and computation improvements","authors":"Xinwang Liu et al.","year":2012,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2011.07.042","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Computing the centroid of an interval type-2 fuzzy set is a core operation in IT2 fuzzy logic systems, usually done with the iterative Karnik-Mendel (KM) and Enhanced KM (EKM) algorithms. By connecting the discrete KM algorithms with their continuous counterparts, this paper gives theoretical explanations for the initialization choices used in KM/EKM, derives exact methods for centroid computation, and generalizes EKM into three forms of weighted EKM (WEKM) algorithms (recovering EKM as the constant-weight special case). WEKM is shown to have smaller absolute error and faster convergence than EKM, making it attractive for real-time fuzzy systems, as illustrated on four numerical examples."},{"id":"Wu2012_TwelveConsiderationsChoosingBetweenGaussianTrapezoidal","title":"Twelve considerations in choosing between Gaussian and trapezoidal membership functions in interval type-2 fuzzy logic controllers","authors":"Dongrui Wu","year":2012,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZ-IEEE.2012.6251210","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses the design decision of which membership-function type (Gaussian vs. trapezoidal) to use in interval type-2 fuzzy logic controllers (IT2 FLCs), for which no comprehensive prior study existed. It presents 12 considerations for the comparison: representation, construction, optimization, adaptiveness, novelty, analytical structure, continuity, monotonicity, stability, robustness, computational cost, and control performance. The conclusion is that each type has advantages: Gaussian IT2 FLCs are simpler in design (easier to represent and optimize, always continuous, faster for small rulebases), whereas trapezoidal IT2 FLCs are simpler in analysis."},{"id":"Wu2011_ActiveClassSelectionArousalClassification","title":"Active Class Selection for Arousal Classification","authors":"Dongrui Wu et al.","year":2011,"venue":"ACII","doi":"10.1007/978-3-642-24571-8_14","topic":"Transfer Learning & Alignment","paradigm":["Affect"],"code_url":null,"tldr":"Introduces active class selection (ACS), the problem of optimally choosing which classes to draw training examples from so a good classifier can be built from few examples, to the affective-computing community. This is motivated by emotion-classification settings where the class label (target emotion) must be specified before the corresponding physiological responses can be elicited and recorded. Comparing two ACS approaches on an arousal-classification task with a kNN classifier, one approach almost always beats uniform sampling, and the authors argue ACS combined with transfer learning can greatly reduce data-acquisition effort."},{"id":"Wu2011_ComparisonPracticalImplementationTypeReductionAlgorithms","title":"Comparison and practical implementation of type-reduction algorithms for type-2 fuzzy sets and systems","authors":"Dongrui Wu et al.","year":2011,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2011.6007317","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Compares type-reduction algorithms for type-2 fuzzy sets and systems, where the standard iterative Karnik-Mendel (KM) algorithm is computationally intensive, and proposes a new enhanced algorithm that improves over the latest results. Experiments show it is the most efficient in practice, saving over 50% of the computational cost of the KM algorithms when the number of elements in type-reduction is below 100 (the typical case). The paper also gives a Matlab implementation of the proposed algorithm in the appendix, adding preprocessing to eliminate numerical problems and improved stopping criteria to prevent infinite loops."},{"id":"Wu2011_InductiveTransferLearningHandlingIndividualDifferences","title":"Inductive Transfer Learning for Handling Individual Differences in Affective Computing","authors":"Dongrui Wu et al.","year":2011,"venue":"ACII","doi":"10.1007/978-3-642-24571-8_15","topic":"Transfer Learning & Alignment","paradigm":["Affect"],"code_url":null,"tldr":"Addresses the large individual differences in affective-computing physiological data, which force per-user retuning with expensive user-specific training examples. It applies inductive transfer learning to improve learning performance by combining a user's own training examples with auxiliary examples from other subjects that are similar but not identical, using a nearest-neighbors classifier. Results on an arousal-classification task within a Virtual Reality Stroop Task designed to elicit varying arousal levels demonstrate the effectiveness of the transfer-learning approach, complementing the authors' earlier active-class-selection work."},{"id":"Wu2011_LinguisticSummarizationIFTHENRulesInterval","title":"Linguistic Summarization Using IF-THEN Rules and Interval Type-2 Fuzzy Sets","authors":"Dongrui Wu et al.","year":2011,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2010.2088128","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Extends linguistic summarization (a data-mining approach that produces summaries such as 'most senior workers have high salary') to generate decision-usable IF-THEN rules from causal databases, using both type-1 and interval type-2 fuzzy sets. It defines five quality measures (degrees of truth, sufficient coverage, reliability, outlier, and simplicity), where the degree of reliability finds the most reliable/representative rules and the degree of outlier flags outlier rules and data, and proposes an improved parallel-coordinates method to visualize the rules. Experiments on two datasets demonstrate the approach, which is also related to the Wang-Mendel method, perceptual reasoning, and granular computing."},{"id":"Wu2011_ContinuityType1IntervalType2","title":"On the Continuity of Type-1 and Interval Type-2 Fuzzy Logic Systems","authors":"Dongrui Wu et al.","year":2011,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2010.2091962","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Studies the continuity of the input-output mappings of type-1 (T1) and interval type-2 (IT2) fuzzy logic systems. For T1 FLSs it shows that being a universal approximator is equivalent to having a continuous input-output mapping and derives the condition for discontinuity. For IT2 FLSs it considers six type-reduction/defuzzification methods (Karnik-Mendel, uncertainty bound, Wu-Tan, Nie-Tan, Du-Ying, Begian-Melek-Mendel) and derives the conditions under which continuous or discontinuous mappings result. It provides design guidelines for achieving desired continuity (for traditional modeling/control) or intentional discontinuity (for hybrid/switched systems), positioned as the most comprehensive study of FLS continuity to date."},{"id":"Wu2011_PMapIntuitivePlotVisualizeUnderstand","title":"P-Map: An Intuitive Plot to Visualize, Understand, and Compare Variable-Gain PI Controllers","authors":"Dongrui Wu","year":2011,"venue":"AIS","doi":"10.1007/978-3-642-21538-4_19","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Introduces the 'P-map,' a visualization for understanding and comparing complex variable-gain PI controllers (e.g., fuzzy, interval type-2 fuzzy, and gain-scheduling controllers). The idea is to represent the difference between a target controller and a baseline (or a second) controller as an equivalent proportional gain, and to plot how this gain varies with the inputs, giving a qualitative understanding of the controller's behavior. Examples show the P-map conveys more useful information than the conventional control surface for variable-gain PI controllers, so it can supplement or even replace the control surface."},{"id":"Rajati2011_SolvingZadehAposSMagnusChallenge","title":"Solving Zadeh's Magnus challenge problem on linguistic probabilities via Linguistic Weighted Averages","authors":"Mohammad Reza Rajati et al.","year":2011,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2011.6007614","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Presents a computing-with-words solution to Zadeh's Magnus challenge problem on linguistic probabilities. After implementing Zadeh's own solution, the authors reinterpret the problem using the intersection-product syllogism and an entailment-principle syllogism so it can be solved via Linguistic Weighted Averages (LWAs), computing pessimistic (lower) and optimistic (upper) probabilities. Vocabularies for the quantifiers and linguistic probabilities are modeled with interval type-2 fuzzy sets, and the resulting lower/upper probabilities are mapped back to linguistic probabilities so the answer is human-comprehensible."},{"id":"Coupland2010_EnhancedIntervalApproachEncodingWordsInto","title":"Enhanced Interval Approach for encoding words into interval type-2 fuzzy sets and convergence of the word FOUs","authors":"Simon Coupland et al.","year":2010,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2010.5584725","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"http://sipi.usc.edu/~mendel/software","tldr":"The Interval Approach (IA) synthesizes an interval type-2 fuzzy set (IT2 FS) model of a word from subjects' interval endpoint data, but assumes each person's interval is random and uniform, which makes the resulting IT2 FS model itself random and raises the question of whether it converges. The paper modifies several IA steps to form an Enhanced IA (EIA) and studies stochastic convergence of the word footprints-of-uncertainty (FOUs) through simulations. It shows the EIA word models converge in a mean-square sense as the number of subjects grows, supporting use of the EIA for word modeling."},{"id":"Wu2010_AcousticFeatureAnalysisSpeechEmotionPrimitives","title":"Acoustic feature analysis in speech emotion primitives estimation","authors":"Dongrui Wu et al.","year":2010,"venue":"INTERSPEECH","doi":"10.21437/INTERSPEECH.2010-285","topic":"Robustness & Security","paradigm":["Speech"],"code_url":null,"tldr":"Follows up the authors' 3D speech-emotion estimators by asking which acoustic feature categories matter most for estimating the valence/activation/dominance primitives. Using the prior robust linear/nonlinear estimators, it analyzes the relative importance of duration, energy, MFCC and pitch features via three measures: feature counts selected from each category, mean absolute error (MAE) using each category alone, and MAE when a category is excluded. It finds importance ranks MFCC > Energy ~= Pitch > Duration, and that estimator fusion (especially locally weighted fusion) almost always improves performance."},{"id":"Wu2010_ComputingWordsHierarchicalDecisionMakingApplied","title":"Computing With Words for Hierarchical Decision Making Applied to Evaluating a Weapon System","authors":"Dongrui Wu et al.","year":2010,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2010.2043439","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Addresses subjective hierarchical decision making where the inputs to criteria and subcriteria are heterogeneous and uncertain (numbers, intervals, type-1 fuzzy sets, or words modeled by interval type-2 fuzzy sets). The paper applies the Perceptual Computer (Per-C) architecture, using novel weighted averages (NWAs) as the computing-with-words engine to aggregate these diverse inputs up a criteria hierarchy and then rank competing alternatives, illustrated on a missile/weapon-system evaluation. The key contribution is that heterogeneous inputs can be fused while their uncertainties are preserved and propagated into the final evaluation, unlike prior methods that require crisp inputs."},{"id":"Wu2010_EfficientAlgorithmsComputingClassSubsethoodSimilarity","title":"Efficient algorithms for computing a class of subsethood and similarity measures for interval type-2 fuzzy sets","authors":"Dongrui Wu et al.","year":2010,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2010.5584484","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Subsethood and similarity measures are core fuzzy-set concepts, but computing Rickard et al.'s interval type-2 (IT2) FS subsethood measure and Nguyen-Kreinovich's IT2 FS Jaccard-type similarity measure is computationally expensive. The paper introduces these measures (extended from Kosko subsethood and Jaccard similarity via the Representation Theorem) and proposes efficient algorithms to compute them. Simulations show the proposed algorithms outperform existing computation methods in the literature."},{"id":"Wu2010_ExaminingContinuityType1IntervalType","title":"Examining the continuity of type-1 and interval type-2 fuzzy logic systems","authors":"Dongrui Wu et al.","year":2010,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2010.5584482","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Studies when fuzzy logic systems (FLSs) produce continuous versus discontinuous input-output mappings, which matters because control applications usually want smooth surfaces while hybrid/switched-system modeling can exploit discontinuities. For type-1 FLSs it proves that being a universal approximator is equivalent to having a continuous mapping and derives the condition for discontinuity. For interval type-2 FLSs (Karnik-Mendel type-reduction with center-of-sets defuzzification) it derives conditions yielding continuous or discontinuous mappings. The result gives explicit guidance for choosing membership-function parameters to obtain a desired (dis)continuity."},{"id":"Wu2010_IntervalType2FuzzyPIControllers","title":"Interval Type-2 Fuzzy PI Controllers: Why They are More Robust","authors":"Dongrui Wu et al.","year":2010,"venue":"GrC","doi":"10.1109/GRC.2010.112","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Experiments consistently show interval type-2 (IT2) fuzzy PI controllers are more robust than their type-1 counterparts at rejecting disturbances and eliminating oscillations, but a theoretical explanation was lacking. The paper derives closed-form equivalent PI gains and analyzes controller behavior around the origin/steady state. It shows the footprint of uncertainty lets an IT2 fuzzy PI controller emulate a variable-gain PI controller with smaller gains near the origin, so a given disturbance produces a smaller control-signal change and less oscillation, thereby connecting IT2 fuzzy control to classical PI design."},{"id":"Wu2010_LinguisticSummarizationIFTHENRules","title":"Linguistic summarization using IF-THEN rules","authors":"Dongrui Wu et al.","year":2010,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2010.5584500","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Linguistic summarization (LS) extracts human-friendly patterns from data, but prior LS methods do not produce IF-THEN rules that could be added to a knowledge base or used in perceptual reasoning. The paper proposes LS that generates IF-THEN rules and defines five quality measures for the summaries - notably a 'degree of usefulness' to find reliable/representative rules and a 'degree of outlier' to flag outlier rules and data - and relates the approach to the Wang-Mendel method. An example verifies that the method yields interpretable rules and can identify outliers."},{"id":"Wu2010_OptimalArousalIdentificationClassificationAffectiveComputing","title":"Optimal Arousal Identification and Classification for Affective Computing Using Physiological Signals: Virtual Reality Stroop Task","authors":"Dongrui Wu et al.","year":2010,"venue":"IEEE Trans. Affect. Comput.","doi":"10.1109/T-AFFC.2010.12","topic":"General ML & Optimization","paradigm":["Affect"],"code_url":null,"tldr":"Works toward a closed-loop affective-computing system that must assess both the user's optimal affective/cognitive state and their currently observed state, focusing on arousal because of its link to cognitive performance (Yerkes-Dodson Law). Using a Virtual Reality Stroop Task with three stimulus presentations of distinct arousal levels, it identifies the optimal arousal level via reaction time and classifies psychophysiological responses (skin conductance level, respiration, ECG, and EEG) into three arousal levels with a support vector machine. Results show that one of the three presentations elicits optimal arousal for most subjects and that high classification rates are achievable, representing progress toward a closed-loop affective computing system."},{"id":"Wu2010_OrderedFuzzyWeightedAveragesOrderedLinguistic","title":"Ordered fuzzy weighted averages and ordered linguistic weighted averages","authors":"Dongrui Wu et al.","year":2010,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2010.5584479","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The ordered weighted average (OWA) operator is widely used in decision making but requires crisp sub-criteria and weights, whereas real inputs are often uncertain (intervals, type-1 or interval type-2 fuzzy sets). The paper proposes two fuzzy extensions of the OWA - ordered fuzzy weighted averages (for T1 FSs) and ordered linguistic weighted averages (for IT2 FSs) - together with procedures to compute them, and compares them to Zhou et al.'s extensions. Because the proposed operators respect the 'fuzzy set in its entirety' intuition, they can yield different and more appropriate results than Zhou et al.'s when the fuzzy-set legs intersect."},{"id":"Wu2010_SocialJudgmentAdvisorApplicationPerceptualComputer","title":"Social Judgment Advisor: An application of the Perceptual Computer","authors":"Dongrui Wu et al.","year":2010,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2010.5584488","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Demonstrates building a rule-based system that makes subjective social judgments using only words, as an application of the Perceptual Computer (Per-C). Vocabulary words are modeled as interval type-2 fuzzy sets, surveys are used to construct a rulebase with consequent histograms, perceptual reasoning (PR) prunes the rulebase and infers output IT2 FSs for new inputs, and outputs are mapped back to words via a similarity measure so the user interacts entirely in words. The resulting 'Social Judgment Advisor' shows an end-to-end Per-C pipeline that generalizes to many rule-based decision-making situations."},{"id":"Wu2010_SpeechEmotionEstimation3DSpace","title":"Speech emotion estimation in 3D space","authors":"Dongrui Wu et al.","year":2010,"venue":"ICME","doi":"10.1109/ICME.2010.5583101","topic":"Robustness & Security","paradigm":["Speech"],"code_url":null,"tldr":"Most speech-emotion research classifies emotion into a few discrete categories, whereas continuous representation in a multi-dimensional space better reflects the gradient nature of emotion. The paper presents three elementary estimators - robust regression, support vector regression, and locally linear reconstruction - for estimating valence/activation/dominance from duration, energy, MFCC and pitch features, plus two fusion schemes (average fusion and locally weighted fusion). On a spontaneously-elicited emotion dataset all three estimators work well, and locally weighted fusion of the complementary (linear/nonlinear, global/local) estimators improves accuracy beyond the state-of-the-art estimator."},{"id":"Wu2009_ComparativeStudyRankingMethodsSimilarityMeasures","title":"A comparative study of ranking methods, similarity measures and uncertainty measures for interval type-2 fuzzy sets","authors":"Dongrui Wu et al.","year":2009,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2008.12.010","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":"http://sipi.usc.edu/~mendel/software","tldr":"For interval type-2 (IT2) fuzzy sets there was only one prior ranking method but many competing similarity and uncertainty measures, and it was unclear which are most suitable for computing with words (CWW). The paper proposes a new ranking method and a new similarity measure for IT2 FSs, then compares all available ranking methods, similarity measures and uncertainty measures on real linguistic survey data. It recommends the most suitable ranking method, similarity measure and uncertainty measure for the CWW paradigm, aiding survey design and linguistic information processing."},{"id":"Wu2009_EnhancedKarnikMendelAlgorithms","title":"Enhanced Karnik-Mendel Algorithms","authors":"Dongrui Wu et al.","year":2009,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2008.924329","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The Karnik-Mendel (KM) algorithms are the standard iterative procedure for the min/max bounds arising in interval type-2 fuzzy type-reduction and uncertainty-measure computation. They converge monotonically and super-exponentially but still need about two to six iterations. The paper proposes enhanced KM (EKM) algorithms that use better initialization and computation reductions. Extensive simulations show EKM saves about two iterations (more than a 39% reduction in computation time), with at least a further 23% saving when input sorting is unnecessary."},{"id":"Wu2009_PerceptualReasoningPerceptualComputingSimilarityApproach","title":"Perceptual Reasoning for Perceptual Computing: A Similarity-Based Approach","authors":"Dongrui Wu et al.","year":2009,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2009.2032652","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Perceptual reasoning (PR) is a computing-with-words (CWW) engine for the Perceptual Computer, but the existing firing-interval-based PR (FI-PR) tends to produce overly fat output footprints of uncertainty (FOUs). This paper proposes similarity-based PR (S-PR), which computes a scalar firing level from the Jaccard similarity between the input and antecedent interval type-2 fuzzy sets (IT2 FSs) and combines fired-rule consequents with a linguistic weighted average that reduces to arithmetic weighted averages. It proves the S-PR output resembles the three codebook FOU types with bounded span, and a comparative study on a flirtation social-judgment advisor shows S-PR outputs match subject-derived word FOUs more closely and are computed faster than FI-PR."},{"id":"Wu2009_SimilarityPerceptualReasoningPerceptualComputing","title":"Similarity-based perceptual reasoning for perceptual computing","authors":"Dongrui Wu et al.","year":2009,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2009.5277374","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"This is the FUZZ-IEEE 2009 conference version of the similarity-based perceptual reasoning (PR) work. It proposes similarity-based PR as a computing-with-words engine, in which the firing quantity of each rule is a scalar similarity (firing level) rather than a firing interval, and fired-rule consequents are aggregated via a linguistic weighted average. A comparative study shows the output FOUs from similarity-based PR more closely resemble the three kinds of codebook FOUs and yield more intuitive linguistic descriptions than firing-interval PR."},{"id":"Wu2008_VectorSimilarityMeasureLinguisticApproximationInterval","title":"A vector similarity measure for linguistic approximation: Interval type-2 and type-1 fuzzy sets","authors":"Dongrui Wu et al.","year":2008,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2007.04.014","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"In a Perceptual Computer the decoder must map a CWW-engine output IT2 FS to the most similar word (linguistic label) in a codebook, which requires a reliable similarity measure for IT2 FSs. This paper proposes a vector similarity measure (VSM) whose two components separately quantify similarity in shape and in proximity (position). A comparative study shows the VSM gives more reasonable linguistic-approximation results than all existing IT2 FS similarity measures, and it also applies to type-1 FSs as a special case when uncertainty disappears."},{"id":null,"title":"Corrections to \"Aggregation Using the Linguistic Weighted Average and Interval Type-2 Fuzzy Sets\"","authors":"Dongrui Wu et al.","year":2008,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2008.2005941","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":""},{"id":"Mendel2008_PerceptualReasoningPerceptualComputing","title":"Perceptual Reasoning for Perceptual Computing","authors":"Jerry M. Mendel et al.","year":2008,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2008.2005691","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"This is the foundational IEEE T-FS 2008 paper that introduces Perceptual Reasoning (PR) as a rule-based CWW engine for the Perceptual Computer, motivated by the fact that existing approximate-reasoning methods do not guarantee that the combined fired-rule output resembles the three word-FOU types (interior, left-shoulder, right-shoulder). PR uses firing intervals and a linguistic weighted average to combine fired IT2 FS consequents, with the required sup-min inference computations worked out for the shoulder/interior FOU cases. It proves PR always yields a normal IT2 FS output resembling codebook word FOUs, enabling a practical rule-based CWW engine."},{"id":"Wu2008_PerceptualReasoningIntervalType2Fuzzy","title":"Perceptual reasoning using interval type-2 fuzzy sets: Properties","authors":"Dongrui Wu et al.","year":2008,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2008.4630526","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"This FUZZ-IEEE 2008 properties paper accompanies the introduction of Perceptual Reasoning (PR), a CWW engine whose output IT2 FS must resemble the codebook word FOUs for accurate decoding. It presents the step-by-step computation procedure for PR (firing intervals combined via a linguistic weighted average) and analyzes its mathematical properties in detail. The main results establish the conditions under which the PR output is a left-shoulder, right-shoulder, or interior footprint of uncertainty."},{"id":"Wu2007_VectorSimilarityMeasureIntervalType2","title":"A Vector Similarity Measure for Interval Type-2 Fuzzy Sets","authors":"Dongrui Wu et al.","year":2007,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2007.4295333","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"This FUZZ-IEEE 2007 conference paper is the IT2 FS portion of the vector-similarity-measure work, addressing the decoding problem of mapping a CWW-engine output IT2 FS to the most similar word in a codebook. It proposes a vector similarity measure (VSM) for IT2 FSs whose two elements measure shape similarity and proximity, respectively. A comparative study shows the VSM gives more reasonable results than existing IT2 FS similarity measures for linguistic approximation."},{"id":"Wu2007_VectorSimilarityMeasureType1Fuzzy","title":"A Vector Similarity Measure for Type-1 Fuzzy Sets","authors":"Dongrui Wu et al.","year":2007,"venue":"IFSA","doi":"10.1007/978-3-540-72950-1_57","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The paper targets the linguistic-approximation problem for type-1 fuzzy sets: associating a T1 FS with the most similar linguistic label in a vocabulary. It proposes a vector similarity measure (VSM) for T1 FSs whose two elements capture similarity in shape and in proximity, and which is simpler than Bonissone's and Wenstop's classical methods. A comparative study shows the VSM gives the best results, and it extends readily to interval type-2 FSs."},{"id":"Wu2007_AggregationLinguisticWeightedAverageIntervalType","title":"Aggregation Using the Linguistic Weighted Average and Interval Type-2 Fuzzy Sets","authors":"Dongrui Wu et al.","year":2007,"venue":"IEEE Trans. Fuzzy Syst.","doi":"10.1109/TFUZZ.2007.896325","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The paper addresses aggregating attributes and weights that are words modeled as interval type-2 fuzzy sets, as needed in distributed and hierarchical decision-making within a Perceptual Computer. It defines the linguistic weighted average (LWA) - a generalization of the fuzzy weighted average (FWA) in which the weights (and optionally the attributes) are IT2 FSs - and shows that computing the LWA decomposes into computing two FWAs (for the upper and lower membership functions) using alpha-cuts and the Karnik-Mendel algorithms. It provides the theory, algorithms, and a decision-making application, with the LWA output being an IT2 FS that captures more uncertainty than the FWA."},{"id":"Mendel2007_CardinalityFuzzinessVarianceSkewnessIntervalType","title":"Cardinality, Fuzziness, Variance and Skewness of Interval Type-2 Fuzzy Sets","authors":"Jerry M. Mendel et al.","year":2007,"venue":"FOCI","doi":"10.1109/FOCI.2007.371499","topic":"Fuzzy Systems & Computing-with-Words","paradigm":["Affect"],"code_url":null,"tldr":"This is the conference version of the IT2 FS uncertainty-measures work. Using the Mendel-John Representation Theorem, it defines cardinality, fuzziness, variance, and skewness for interval type-2 fuzzy sets, each being an interval whose length measures uncertainty. Unlike the centroid, which requires the iterative Karnik-Mendel algorithms, these four measures are given closed-form expressions so they can be computed very fast, and they are useful both for quantifying IT2 FS uncertainty and for measuring similarity between two IT2 FSs."},{"id":"Tan2007_DesignTypeReductionStrategiesType2","title":"Design of Type-Reduction Strategies for Type-2 Fuzzy Logic Systems using Genetic Algorithms","authors":"Woei Wan Tan et al.","year":2007,"venue":"Advances in Evolutionary Computing for System Design","doi":"10.1007/978-3-540-72377-6_7","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Type-reduction in type-2 fuzzy logic systems is normally done with the computationally intensive iterative Karnik-Mendel algorithm, which hinders real-time use. This book chapter uses the concept of equivalent type-1 fuzzy sets (ET1FSs) - a collection of T1 FSs that replicates the input-output relationship of a type-2 FLS - so that type-reduction reduces to deciding which ET1FS to employ in a given situation, and it evolves that selection strategy with a genetic algorithm. Results show the GA-designed type-reducer has lower computational cost and can provide better performance than FLSs using existing type-reducers."},{"id":null,"title":"Perceptual Reasoning: A New Computing with Words Engine","authors":"Jerry M. Mendel et al.","year":2007,"venue":"GrC","doi":"10.1109/GRC.2007.55","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":""},{"id":"Wu2007_UncertaintyMeasuresIntervalType2Fuzzy","title":"Uncertainty measures for interval type-2 fuzzy sets","authors":"Dongrui Wu et al.","year":2007,"venue":"Inf. Sci.","doi":"10.1016/J.INS.2007.07.012","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"Beyond the centroid (defined earlier by Karnik and Mendel), uncertainty measures for interval type-2 fuzzy sets were largely undefined. Using a Representation Theorem for IT2 FSs, this paper defines cardinality, fuzziness (entropy), variance, and skewness for IT2 FSs and derives formulas to compute each. Each measure is an interval whose length indicates the amount of uncertainty. These measures are intended to support IT2 fuzzy-logic-system design via the principles of uncertainty and to enable similarity computation between two IT2 FSs."},{"id":"Wu2006_GeneticLearningPerformanceEvaluationIntervalType","title":"Genetic learning and performance evaluation of interval type-2 fuzzy logic controllers","authors":"Dongrui Wu et al.","year":2006,"venue":"Eng. Appl. Artif. Intell.","doi":"10.1016/J.ENGAPPAI.2005.12.011","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":"The paper investigates how much the extra degrees of freedom provided by antecedent type-2 fuzzy sets actually improve control performance. An interval type-2 fuzzy logic controller (FLC) is evolved using genetic algorithms and compared against three GA-evolved type-1 FLCs having different numbers of design parameters on a process-control task. Experimental results show the type-2 FLC achieves better control using fewer fuzzy sets/rules, meaning a lower trade-off between modeling accuracy and interpretability."},{"id":null,"title":"The Linguistic Weighted Average","authors":"Dongrui Wu et al.","year":2006,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2006.1681768","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":null,"title":"Computationally Efficient Type-Reduction Strategies for a Type-2 Fuzzy Logic Controller","authors":"Dongrui Wu et al.","year":2005,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2005.1452419","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":""},{"id":null,"title":"Type-2 FLS Modeling Capability Analysis","authors":"Dongrui Wu et al.","year":2005,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2005.1452400","topic":"General ML & Optimization","paradigm":[],"code_url":null,"tldr":""},{"id":null,"title":"A type-2 fuzzy logic controller for the liquid-level process","authors":"Dongrui Wu et al.","year":2004,"venue":"FUZZ-IEEE","doi":"10.1109/FUZZY.2004.1375536","topic":"Fuzzy Systems & Computing-with-Words","paradigm":[],"code_url":null,"tldr":""}];
